INSERT INTO state_property_tax_provisions
  (state_code, jurisdiction_level, topic, subtype, summary, params, statute_citation, source_url, source_date, effective_year)
VALUES
  ('AK','state','exemption','senior','Alaska mandates that every municipality exempt the first $150,000 of assessed value of the primary residence of a resident who is 65 or older (also covers disabled veterans and certain surviving spouses). This is a statewide-required exemption; localities apply it uniformly. A municipality may, in hardship cases, exempt value beyond $150,000.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":150000,"benefit_unit":"usd","locally_variable":false,"notes":"Mandatory statewide. Written application required; each municipality sets the application deadline/procedure. May require PFD eligibility (AS 29.45.030(f)). Hardship exemption above $150,000 permitted by ordinance per dept. regulations. State reimburses municipalities for lost revenue under AS 29.45.030(g)."}'::jsonb,'Alaska Stat. (AS) 29.45.030(e)','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AK','state','exemption','disabled_veteran','Alaska mandates the same $150,000 assessed-value exemption on a disabled veteran''s primary residence. A ''disabled veteran'' is a resident whose service-connected disability is rated 50 percent or more by the branch of service or the U.S. Department of Veterans Affairs.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":150000,"benefit_unit":"usd","locally_variable":false,"notes":"Disability rating threshold is 50% or more (service-connected). Resident requirement. Assessor requires evidence of the disability rating (AS 29.45.030(f)). Same $150,000 cap as senior exemption; both flow from AS 29.45.030(e). Definition also covers Alaska Territorial Guard service (AS 29.45.030(i)(1)(B))."}'::jsonb,'Alaska Stat. (AS) 29.45.030(i)(1) (definition); AS 29.45.030(e) (benefit)','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AK','state','exemption','other','Optional, voter-approved municipal exemption: a municipality may by ordinance approved by the voters exempt the assessed value EXCEEDING $150,000 of a primary residence owned by a resident 65+, a disabled veteran, or a qualifying surviving spouse 60+. This is on top of the mandatory first-$150,000 exemption and is purely local/optional.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":150000,"benefit_unit":"usd","locally_variable":true,"notes":"Optional exemption of value ABOVE the mandatory $150,000 floor. Requires ordinance approved by voters. Also covers disabled veterans (incl. Alaska Territorial Guard) and surviving spouse at least 60 of a qualifying person. benefit_value=150000 is the THRESHOLD above which value may be exempted, not a cap on the exempt amount."}'::jsonb,'Alaska Stat. (AS) 29.45.050(i)','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AK','state','assessment_appeal',NULL,'A property owner must file a written appeal of an assessment with the assessor within 30 days after the date of mailing of the assessment notice; otherwise the right to appeal ceases. Appeals are heard by the municipal Board of Equalization, and its decision may be appealed to the superior court.','{"deadline_kind":"relative_to_roll","deadline_desc":"Within 30 days after the date of mailing of the notice of assessment","review_body":"Municipal Board of Equalization (appointed by the governing body); further appeal to the superior court","locally_variable":false}'::jsonb,'Alaska Stat. (AS) 29.45.190(b); review body AS 29.45.200, AS 29.45.210','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AK','state','payment',NULL,'Alaska has no statewide property tax; property tax is municipal/borough only. The state sets only the framework: the rate of levy, date of equalization, and the date taxes become delinquent are fixed locally by resolution. Municipalities must set the levy rate before June 15 and mail tax statements (with payable/delinquent dates) by July 1. Actual due/delinquency dates vary by locality.','{"installments":[],"delinquent_after_desc":"Set locally by municipal resolution; statements mailed by July 1 state the payable and delinquent dates. State law permits payment in two installments if the municipality so provides (AS 29.45.250(b)).","locally_variable":true}'::jsonb,'Alaska Stat. (AS) 29.45.240; two-installment option AS 29.45.250(b)','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AK','state','delinquency_redemption',NULL,'Alaska enforces delinquent property taxes through a judicial in-rem foreclosure in which the municipality takes the property (tax-deed-style; not a third-party lien-certificate sale). After foreclosure, the municipality holds the property for at least one year, during which an interested party may redeem by paying the lien amount plus penalties, interest, and costs. Statutory caps: penalty up to 20% of tax due and interest up to 15% per year, with the specific figures set locally within those caps.','{"late_penalty_pct":20,"late_interest_pct_per_year":15,"redemption_period_months":12,"tax_sale_kind":"tax_deed","locally_variable":true,"notes":"Penalty (\u226420%) and interest (\u226415%/yr) are statutory CEILINGS; municipalities set the actual figures by resolution. Redemption period is a statutory MINIMUM of one year (''at least one year''); a borough/city may extend it by ordinance (AS 29.45.050(c)(1)). Enforcement is a single general in-rem foreclosure proceeding (AS 29.45.360); unredeemed property is deeded to the municipality (AS 29.45.450). The redemption right also expires 30 days after first publication of the redemption-period-expiration notice near the end of the period (AS 29.45.440(b))."}'::jsonb,'Alaska Stat. (AS) 29.45.400 (redemption period); AS 29.45.250(a) (penalty/interest caps); AS 29.45.360, 29.45.450 (in-rem foreclosure / deed to municipality)','https://www.akleg.gov/statutesPDF/Title-29.pdf','2026-06-14',2026),
  ('AL','state','assessment_appeal',NULL,'Owner who disagrees with the valuation may file a written protest with the County Board of Equalization (BOE) within 30 days of the notice of valuation. Appeals process governed by Code of Alabama 1975 §§ 40-3-20, 40-3-24, 40-3-25.','{"deadline_kind":"relative_to_roll","deadline_desc":"Within 30 calendar days of the notice of valuation (statute: 30 days of final publication of notice / date of notice under \u00a7 40-3-21)","review_body":"County Board of Equalization (BOE)","locally_variable":true}'::jsonb,'Code of Alabama 1975 §§ 40-3-20, 40-3-24, 40-3-25','https://www.revenue.alabama.gov/faqs/what-can-i-do-if-i-do-not-agree-with-the-value-on-my-property/','2026-06-14',2026),
  ('AL','state','assessment',NULL,'Alabama assesses property at a percentage of fair and reasonable market value by class: Class I (utilities) 30%, Class II (general/all other) 20%, Class III (agricultural, forest, residential, historic) 10%, Class IV (private passenger autos/pickups) 15%. Property is appraised at fair and reasonable market value, or at current use value as provided by law.','{"assessment_ratio_pct":10,"market_value_standard":"fair and reasonable market value (or current use value as provided by law; Class III owner-occupied residential ratio = 10%)","locally_variable":false}'::jsonb,'Code of Alabama 1975 § 40-8-1','https://www.revenue.alabama.gov/tax-types/property-ad-valorem-tax/','2026-06-14',2026),
  ('AL','state','exemption','homestead','H-1: regular homestead for owner-occupants under 65 and not disabled — exempts $4,000 of assessed value on the state portion and $2,000 of assessed value on the county portion, up to 160 acres.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":4000,"benefit_unit":"usd","locally_variable":false,"notes":"$4,000 assessed value exempt on state portion AND $2,000 assessed value exempt on county portion; 160-acre limit; resident not over 65 years of age"}'::jsonb,'Code of Alabama 1975 § 40-9-19','https://www.revenue.alabama.gov/property-tax/homestead-exemptions/','2026-06-14',2026),
  ('AL','state','exemption','senior','H-3 (age 65+): owner-occupant age 65 or older with net annual federally taxable income of $12,000 or less (person and spouse combined) is exempt from ALL ad valorem taxes on the principal residence and up to 160 acres, with no assessed-value cap. H-2: residents over 65 with adjusted gross income under $12,000 (or disabled/blind) are exempt from all state ad valorem plus county ad valorem up to $5,000 of assessed value.','{"age_min":65,"income_max":12000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"H-3 (65+, net annual taxable income $12,000 or less, person+spouse on US income tax return): exempt from ALL ad valorem taxes, no assessed-value cap, 160-acre limit (\u00a7 40-9-21). H-2 (65+ with AGI under $12,000, or disabled/blind): all state portion (\u00a7 40-9-19(a)(2)) + county ad valorem up to $5,000 of assessed value (\u00a7 40-9-19(d))."}'::jsonb,'Code of Alabama 1975 § 40-9-19; § 40-9-21','https://www.revenue.alabama.gov/property-tax/homestead-exemptions/','2026-06-14',2026),
  ('AL','state','exemption','disability','Owner-occupant who is permanently and totally disabled (any age, no income limit) is exempt from ALL ad valorem taxes on the principal residence and up to 160 acres.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Permanently and totally disabled, any age, no income limit (the $12,000 income condition in \u00a7 40-9-21 attaches only to the 65+ branch, not the disabled branch); 160-acre limit; single-family home owned/occupied as principal residence. Blind persons as defined in \u00a7 1-1-3 qualify similarly per \u00a7 40-9-19(a)(2),(d)."}'::jsonb,'Code of Alabama 1975 § 40-9-21','https://www.revenue.alabama.gov/property-tax/homestead-exemptions/','2026-06-14',2026),
  ('AL','state','payment',NULL,'Property taxes become due and payable on October 1 and become delinquent if not paid before January 1.','{"installments":[{"label":"Annual tax due","due_month":10,"due_day":1}],"delinquent_after_desc":"Delinquent if not paid before January 1 (i.e., after December 31)","locally_variable":false}'::jsonb,'Code of Alabama 1975 § 40-11-4','https://www.revenue.alabama.gov/faqs/what-is-the-timetable-for-property-taxes/','2026-06-14',2026),
  ('AZ','state','assessment_appeal',NULL,'An owner who believes their property was valued too high or improperly valued/classified may file a petition for review with the county assessor within 60 days after the date the assessor mailed the notice of valuation (administrative-level appeal). The county assessor is the first review body; further levels (State Board of Equalization or tax court) follow.','{"deadline_kind":"relative_to_roll","deadline_desc":"Within 60 days after the date the county assessor mailed the notice of valuation (or amended notice) under ARS 42-15101","review_body":"County assessor (administrative petition for review of valuation)","locally_variable":false}'::jsonb,'Ariz. Rev. Stat. § 42-16051','https://www.azleg.gov/ars/42/16051.htm','2026-06-14',2026),
  ('AZ','state','exemption','senior','Senior Property Valuation Protection Option (''senior freeze''). A resident 65 or older who has resided in the primary residence for two years may apply to the county assessor to freeze the property''s valuation. Income limit is 400% of the SSI benefit rate for a single owner, or 500% of the SSI benefit rate where there are two or more owners. Benefit is a valuation freeze, not a dollar exemption.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"assessment_freeze","income_unit":"usd_per_year","locally_variable":false,"notes":"Income tested as a percent of the federal Supplemental Security Income (SSI) benefit rate, not a fixed dollar figure: <=400% SSI for one owner, <=500% SSI for two or more owners. Requires two years residing in the primary residence before applying. Established in Ariz. Const. art. IX, sec. 18(7); administered via ADOR form 82104, application to county assessor. Verified against live azleg.gov const/9/18.htm; constitutional text is not seeded in the property_tax DB category, so re-fetched from the official source for this verification."}'::jsonb,'Ariz. Const. art. IX, § 18(7)','https://www.azleg.gov/viewDocument/?docName=http://www.azleg.gov/const/9/18.htm','2026-06-14',2026),
  ('AZ','state','exemption','disability','Statutory exemption for Arizona-resident widows, widowers, persons with a total and permanent disability, and veterans with service or non-service connected disabilities. Exempt assessed valuation amount is $4,188; no exemption if the claimant''s total assessment exceeds $28,459; claimant household income may not exceed $34,901 (where no children under 18 reside with the claimant). Dollar amounts are statutorily indexed and adjusted annually.','{"primary_residence_required":false,"ownership_required":true,"income_max":34901,"income_unit":"usd_per_year","benefit_kind":"exempt_value_cap","benefit_value":4188,"benefit_unit":"usd","locally_variable":false,"notes":"Exempt assessed valuation of $4,188; phases out / no exemption once total assessment exceeds $28,459; income ceiling $34,901 when no children under 18 reside with claimant (higher ceiling $41,870 applies when minor or disabled children reside there, per subsection H.2). Same statute covers widows/widowers, total-and-permanent-disability persons, and disabled veterans. Figures are annually inflation-adjusted (GDP price deflator / federal house price index per subsection F); 2025/2026 values as retrieved; re-verify on annual refresh. Benefit is an exempt assessed-value amount, not a full property exemption."}'::jsonb,'Ariz. Rev. Stat. § 42-11111','https://www.azleg.gov/ars/42/11111.htm','2026-06-14',2026),
  ('AZ','state','payment',NULL,'Property taxes over $100 are payable in two installments: first half due October 1 (delinquent after 5:00 p.m. November 1), second half due the following March 1 (delinquent after 5:00 p.m. May 1). Taxes of $100 or less are due in full October 1 and delinquent after December 31. If a delinquency date falls on a weekend or legal holiday, the deadline moves to 5:00 p.m. the next business day.','{"installments":[{"label":"First half (taxes over $100)","due_month":10,"due_day":1},{"label":"Second half (taxes over $100)","due_month":3,"due_day":1}],"delinquent_after_desc":"First half delinquent after 5:00 p.m. November 1; second half delinquent after 5:00 p.m. the following May 1. Taxes of $100 or less due in full October 1, delinquent after December 31 at 5:00 p.m. Weekend/holiday delinquency dates roll to 5:00 p.m. the next business day.","locally_variable":false}'::jsonb,'Ariz. Rev. Stat. § 42-18052','https://www.azleg.gov/ars/42/18052.htm','2026-06-14',2026),
  ('AZ','state','delinquency_redemption',NULL,'Delinquent property taxes bear interest at 16% per year simple from the time of delinquency until paid. Arizona collects delinquent taxes by selling a tax lien (not the property/deed) via the county treasurer. A real property tax lien may be redeemed within three years after the date of the tax lien sale (and thereafter until a treasurer''s deed is delivered); after the three-year period the certificate holder may begin foreclosure to obtain a treasurer''s deed.','{"late_interest_pct_per_year":16,"redemption_period_months":36,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"16% per year simple interest on delinquent taxes (ARS 42-18053); fractions of a month count as a whole month. Tax-lien sale conducted by county treasurer (ARS 42-18101). Redemption available within three years after the tax lien sale, and after three years but before delivery of a treasurer''s deed (ARS 42-18152); a partially redeemed lien must be fully redeemed before the deed issues. The 16% is the statutory ceiling for the bid-down auction interest rate \u2014 confirmed via ARS 42-18114, which provides the lien is sold to the bidder accepting the lowest rate ''which may not exceed the rate prescribed by ... section 42-18053'' (42-18114 is not in this fact''s citation list but was independently verified)."}'::jsonb,'Ariz. Rev. Stat. §§ 42-18053, 42-18101, 42-18152','https://www.azleg.gov/ars/42/18152.htm','2026-06-14',2026),
  ('AR','state','exemption','homestead','Arkansas grants a Homestead Property Tax Credit reducing real property tax on an owner''s principal place of residence. The credit is up to $500/year; the General Assembly authorized an increase to up to $600 beginning with the 2026 tax bills. The credit cannot reduce taxes below $0. Owners register with the county assessor; the credit is not allowed after October 15 of the year after the assessment.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"fixed_amount","benefit_value":500,"benefit_unit":"usd","locally_variable":false,"notes":"Up to $500/year per DFA; authorized increase to up to $600 beginning with 2026 tax bills (Act 330 of 2025). The codified statutory base figure in A.C.A. 26-26-1118 trails the administrative amount (2024 text states $425); the DFA-published current/forward credit is up to $500 rising to $600. Assessment cannot be reduced below $0.00. Register with the county assessor; credit not allowed after Oct 15 of the year after the assessment (next business day if Oct 15 is a Sat/Sun/USPS holiday)."}'::jsonb,'Ark. Code Ann. § 26-26-1118','https://www.dfa.arkansas.gov/office/arkansas-assessment-coordination-division/real-property/property-tax-relief/','2026-06-14',2026),
  ('AR','state','exemption','senior','Arkansas freezes the taxable assessed value of a homestead for owners who are age 65 or older or disabled and who qualify for the homestead credit. The frozen value is set at the value of the homestead at the next assessment date after the owner turns 65 or becomes disabled. The frozen value may rise only for new construction or substantial improvements (defined as renovation, reconstruction and refurbishment adding 25% or more to value).','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"assessment_freeze","locally_variable":false,"notes":"Applies to homeowners who qualify for the homestead credit and are age 65+ OR disabled (Amendment 79). Freezes the taxable assessed value at the value at the next assessment date after the owner turns 65 / becomes disabled. Frozen value increases only on new construction or substantial improvements (renovation, reconstruction, refurbishment) adding 25%+ to value. CITATION CORRECTED: the current codified freeze statute is A.C.A. 26-26-1124 (''Property tax relief for persons disabled or more than sixty-five years of age''), not 26-26-1120 as originally cited; the verified benefit text is from the AAC/DFA Property Tax Relief page."}'::jsonb,'Ark. Code Ann. § 26-26-1124','https://www.dfa.arkansas.gov/office/arkansas-assessment-coordination-division/real-property/property-tax-relief/','2026-06-14',2026),
  ('AR','state','assessment_appeal',NULL,'A property owner disputing an assessment first makes an informal appeal to the County Assessor, then appeals to the County Board of Equalization. The last day to schedule an appeal hearing with the County Board of Equalization is the third Monday in August.','{"deadline_kind":"fixed_date","deadline_month":8,"deadline_desc":"Third Monday in August - last day to schedule an appeal hearing with the County Board of Equalization","review_body":"County Board of Equalization (informal appeal to County Assessor first; further appeal to County Court / County Judge)","locally_variable":false}'::jsonb,'Ark. Code Ann. § 26-27-317 (Board of Equalization petition/hearing); informal review under § 26-23-101 et seq.','https://www.dfa.arkansas.gov/office/arkansas-assessment-coordination-division/real-property/residential-real-estate/','2026-06-14',2026),
  ('AR','state','payment',NULL,'Arkansas property taxes are payable to the County Collector by October 15 each year (next business day if Oct 15 is a Saturday, Sunday, or legal/USPS holiday). Taxpayers may pay in installments: first quarter by the third Monday in April, second quarter by the third Monday in July, and the balance by October 15. Taxes not paid by October 15 are delinquent.','{"installments":[{"label":"First quarter (1/4)","due_month":4,"due_day":null},{"label":"Second quarter (1/4)","due_month":7,"due_day":null},{"label":"Balance / remaining 1/2","due_month":10,"due_day":15}],"delinquent_after_desc":"Delinquent if any real or personal property tax is not paid by October 15 (next business day if Oct 15 falls on a Saturday, Sunday, or legal/USPS-observed holiday)","locally_variable":false,"notes":"Statewide due date Oct 15 verbatim-confirmed on the cited DFA page. Installment option (1st 1/4 by third Monday in April, 2nd 1/4 by third Monday in July, balance 1/2 by Oct 15) is from A.C.A. 26-35-501 ''Time to pay - Installments'' \u2014 verified against the statute, not present verbatim on the cited DFA source_url. Installment due days are the ''third Monday'' (variable calendar day), so due_day left null for April/July."}'::jsonb,'Ark. Code Ann. § 26-35-501','https://www.dfa.arkansas.gov/office/arkansas-assessment-coordination-division/real-property/residential-real-estate/','2026-06-14',2026),
  ('AR','state','delinquency_redemption',NULL,'Property taxes not paid by October 15 are delinquent and the county collector extends a 10% penalty, per A.C.A. § 26-36-201. Real property remaining delinquent is certified to the Commissioner of State Lands; the owner may redeem at any time after certification and prior to sale (a Redemption Deed is then issued and filed with the county). At a Tax Delinquent Property Auction the purchaser receives a Limited Warranty Deed from the Commissioner (tax-deed system, not a tax-lien certificate).','{"late_penalty_pct":10,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"10% delinquency penalty per A.C.A. 26-36-201 (verified against statute). Delinquent real property is certified to the Commissioner of State Lands; redemption allowed at any time after Certification and prior to sale, then a Redemption Deed is issued and filed with the county (verbatim in cited COSL Rules PDF). Sale conveys a Limited Warranty Deed (tax deed). CORRECTION: the original notes'' ''~2 years before public auction'' is NOT supported \u2014 the COSL Rules set the first Tax Delinquent Property Auction sale date ''no earlier than one (1) year after'' certification; the ''two (2) years'' figure refers to a Negotiated-Price (Unsold-Property) Auction held two+ years AFTER the initial auction. Unsold parcels move to Unsold-Property Auctions 30 calendar days after the initial auction. Redemption procedures in A.C.A. ch. 26-37; precise interest figures are not fixed here."}'::jsonb,'Ark. Code Ann. § 26-36-201 (10% delinquency penalty); §§ 26-37-101 et seq. (certification, sale, and redemption by Commissioner of State Lands)','https://arkleg.state.ar.us/Home/FTPDocument?path=%2FAssembly%2FMeeting+Attachments%2F040%2F26045%2FD.1.a.+COSL+Rules+and+Relevant+Acts.pdf','2026-06-14',2026),
  ('CA','state','assessment_appeal',NULL,'Assessment appeals are filed with the county board of equalization (assessment appeals board) on a regular filing period of July 2 through September 15. The deadline extends to November 30 in counties where the assessor does not provide value notices to all assessees by August 1.','{"deadline_kind":"window","deadline_month":9,"deadline_day":15,"deadline_desc":"Regular filing window July 2 - September 15 (inclusive); extended to November 30 in counties that do not mail value notices to all assessees by August 1. Some counties (e.g., first-class counties) the board convenes on the fourth Monday in September; all others on the third Monday in July.","review_body":"County board of equalization / county assessment appeals board (forms prescribed by the State Board of Equalization)","locally_variable":true}'::jsonb,'Cal. Rev. & Tax. Code § 1603; § 1604','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=1603.','2026-06-14',2026),
  ('CA','state','exemption','homestead','Homeowners'' property tax exemption reduces the assessed value of an owner-occupied principal-residence dwelling by $7,000. Does not apply to rented, vacant, under-construction, vacation/secondary homes, or property receiving the veterans'' exemption.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":7000,"benefit_unit":"usd","locally_variable":false,"notes":"Exemption is from assessed (full) value, not a dollar tax credit. Does not extend to rented, vacant, under-construction, vacation/secondary homes, or property where owner receives the veterans'' exemption."}'::jsonb,'Cal. Rev. & Tax. Code § 218 (Cal. Const. art. XIII, § 3(k))','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=218.','2026-06-14',2026),
  ('CA','state','exemption','disabled_veteran','Disabled veterans'' exemption exempts up to $100,000 of the full value of a veteran''s principal residence (blind in both eyes, loss of use of two or more limbs, or totally disabled from service); raised to $150,000 if household income does not exceed $40,000. All three figures are annually inflation-adjusted.','{"income_max":40000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":100000,"benefit_unit":"usd","locally_variable":false,"notes":"Base exempt value $100,000; rises to $150,000 if household income does not exceed $40,000. All three dollar figures ($100k / $150k / $40k income limit) are adjusted annually for inflation per subdivisions (h) and (i). Veteran must be blind in both eyes, have lost use of two or more limbs, or be totally disabled from a service-connected injury/disease; also covers an unmarried surviving spouse in related provisions."}'::jsonb,'Cal. Rev. & Tax. Code § 205.5','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=205.5.','2026-06-14',2026),
  ('CA','state','exemption','senior','Persons over age 55 (or severely and permanently disabled) who own a home eligible for the homeowners'' exemption may transfer the property''s Proposition 13 base year value to a replacement principal residence of equal or lesser value, purchased or built within two years of selling the original property.','{"age_min":55,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","locally_variable":false,"notes":"Not a dollar exemption: a base-year-value transfer (Proposition 13 carryover). Original and replacement dwelling generally within the same county; a county board of supervisors may by ordinance allow inter-county transfers. Replacement must be of equal or lesser value and acquired within two years of the sale of the original property. Also available to severely and permanently disabled persons regardless of age."}'::jsonb,'Cal. Rev. & Tax. Code § 69.5 (Cal. Const. art. XIII A, § 2(a))','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=69.5.','2026-06-14',2026),
  ('CA','state','payment',NULL,'Secured-roll real property taxes are payable in two installments: the first half is due November 1 and delinquent after December 10; the second half is due February 1 and delinquent after April 10. A 10% delinquent penalty attaches to each installment after its delinquency date.','{"installments":[{"label":"First installment (half of real property tax)","due_month":11,"due_day":1},{"label":"Second installment (second half)","due_month":2,"due_day":1}],"delinquent_after_desc":"First installment delinquent at 5 p.m. (or close of business, whichever is later) on December 10; second installment delinquent at 5 p.m. (or close of business, whichever is later) on April 10. A 10% penalty attaches to each installment after delinquency.","locally_variable":false}'::jsonb,'Cal. Rev. & Tax. Code §§ 2605, 2606, 2617, 2618','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=2617.','2026-06-14',2026),
  ('CA','state','delinquency_redemption',NULL,'Defaulted property may be redeemed up until the right of redemption terminates at the close of business on the last business day before the tax sale; redemption penalties accrue at 1.5% per month (18% per year) on the declared defaulted amount. The tax collector''s power to sell (tax-deed sale at public auction) arises 5 years after default for residential property, or 3 years for nonresidential commercial property.','{"late_penalty_pct":10,"late_interest_pct_per_year":18,"redemption_period_months":60,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Redemption penalty is 1.5% per month (= 18%/yr) on the declared defaulted amount, beginning July 1 of the year of default, until redeemed (\u00a7 4103(a)(1)). Right of redemption terminates at the close of business on the last business day prior to the commencement date of the tax sale (\u00a7 3707(a)(1)). Power to sell arises 5 years after default for residential, or 3 years for nonresidential commercial property; by ordinance a county may elect to have the 5-year period apply to nonresidential commercial property (i.e., opt that property OUT of the 3-year default) (\u00a7 3691(a)(1)(A),(C)). California conveys property by tax-deed at public auction (\u00a7 3692), not tax-lien certificates. The 10% figure is the initial delinquency penalty (\u00a7\u00a7 2617/2618); ongoing redemption interest is 1.5%/month."}'::jsonb,'Cal. Rev. & Tax. Code § 4103; § 3691; § 3707; § 3692','https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?lawCode=RTC&sectionNum=4103.','2026-06-14',2026),
  ('CO','state','assessment_appeal',NULL,'Real property: object/protest to the county assessor (notice postmarked, delivered, or given in person by June 8). If denied, appeal to the County Board of Equalization by July 15. Personal property has later dates (protest by June 30; CBOE petition by July 20). Counties electing the alternate procedure under 39-5-122.7 use later dates (Aug 15 / Sept 15).','{"deadline_kind":"fixed_date","deadline_month":6,"deadline_day":8,"deadline_desc":"Real property protest to assessor by June 8; appeal to County Board of Equalization by July 15. Personal property: protest by June 30, CBOE petition by July 20. Alternate-procedure counties (39-5-122.7): Aug 15 assessor / Sept 15 CBOE.","review_body":"County assessor (first-level protest), then County Board of Equalization (appeal)","locally_variable":true}'::jsonb,'C.R.S. § 39-5-122; C.R.S. § 39-8-106','https://content.leg.colorado.gov/sites/default/files/images/olls/crs2024-title-39.pdf','2026-06-14',2026),
  ('CO','state','exemption','senior','Senior homestead exemption: owner-occupier age 65+ as of the assessment date who has owned and occupied the property as primary residence for the 10 preceding years (or qualifying surviving spouse). Exempts 50% of the first $200,000 of actual value of the residence. Application required under 39-3-205. No income test in statute.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":200000,"benefit_unit":"usd","notes":"Exempts 50% of the first $200,000 of actual value (i.e., up to $100,000 of actual value exempted). Requires 10 years of continuous ownership and occupancy as primary residence. Surviving spouse of a qualified senior may continue. Benefit applies only in tax years the legislature funds it (statute alternates funded/unfunded years). Application required under C.R.S. 39-3-205.","locally_variable":false}'::jsonb,'C.R.S. § 39-3-203(1)','https://content.leg.colorado.gov/sites/default/files/images/olls/crs2024-title-39.pdf','2026-06-14',2026),
  ('CO','state','exemption','disabled_veteran','Disabled-veteran homestead exemption: owner-occupier who is a qualifying veteran with a disability and uses the property as primary residence. Exempts 50% of the first $200,000 of actual value. Qualifying surviving spouse may continue (tax years on/after Jan 1, 2015). Application required under 39-3-205.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":200000,"benefit_unit":"usd","notes":"Exempts 50% of the first $200,000 of actual value (up to $100,000 of actual value exempted). Owner-occupier must be a ''qualifying veteran with a disability''; surviving spouse may continue for tax years on/after Jan 1, 2015. No age minimum. Application required under C.R.S. 39-3-205.","locally_variable":false}'::jsonb,'C.R.S. § 39-3-203(1.5)','https://content.leg.colorado.gov/sites/default/files/images/olls/crs2024-title-39.pdf','2026-06-14',2026),
  ('CO','state','payment',NULL,'At the taxpayer''s option, property taxes may be paid in full or in two equal installments. First installment due by the last day of February; second by June 15. Alternatively, full payment by April 30 avoids delinquent interest. Delinquent interest accrues at 1% per month. Taxes under $25 must be paid in full by last day of April.','{"installments":[{"label":"First installment (half)","due_month":2,"due_day":28},{"label":"Second installment (half)","due_month":6,"due_day":15},{"label":"Full payment option","due_month":4,"due_day":30}],"delinquent_after_desc":"First installment delinquent interest accrues from March 1 at 1%/month if unpaid by last day of February; second installment from June 16 at 1%/month if unpaid by June 15. Full single payment after April 30 accrues 1%/month from May 1.","locally_variable":false}'::jsonb,'C.R.S. § 39-10-104.5','https://content.leg.colorado.gov/sites/default/files/images/olls/crs2024-title-39.pdf','2026-06-14',2026),
  ('CO','state','delinquency_redemption',NULL,'Colorado sells a tax lien (certificate of purchase) for delinquent taxes, not a tax deed at sale. The owner (or other interested party) may redeem at any time before the treasurer executes a treasurer''s deed to the purchaser. Redemption interest is set annually at 9 percentage points above the federal-reserve discount rate, rounded to the nearest full percent.','{"redemption_period_months":null,"tax_sale_kind":"tax_lien","late_interest_pct_per_year":null,"notes":"Redemption available any time before a treasurer''s deed is issued (no fixed month count; a treasurer''s deed cannot issue until at least 3 years after the lien sale under Article 11). Redemption interest rate = 9 percentage points above the Federal Reserve Bank of Kansas City discount rate, rounded to nearest full percent, reset each Sept 1 effective Oct 1. Partial months counted as whole months.","locally_variable":false}'::jsonb,'C.R.S. § 39-12-103','https://content.leg.colorado.gov/sites/default/files/images/olls/crs2024-title-39.pdf','2026-06-14',2026),
  ('CT','state','assessment',NULL,'Connecticut assesses all property at a uniform 70% of present true and actual (market) value, with a statewide uniform assessment date of October 1. The specific local mill rate is set by each municipality.','{"assessment_ratio_pct":70,"market_value_standard":"present true and actual value","assessment_date_month":10,"assessment_date_day":1,"reassessment_cycle_years":5,"locally_variable":false,"notes":"70% ratio and Oct 1 date are state-mandated and uniform (Sec. 12-62a). Revaluation cycle (max 5 years) is set under Sec. 12-62; mill rates are local. Verified verbatim against DB: 12-62a(a)(b) and 12-62(b) both confirmed."}'::jsonb,'Conn. Gen. Stat. Sec. 12-62a','https://www.cga.ct.gov/current/pub/chap_203.htm','2026-06-14',2026),
  ('CT','state','assessment_appeal',NULL,'An aggrieved property owner appeals the assessor''s valuation to the municipal Board of Assessment Appeals; the written appeal must be filed on or before February 20. A taxpayer dissatisfied with the Board''s decision (or whose appeal the Board declines to hear) may then appeal to the Superior Court within two months of the mailing of the Board''s notice.','{"deadline_kind":"fixed_date","deadline_month":2,"deadline_day":20,"deadline_desc":"Written appeal to the Board of Assessment Appeals on or before February 20; further appeal to Superior Court within two months of mailing of the Board''s notice of action.","review_body":"Board of Assessment Appeals (then Superior Court on further appeal)","locally_variable":false}'::jsonb,'Conn. Gen. Stat. Sec. 12-111, 12-112; Sec. 12-117a','https://www.cga.ct.gov/current/pub/chap_203.htm','2026-06-14',2026),
  ('CT','state','exemption','veteran','A resident veteran who was a member of the armed forces in service during a time of war is entitled to a base exemption of $1,000 of assessed property value (subject to filing/eligibility conditions). Municipalities may grant additional optional veteran exemptions.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":1000,"benefit_unit":"usd","locally_variable":false,"notes":"Base state veteran exemption is a fixed $1,000 of assessed value (Sec. 12-81(19)), verified verbatim. Municipalities may add optional supplemental exemptions under Sec. 12-81f and others; those are locally variable. Conditions in Sec. 12-89/12-90/12-95 apply (cited verbatim in the statute)."}'::jsonb,'Conn. Gen. Stat. Sec. 12-81(19)','https://www.cga.ct.gov/current/pub/chap_203.htm','2026-06-14',2026),
  ('CT','state','exemption','disabled_veteran','A resident serviceperson or veteran with a VA disability rating receives a graduated exemption of assessed value: $2,000 for a rating of 10-25%, $2,500 for >25-50%, $3,000 for >50-75%, and $3,500 where the rating exceeds 75% or the person has attained age 65.','{"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":3500,"benefit_unit":"usd","age_min":65,"locally_variable":false,"notes":"Graduated by VA disability rating: $2,000 (10-25%), $2,500 (>25-50%), $3,000 (>50-75%), $3,500 (>75% or age 65+). All four tiers + age-65 trigger verified verbatim against Sec. 12-81(20)(A). Maximum tier ($3,500) shown in benefit_value. Separate service-connected permanent-and-total provisions exist elsewhere (subdivision (83) referenced)."}'::jsonb,'Conn. Gen. Stat. Sec. 12-81(20)','https://www.cga.ct.gov/current/pub/chap_203.htm','2026-06-14',2026),
  ('CT','state','exemption','senior','A municipality MAY (by vote of its legislative body) provide local property tax relief on the owner-occupied principal residence of residents age 65 or over (or surviving spouses age 60+), and residents under 65 who are permanently and totally disabled, subject to a one-year residency requirement and a locally-set maximum income limit. This is a local-option program, not a uniform statewide exemption.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"income_max":null,"income_unit":"usd_per_year","benefit_kind":"fixed_amount","locally_variable":true,"notes":"Local-option only (Sec. 12-129n) \u2014 each municipality decides whether to offer it, sets the maximum allowable income and the form/extent of relief. Surviving spouse eligible at 60+. Also covers permanently and totally disabled residents under 65. All elements verified verbatim. A separate statewide circuit-breaker elderly/disabled homeowners program exists at Sec. 12-170aa (not present in the queried database and therefore not asserted here)."}'::jsonb,'Conn. Gen. Stat. Sec. 12-129n','https://www.cga.ct.gov/current/pub/chap_204.htm','2026-06-14',2026),
  ('CT','state','payment',NULL,'The legislative body of each municipality decides whether the property tax is due in one, two, or four installments and sets the due date(s) (the last installment must be due no later than 45 days before the fiscal year-end). A tax/installment becomes delinquent if not paid by the first day of the month after it became due; delinquent tax accrues interest at 1.5% per month (18% per year), with a $2 minimum per installment.','{"installments":[],"delinquent_after_desc":"Delinquent if not paid in full on or before the first day of the month next succeeding the month in which it became due and payable; once delinquent, 1.5%/month (18%/yr) interest applies from the original due date.","grace_days":null,"locally_variable":true,"notes":"Due dates and number of installments (1, 2, or 4) are set locally by each municipality''s legislative body (Sec. 12-142); the last installment must be due no later than 45 days before fiscal year-end. Delinquency interest rate (1.5%/month per Sec. 12-145 = 18%/yr per Sec. 12-146, $2 minimum/installment) is state-fixed. All figures verified verbatim; the 1.5%/month and 18%/yr are the same rate stated two ways across the two sections."}'::jsonb,'Conn. Gen. Stat. Sec. 12-142; Sec. 12-145; Sec. 12-146','https://www.cga.ct.gov/current/pub/chap_204.htm','2026-06-14',2026),
  ('CT','state','delinquency_redemption',NULL,'On a tax sale of real estate, the collector executes a deed to the purchaser which remains unrecorded for six months from the date of sale. The owner (or other party in interest) may redeem within that six-month period by paying the purchase price plus interest at 18% per annum from the date of sale, plus other taxes/charges. If not redeemed, the deed is recorded and takes full effect.','{"late_interest_pct_per_year":18,"redemption_period_months":6,"tax_sale_kind":"hybrid","locally_variable":false,"notes":"Six-month redemption period runs from date of sale; redemption requires repaying the total purchase price plus 18%/yr interest from sale date plus unrecovered taxes/charges (Sec. 12-157(e),(f)). Collector''s deed becomes effective only after the redemption period lapses (Sec. 12-159 / 12-157(f)) \u2014 a tax-deed sale with a statutory redemption window, hence ''hybrid''. All figures verified verbatim."}'::jsonb,'Conn. Gen. Stat. Sec. 12-157; Sec. 12-159','https://www.cga.ct.gov/current/pub/chap_204.htm','2026-06-14',2026),
  ('DE','state','exemption','senior','Delaware grants a senior (age 65+) low-income county property-tax exemption: a resident 65 or older with income not over $3,000/year who owns and lives in the dwelling is exempt from county real-property tax on assessed valuation up to $5,000. Requires 10-year Delaware domicile. Does not apply to municipal taxes. Kent County sets its own senior exemption by ordinance (9 Del. C. § 8141).','{"age_min":65,"income_max":3000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":5000,"benefit_unit":"usd","locally_variable":true,"notes":"Exempt value cap is on assessed valuation, not market value. 10-year DE domicile required (9 Del. C. 8131). Spouse living in the home must also have income <= $3,000. County-administered; does not apply to municipal, ditch, or sewer taxes. Kent County provides its senior exemption by Levy Court ordinance per 9 Del. C. 8141. No statewide homestead, veteran, or general disability property-tax exemption exists in DE statute."}'::jsonb,'9 Del. C. § 8132','https://delcode.delaware.gov/title9/c081/sc02/index.html','2026-06-14',2026),
  ('DE','state','assessment',NULL,'Delaware real property is assessed at fair market value as of the county''s most recent reassessment base year, and each county must reassess all real property at least once every 5 years.','{"market_value_standard":"fair_market_value","reassessment_cycle_years":5,"locally_variable":true}'::jsonb,'9 Del. C. § 8306','https://delcode.delaware.gov/title9/c083/sc01/index.html','2026-06-14',2026),
  ('DE','state','assessment_appeal',NULL,'Assessment appeals are filed with the county Board of Assessment Review. New Castle County: written notice of appeal must be filed before March 15. Kent and Sussex Counties: the Board hears appeals March 1 through May 31. A board decision may be appealed to the Superior Court within 30 days.','{"deadline_kind":"fixed_date","deadline_month":3,"deadline_day":15,"deadline_desc":"New Castle County: file written notice prior to March 15. Kent and Sussex Counties: Board of Assessment Review hears appeals March 1 to May 31 each year. Further appeal to Superior Court within 30 days of receiving the board''s decision (9 Del. C. 8312(c)).","review_body":"County Board of Assessment Review (then Superior Court)","locally_variable":true}'::jsonb,'9 Del. C. § 8311','https://delcode.delaware.gov/title9/c083/sc01/index.html','2026-06-14',2026),
  ('DE','state','payment',NULL,'County real estate taxes are due each year on July 1 in New Castle and Sussex Counties and June 1 in Kent County. Late-payment penalties begin after September 1 in New Castle County (6% of the current charge plus 1%/month on unpaid principal) and after September 30 in Kent and Sussex Counties (1.5%/month).','{"installments":[{"label":"New Castle County annual tax due","due_month":7,"due_day":1},{"label":"Kent County annual tax due","due_month":6,"due_day":1},{"label":"Sussex County annual tax due","due_month":7,"due_day":1}],"delinquent_after_desc":"New Castle County: penalty added after September 1 (6% of current charge + 1% of unpaid principal per month). Kent and Sussex Counties: 1.5% per month added after September 30.","locally_variable":true}'::jsonb,'9 Del. C. § 8601','https://delcode.delaware.gov/title9/c086/index.html','2026-06-14',2026),
  ('DE','state','payment','late_penalty','Late-payment penalties on delinquent county property tax: New Castle County adds 6% of the current charge after September 1 plus 1% of unpaid principal per month thereafter; Kent and Sussex Counties add 1.5% per month after September 30.','{"delinquent_after_desc":"New Castle: 6% of current charge + 1%/month of unpaid principal after Sept 1. Kent/Sussex: 1.5%/month after Sept 30.","locally_variable":true,"notes":"Counties may by ordinance allow abatement or discount of penalties (9 Del. C. 8604(c)), and must waive penalties for qualifying residential taxpayers on an installment payment plan (9 Del. C. 8604(c)(2)/(d))."}'::jsonb,'9 Del. C. § 8604(a)','https://delcode.delaware.gov/title9/c086/index.html','2026-06-14',2026),
  ('DE','state','delinquency_redemption',NULL,'Delaware sells real property at a sheriff''s/tax sale to collect unpaid taxes. Under the monition method, the owner may redeem within 60 days after the court approves the sale by paying the purchase price plus 15%, plus costs. Under the older general tax-sale procedure, the owner may redeem within 1 year of sale by paying the purchase money plus 20% interest, costs, and expenses (no deed issues until that year expires).','{"late_penalty_pct":15,"redemption_period_months":12,"tax_sale_kind":"tax_deed","locally_variable":true,"notes":"Two parallel statutory tracks. Monition method (9 Del. C. 8729) and Superior Court order-of-sale (9 Del. C. 8758): 60-day redemption from court approval/confirmation at purchase price + 15%. General tax-sale procedure (9 Del. C. 8776): 1-year redemption at purchase money + 20% interest; no deed until the year expires. redemption_period_months reflects the longest (1-year) track; late_penalty_pct 15 reflects the monition track (20% applies under the 1-year track). Source_url points to subchapter IV (8776); 8729 lives in subchapter II at .../c087/sc02/index.html, 8758 in subchapter III at .../c087/sc03/index.html."}'::jsonb,'9 Del. C. §§ 8729, 8776','https://delcode.delaware.gov/title9/c087/sc04/index.html','2026-06-14',2026),
  ('FL','state','exemption','homestead','Florida homestead exemption: up to $25,000 off assessed value (all levies), plus an additional up to $25,000 off assessed value above $50,000 for all levies other than school district levies. Total exemption cannot exceed $50,000 of exempt value for a permanent-residence homestead.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":50000,"benefit_unit":"usd","locally_variable":false,"notes":"Two stacked components: first $25,000 applies to all levies; second up to $25,000 applies to assessed value above $50,000 and does NOT apply to school district levies. Statutory cap: ''an exemption of more than $25,000 is not allowed to any one person or on any one dwelling house'' per component."}'::jsonb,'Fla. Stat. § 196.031','https://www.flsenate.gov/Laws/Statutes/2024/196.031','2026-06-14',2026),
  ('FL','state','exemption','senior','Additional homestead exemption for residents age 65+ whose household income does not exceed a statutory income limit (base $20,000, adjusted annually for CPI). Local option: up to $50,000 additional exemption; alternatively a full exemption (the assessed value) for 65+ long-term residents (25+ years) whose property just value is under $250,000. Adopted by county/municipal ordinance.','{"age_min":65,"income_max":20000,"income_unit":"usd_per_year","primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":50000,"benefit_unit":"usd","locally_variable":true,"notes":"Income limit is the $20,000 statutory base ''adjusted annually'' per \u00a7 196.075(3) by the change in the cost-of-living index (CPI figures issued by the U.S. Dept. of Labor); the adjusted figure is well above $20,000 in recent years \u2014 confirm the live adjusted limit each year per the carve-out annual-refresh discipline. The property appraiser annually notifies each taxpayer of the adjusted limit (\u00a7 196.075(5)). Exemption only applies where the county or municipality has adopted the ordinance; amount up to $50,000. Alternative full-exemption option requires 25+ years residence and just value < $250,000."}'::jsonb,'Fla. Stat. § 196.075','https://www.flsenate.gov/Laws/Statutes/2024/196.075','2026-06-14',2026),
  ('FL','state','exemption','disabled_veteran_total','Total ad valorem exemption on the homestead of a veteran honorably discharged with a service-connected total and permanent disability (certified by the U.S. Department of Veterans Affairs), who is a Florida permanent resident on January 1 of the tax year. Extends to qualifying surviving spouse.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Full exemption from taxation (represented as 100% reduction). Requires VA certification letter as prima facie evidence and Florida permanent residency on Jan 1. Surviving spouse may carry the exemption if unmarried and continuing to reside in the homestead (\u00a7 196.081(3))."}'::jsonb,'Fla. Stat. § 196.081','https://www.flsenate.gov/Laws/Statutes/2024/196.081','2026-06-14',2026),
  ('FL','state','exemption','disabled_veteran_combat_age65','Ad valorem tax discount on homestead for a veteran age 65+ who is partially or totally permanently disabled from a combat-related disability and was honorably discharged. Discount percentage equals the veteran''s VA-determined permanent service-connected disability rating percentage.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"pct_reduction","benefit_unit":"pct","locally_variable":false,"notes":"Discount percentage is variable per veteran \u2014 it equals the individual''s VA service-connected disability rating. Requires the disability to be combat-related AND honorable discharge. Distinct from the \u00a7 196.081 total exemption (this is a partial discount tied to rating, for age 65+)."}'::jsonb,'Fla. Stat. § 196.082','https://www.flsenate.gov/Laws/Statutes/2024/196.082','2026-06-14',2026),
  ('FL','state','assessment_appeal',NULL,'A taxpayer contesting a property valuation files a petition with the county Value Adjustment Board (VAB) on or before the 25th day following the property appraiser''s mailing of the notice of proposed property taxes (TRIM notice). (Petitions contesting denial of an exemption, classification, or deferral instead have a 30-day deadline under § 194.011(3)(d).)','{"deadline_kind":"relative_to_roll","deadline_desc":"For valuation issues: on or before the 25th day following the property appraiser''s mailing of the notice of proposed property taxes (TRIM notice). The TRIM notice is typically mailed in August, so the deadline commonly falls in September, but the exact date depends on the mailing date each year. (Exemption/classification/deferral denials have a 30-day deadline.)","review_body":"Value Adjustment Board (county VAB)","locally_variable":false}'::jsonb,'Fla. Stat. § 194.011(3)','https://www.flsenate.gov/Laws/Statutes/2024/194.011','2026-06-14',2026),
  ('FL','state','payment',NULL,'Florida property taxes are due and payable November 1 (or as soon as the certified tax roll is received) and become delinquent April 1 of the following year, or 60 days after the original tax notice is mailed, whichever is later. Early-payment discounts apply Nov-Feb (collected locally by the county tax collector).','{"installments":[{"label":"Annual taxes due (payable from Nov 1; full delinquency Apr 1)","due_month":11,"due_day":1}],"delinquent_after_desc":"Delinquent on April 1 following the assessment year, or immediately after 60 days from the mailing of the original tax notice, whichever is later.","locally_variable":true,"notes":"Statewide statutory framework sets the Nov 1 due / Apr 1 delinquency dates (\u00a7 197.333). The early-payment discount schedule (\u00a7 197.162: 4% in November, 3% December, 2% January, 1% February, 0% March) and any installment-payment plan (\u00a7 197.222) are administered by the county tax collector \u2014 locally administered within the state framework."}'::jsonb,'Fla. Stat. § 197.333','https://www.flsenate.gov/Laws/Statutes/2024/197.333','2026-06-14',2026),
  ('FL','state','delinquency_redemption',NULL,'Florida is a tax-lien-certificate state. On delinquency the county sells a tax certificate; the owner may redeem at any time after the certificate is issued and before a tax deed is issued, paying face amount plus interest/costs/charges. Redemption interest is the rate bid on the certificate or a mandatory minimum of 5%, whichever is greater (the 5% minimum does not apply to 0%-bid certificates). A certificate holder may apply for a tax deed only after 2 years have elapsed since April 1 of the year the certificate was issued — i.e., the owner''s practical redemption window runs at least ~2 years.','{"late_penalty_pct":5,"redemption_period_months":24,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"Mandatory minimum 5% interest on the certificate face value (or the higher bid rate); 0%-bid certificates exempt from the 5% minimum (\u00a7 197.472(2)). Redemption is open until a tax deed issues (\u00a7 197.472(1)). A tax deed application cannot be made until 2 years after April 1 of the year of certificate issuance (\u00a7 197.502(1)), which bounds the minimum redemption window at ~24 months. $6.25 tax collector fee per certificate redeemed (\u00a7 197.472(3)). Hybrid note: certificates are sold as liens (tax_lien), but title ultimately transfers via a tax deed sale (\u00a7 197.502/197.542) if not redeemed."}'::jsonb,'Fla. Stat. §§ 197.472, 197.502','https://www.flsenate.gov/Laws/Statutes/2024/197.472','2026-06-14',2026),
  ('GA','state','assessment_appeal',NULL,'A property owner may appeal the assessment within 45 days of the date the annual Assessment Notice was mailed. The appeal goes to the county board of tax assessors, who may certify it to the county board of equalization (and may also be heard by a hearing officer or nonbinding arbitration). Appeal may address taxability, value, uniformity, and/or denial of an exemption.','{"deadline_kind":"relative_to_roll","deadline_desc":"within 45 days of the date the annual Assessment Notice was mailed","review_body":"county board of tax assessors; appeals certified to the county board of equalization (hearing officer or nonbinding arbitration also available)","locally_variable":true}'::jsonb,'O.C.G.A. § 48-5-311','https://dor.georgia.gov/property-tax-real-and-personal-property-faq','2026-06-14',2026),
  ('GA','state','assessment',NULL,'Georgia assesses real property at 40% of fair market value statewide; the millage rate is applied to assessed value (less applicable exemptions) to compute tax due. Millage rates are set locally.','{"assessment_ratio_pct":40,"market_value_standard":"fair market value","locally_variable":true}'::jsonb,'O.C.G.A. § 48-5-7','https://dor.georgia.gov/property-tax-real-and-personal-property-faq','2026-06-14',2026),
  ('GA','state','exemption','homestead','Standard homestead exemption: the home of each Georgia resident actually occupied and used as the owner''s primary residence (owned and occupied as legal residence on January 1 of the taxable year) may receive a $2,000 exemption from county and school taxes, deducted from the 40% assessed value.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":2000,"benefit_unit":"usd","locally_variable":false,"notes":"Deducted from the 40% assessed value; ownership and occupancy as legal residence required as of January 1. Many counties/localities offer larger local homestead exemptions on top of this state floor."}'::jsonb,'O.C.G.A. § 48-5-44','https://dor.georgia.gov/property-tax-homestead-exemptions','2026-06-14',2026),
  ('GA','state','exemption','senior','Individuals 65 years of age or older may claim a $4,000 exemption from all county ad valorem taxes if the income of that person and spouse does not exceed $10,000 for the prior year (certain retirement/Social Security income is excluded from that income test).','{"age_min":65,"income_max":10000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":4000,"benefit_unit":"usd","locally_variable":false,"notes":"Income excludes certain retirement-source income up to the federal Social Security maximum benefit. Applies to county ad valorem taxes."}'::jsonb,'O.C.G.A. § 48-5-47','https://dor.georgia.gov/property-tax-homestead-exemptions','2026-06-14',2026),
  ('GA','state','exemption','senior_school','Educational/school exemption: individuals 62 years of age or older may claim an additional exemption from ad valorem taxes for educational purposes if the income of that person and spouse does not exceed $10,000 for the prior year; the exemption may not exceed $10,000 of the homestead''s assessed value.','{"age_min":62,"income_max":10000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":10000,"benefit_unit":"usd","locally_variable":false,"notes":"Applies to ad valorem taxes for educational purposes (school taxes). Separate from the age-65 county exemption (O.C.G.A. 48-5-47)."}'::jsonb,'O.C.G.A. § 48-5-52','https://dor.georgia.gov/property-tax-homestead-exemptions','2026-06-14',2026),
  ('GA','state','exemption','disabled_veteran','Qualifying disabled veterans are granted a homestead exemption of the greater of $32,500 or the federally indexed maximum amount; for 2025 the amount is $121,812. May extend to an unremarried surviving spouse/minor children.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":121812,"benefit_unit":"usd","locally_variable":false,"notes":"Statutory floor is the greater of $32,500 or the federally indexed maximum; the $121,812 figure is the 2025 indexed maximum and is refreshed annually (2026 indexed amount is $126,526). Exemption applies against the value of the homestead."}'::jsonb,'O.C.G.A. § 48-5-48','https://dor.georgia.gov/property-tax-homestead-exemptions','2026-06-14',2026),
  ('GA','state','payment',NULL,'Property taxes are normally due December 20 in most counties, but counties may set a different due date; taxpayers have 60 days from the date of billing to pay. Due dates and delinquency are set locally by the county tax commissioner.','{"installments":[{"label":"Annual tax bill (typical, most counties)","due_month":12,"due_day":20}],"delinquent_after_desc":"Delinquent after the county due date; taxpayers have 60 days from the date of billing to pay. Specific due/delinquency dates are set locally by the county.","grace_days":60,"locally_variable":true}'::jsonb,'O.C.G.A. § 48-5-148 (interest on delinquency); county-set due dates','https://dor.georgia.gov/property-tax-real-and-personal-property-faq','2026-06-14',2026),
  ('GA','state','delinquency_redemption',NULL,'Georgia is a redeemable tax-deed (hybrid) state. After a tax sale the owner (or any party in interest) may redeem at any time during the 12 months following the sale, and thereafter until the right is foreclosed by notice. The redemption amount is the price paid at the sale plus taxes the purchaser later paid, plus a premium of 20% of that amount for the first year (or fraction) and an additional 10% for each year (or fraction) thereafter.','{"late_penalty_pct":20,"redemption_period_months":12,"tax_sale_kind":"hybrid","locally_variable":false,"notes":"Premium is 20% for the first year/fraction and an additional 10% for each subsequent year/fraction until redemption (per O.C.G.A. 48-4-42, for sales after July 1, 2002). The 12-month period (O.C.G.A. 48-4-40) is the minimum before the purchaser may begin barring/foreclosing the right of redemption; the right persists until properly foreclosed by notice. Redeemable tax deed, not a pure tax-lien certificate."}'::jsonb,'O.C.G.A. §§ 48-4-40, 48-4-42','https://taxes.franklincountyga.com/ad-valorem-tax-process/','2026-06-14',2026),
  ('HI','state','assessment_appeal',NULL,'In Hawaii all real property taxation is county-administered (the statewide Real Property Tax Law, HRS ch. 246, was repealed L 2016 c 52 when the function moved fully to the four counties). For the City & County of Honolulu (the state''s largest jurisdiction, ~70% of population), the assessment notice (NOA) is mailed on or before December 15 and an appeal to the county Board of Review (BOR) must be filed by the January 15 deadline. Other Hawaii counties (Hawaii, Maui, Kauai) set their own dates by ordinance.','{"deadline_kind":"fixed_date","deadline_month":1,"deadline_day":15,"deadline_desc":"Appeal to county Board of Review due January 15; Honolulu Notice of Assessment mailed on/before December 15","review_body":"County Board of Review (Honolulu BOR); further appeal to the Tax Appeal Court of the State of Hawaii","locally_variable":true}'::jsonb,'City & County of Honolulu Real Property Tax (ROH ch. 8); Hawaii Const. art. VIII, sec. 3 (RPT function vested in counties); HRS ch. 246 repealed L 2016 c 52','https://realproperty.honolulu.gov/appeals/appeal-information/','2026-06-14',2026),
  ('HI','state','exemption','homestead','Honolulu (City & County) home exemption reduces the taxable assessed value of an owner-occupied principal residence by $120,000 (figure in effect through June 30, 2027; it rises to $140,000 effective July 1, 2027). A claim (form BFS-RPA-E-8-10.3) must be filed with the Real Property Assessment Division on or before September 30 preceding the tax year. Exemption amounts and rules are set per county and vary across Hawaii''s four counties.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":120000,"benefit_unit":"usd","locally_variable":true,"notes":"Honolulu figure, in effect through June 30, 2027; rises to $140,000 effective July 1, 2027. Claim filed by September 30 preceding the tax year (e.g., file by Sept 30, 2025 for tax year July 1, 2026 - June 30, 2027). Other counties set their own home-exemption amounts."}'::jsonb,'City & County of Honolulu, Real Property Assessment Division home exemption (form BFS-RPA-E-8-10.3)','https://realproperty.honolulu.gov/tax-relief-and-forms/exemptions/home-exemption/','2026-06-14',2026),
  ('HI','state','exemption','senior','Honolulu (City & County) increases the owner-occupant home exemption to $160,000 of assessed value if the owner is 65 years or older on or before June 30 preceding the tax year. The home-exemption claim must be filed on or before September 30 preceding that tax year. Amounts and age thresholds are county-set and vary across Hawaii''s four counties.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":160000,"benefit_unit":"usd","locally_variable":true,"notes":"Honolulu figure. Owner must be 65+ on/before June 30 preceding the tax year; claim filed by September 30. Other Hawaii counties set their own senior exemption amounts and brackets."}'::jsonb,'City & County of Honolulu, Real Property Assessment Division home exemption (multiple home exemption / age 65+)','https://realproperty.honolulu.gov/tax-relief-and-forms/exemptions/exemption-faq/','2026-06-14',2026),
  ('HI','state','payment',NULL,'Honolulu (City & County) bills real property tax in two installments: the first installment is due August 20 and the second installment is due February 20. Taxes unpaid after the due date are delinquent and subject to a penalty of up to 10% plus interest of 12% a year. Due dates, penalty, and interest are county-set and vary across Hawaii''s four counties.','{"installments":[{"label":"First installment","due_month":8,"due_day":20},{"label":"Second installment","due_month":2,"due_day":20}],"delinquent_after_desc":"Delinquent if unpaid after the installment due date; penalty up to 10% plus interest of 12% per year","locally_variable":true}'::jsonb,'City & County of Honolulu Real Property Tax (ROH ch. 8); Treasury Division, Dept. of Budget & Fiscal Services','https://www.honolulu.gov/mayor/reminder-first-property-tax-installment-for-2025-2026-due-august-20/','2026-06-14',2026),
  ('HI','state','delinquency_redemption',NULL,'Hawaii''s statutory tax-lien/tax-deed redemption framework (HRS sec. 231-67) lets the taxpayer redeem property sold at a tax sale within one year from the date of sale (or one year from deed recording if the deed was not recorded within 60 days of sale) by paying the purchase price, costs, and interest at 12% a year. Since the statewide Real Property Tax Law (HRS ch. 246) was repealed in 2016, the actual real-property tax-sale and redemption process is administered per county by ordinance; this section is the state framework and county specifics vary.','{"late_interest_pct_per_year":12,"redemption_period_months":12,"tax_sale_kind":"tax_deed","locally_variable":true}'::jsonb,'Haw. Rev. Stat. sec. 231-67 (Tax liens; tax deed; redemption)','https://files.hawaii.gov/tax/legal/hrs/hrs_231.pdf','2026-06-14',2026),
  ('IA','state','assessment',NULL,'Iowa property is valued at its actual (fair market) value and assessed at 100% of that actual value statewide; the assessed value equals the taxable value on which levies are made.','{"assessment_ratio_pct":100,"market_value_standard":"actual value = fair and reasonable market value (willing buyer / willing seller)","locally_variable":false}'::jsonb,'Iowa Code § 441.21(1)(a)-(b)','https://www.legis.iowa.gov/docs/code/441.21.pdf','2026-06-14',2026),
  ('IA','state','assessment_appeal','local_board','A dissatisfied owner/taxpayer files a written protest with the local board of review between April 2 and April 30 of the assessment year (extended to May 1-June 5 in declared disaster counties). Allowed grounds are inequitable assessment, over-valuation, non-assessability/exemption/misclassification, error, or fraud/misconduct.','{"deadline_kind":"window","deadline_month":4,"deadline_day":30,"deadline_desc":"File protest with local board of review on or after April 2 to and including April 30 of the assessment year (disaster-county extension to May 1-June 5).","review_body":"Local board of review","locally_variable":false}'::jsonb,'Iowa Code § 441.37(1)(a)','https://www.legis.iowa.gov/docs/code/441.37.pdf','2026-06-14',2026),
  ('IA','state','assessment_appeal','state_appeal_board','After the local board of review, the owner/taxpayer may appeal to the state Property Assessment Appeal Board (or bypass it and appeal to district court). The appeal to the Property Assessment Appeal Board must be filed within 20 days after the board of review adjourns or by May 31, whichever is later.','{"deadline_kind":"relative_to_roll","deadline_desc":"Appeal to the Property Assessment Appeal Board within 20 days after adjournment of the local board of review or by May 31, whichever is later.","review_body":"Property Assessment Appeal Board (state); or bypass to district court under \u00a7 441.38","locally_variable":false}'::jsonb,'Iowa Code § 441.37A(1)(a)-(b)','https://www.legis.iowa.gov/docs/code/441.37A.pdf','2026-06-14',2026),
  ('IA','state','payment',NULL,'Property tax is payable in two installments: at least one-half before September 1 following the levy and the remaining half before March 1 following. An installment unpaid before October 1 becomes delinquent October 1; the second installment unpaid before April 1 becomes delinquent April 1 (next business day if the prior month ends on a weekend).','{"installments":[{"label":"First half","due_month":9,"due_day":1},{"label":"Second half","due_month":3,"due_day":1}],"delinquent_after_desc":"First installment delinquent from October 1; second installment delinquent from April 1 (shifts to second business day when the last day of September/March is a Saturday or Sunday).","locally_variable":false}'::jsonb,'Iowa Code §§ 445.36(2), 445.37(1)(a)','https://www.legis.iowa.gov/docs/code/445.37.pdf','2026-06-14',2026),
  ('IA','state','delinquency_redemption',NULL,'Delinquent property taxes draw interest of 1.5% per month. The county treasurer holds an annual tax sale (tax-sale-certificate / lien system) on the third Monday in June for parcels with delinquent taxes. A sold parcel may be redeemed by paying the sale amount plus interest at 2% per month from the month of sale. The right of redemption expires 90 days after the certificate holder serves a notice of expiration, which may be served only after one year and nine months from the date of sale (nine months for § 446.18 sales).','{"late_interest_pct_per_year":18,"redemption_period_months":21,"tax_sale_kind":"tax_lien","redemption_interest_pct_per_month":2,"redemption_expires_desc":"Right of redemption expires 90 days after completed service of the certificate holder''s notice of expiration; notice may be served only after 1 year 9 months from date of sale (9 months for \u00a7 446.18 public-bidder sales).","locally_variable":false}'::jsonb,'Iowa Code §§ 445.39, 446.7(1), 447.1(1), 447.9(1)','https://www.legis.iowa.gov/docs/code/447.1.pdf','2026-06-14',2026),
  ('IA','state','exemption','homestead','The Homestead Tax Credit reduces tax on owner-occupied homes; the credit equals the actual tax levy on the first $4,850 of the homestead''s actual (taxable) value. The owner must own and occupy the property as a homestead on July 1, declare Iowa residency for income tax, and occupy the property at least six months per year.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":4850,"benefit_unit":"usd","notes":"Credit applies to the actual tax levy on the first $4,850 of actual value; this is a credit (reduces tax), not a value exemption. Owner must own/occupy as homestead on July 1, declare Iowa residency, occupy >=6 months/year.","locally_variable":false}'::jsonb,'Iowa Code § 425.1','https://revenue.iowa.gov/taxes/tax-guidance/tax-credits-deductions-exemption/tax-credits-and-exemptions','2026-06-14',2026),
  ('IA','state','exemption','senior','Homestead owners who are 65 or older on or before January 1 of the assessment year receive an additional homestead exemption that reduces the taxable value of the homestead by $6,500. Once approved it carries forward in successive years without re-filing.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":6500,"benefit_unit":"usd","notes":"Additional $6,500 reduction of taxable value (separate from and on top of the homestead credit). Claimant must be 65+ on or before January 1 of the assessment year. Carries forward without re-filing once approved. (Submitted phase-in subdetail of $3,250 for AY2023 / $6,500 AY2024+ could NOT be confirmed on the cited DOR page; the cited page references the full $6,500 from assessment year 2023 onward without a graduated schedule. Phase-in note retained as unverified secondary detail; core $6,500 / age-65 / carry-forward params are verbatim-confirmed.)","locally_variable":false}'::jsonb,'Iowa Code ch. 425 (2023 Iowa Acts, House File 718)','https://revenue.iowa.gov/homestead-tax-credit-and-exemption','2026-06-14',2026),
  ('ID','state','exemption','homestead','Idaho homestead exemption: the lesser of the first $125,000 of the homestead''s market value for assessment purposes OR 50% of that market value is exempt from property tax. Owner-occupied primary dwelling only; one-time application that carries forward while eligibility is unchanged.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":125000,"benefit_unit":"usd","locally_variable":false,"notes":"Exempt amount is the LESSER of $125,000 or 50% of market value for assessment purposes. No age or income limit. Apply once with county assessor; carries forward while owner continues to occupy. Owner must certify primary dwelling and no other homestead claim."}'::jsonb,'Idaho Code 63-602G','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH6/SECT63-602G/','2026-06-14',2026),
  ('ID','state','exemption','circuit_breaker','Idaho Property Tax Reduction (circuit breaker) for qualifying claimants: maximum reduction of $1,500 (sliding to as low as $250 at higher income tiers), available to claimants 65+, widows/widowers, the blind, the disabled, disabled veterans (10%+ service-connected), former POWs/hostages, and fatherless/motherless children under 18 who own and occupy the homestead. Household income must not exceed $37,000 for tax year 2023 and thereafter.','{"age_min":65,"income_max":37000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1500,"benefit_unit":"usd","locally_variable":false,"notes":"Age 65+ is ONE of several qualifying categories (63-701): also widow/widower, blind, disabled (per SSA/RRB), disabled veteran 10%+ service-connected, former POW/hostage, fatherless/motherless child under 18. Maximum reduction $1,500 (tax year 2021+); reduction slides down to $250 at the highest qualifying income tier. Household income cap $37,000 (tax year 2023+), indexed for cost-of-living per 63-705. Claimant must own and occupy the homestead on January 1."}'::jsonb,'Idaho Code 63-701, 63-705','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH7/SECT63-705/','2026-06-14',2026),
  ('ID','state','exemption','disabled_veteran','A disabled veteran with a 100% service-connected disability (or a 100% individual-unemployability rating) qualifies for the property tax reduction without regard to the standard income limit; veterans with a service-connected disability of 10% or more are among the categories eligible for the circuit-breaker reduction (max $1,500).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1500,"benefit_unit":"usd","locally_variable":false,"notes":"Two veteran tracks: (1) disabled veteran with 10%+ service-connected disability qualifies as a claimant category for the circuit-breaker reduction under 63-701, subject to the $37,000 income cap; (2) a veteran with 100% service-connected disability (or individual-unemployability rating compensated at the 100% rate) receives the reduction under 63-705 without the standard income test. Veteran category is paragraph (e) of the 63-701 claimant definition. Verify current-year mechanics with the Idaho State Tax Commission."}'::jsonb,'Idaho Code 63-701, 63-705','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH7/SECT63-705/','2026-06-14',2026),
  ('ID','state','assessment_appeal',NULL,'Appeal an assessment to the county Board of Equalization in writing by the fourth Monday of June (property roll). A further appeal from the Board of Equalization goes to the Idaho Board of Tax Appeals (or district court) within 30 days of the BOE decision.','{"deadline_kind":"fixed_date","deadline_month":6,"deadline_day":null,"deadline_desc":"On or before the close of the county''s normal business hours on the fourth Monday of June for an assessment on the property roll (fourth Monday of November for the subsequent property roll; day of the January meeting for the missed property roll). Appeal from the Board of Equalization to the Board of Tax Appeals or district court within 30 days of the BOE decision.","review_body":"County Board of Equalization (first level); Idaho Board of Tax Appeals or district court (second level)","locally_variable":false}'::jsonb,'Idaho Code 63-501A, 63-511','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH5/SECT63-501A/','2026-06-14',2026),
  ('ID','state','payment',NULL,'Property taxes are due in full by December 20 of the levy year, or may be paid in two halves: first half by December 20, second half by June 20 of the following year (grace period for the second half only if the first half is fully paid). Late charges and 1% per month interest apply to unpaid amounts after the due dates.','{"installments":[{"label":"First half (or full payment)","due_month":12,"due_day":20},{"label":"Second half","due_month":6,"due_day":20}],"delinquent_after_desc":"Late charges and interest assessed on the first half if not totally paid by December 20; on the second half if not totally paid by June 20. Interest accrues at 1% per month from January 1 following the year the lien attached.","grace_days":null,"locally_variable":false}'::jsonb,'Idaho Code 63-903','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH9/SECT63-903/','2026-06-14',2026),
  ('ID','state','delinquency_redemption',NULL,'Idaho is a tax-deed state: after delinquency the county takes the property in trust and can issue a tax deed; the record owner may redeem until 14 months after the tax deed is issued to the county (paying delinquency, late charges, accrued interest, and costs). Delinquency interest accrues at 1% per month from January 1 following the lien year.','{"late_penalty_pct":null,"late_interest_pct_per_year":12,"redemption_period_months":14,"tax_sale_kind":"tax_deed","locally_variable":false}'::jsonb,'Idaho Code 63-1001, 63-1007','https://legislature.idaho.gov/statutesrules/idstat/Title63/T63CH10/SECT63-1007/','2026-06-14',2026),
  ('IL','state','assessment',NULL,'Illinois assesses most property at 33 1/3% of fair cash value (market value). Counties over 200,000 inhabitants may classify property (Cook County uses a classification ordinance with different levels by property class), so the ratio is locally variable in those counties.','{"assessment_ratio_pct":33.33,"market_value_standard":"fair_cash_value","locally_variable":true}'::jsonb,'35 ILCS 200/9-145','https://www.ilga.gov/Legislation/ILCS/details?ActID=596&ChapterID=8&ChapAct=FullText','2026-06-14',2026),
  ('IL','state','assessment_appeal',NULL,'A taxpayer challenging an assessment files a written complaint with the county Board of Review on or before 30 calendar days after publication of the assessment list for that township. A taxpayer dissatisfied with the Board of Review''s decision may then appeal to the Illinois Property Tax Appeal Board (PTAB) within 30 days of the written decision.','{"deadline_kind":"relative_to_roll","deadline_desc":"Board of Review complaint due within 30 calendar days after publication of the assessment list (Sec. 16-55(d)); PTAB appeal due within 30 days after the Board of Review''s written decision (Sec. 16-160).","review_body":"County Board of Review (first level); Illinois Property Tax Appeal Board (PTAB) on further appeal","locally_variable":true}'::jsonb,'35 ILCS 200/16-55(d); 35 ILCS 200/16-160','https://www.ilga.gov/legislation/ILCS/details?ActID=596&ChapterID=8&SeqStart=44000000&SeqEnd=49100000&Print=True','2026-06-14',2026),
  ('IL','state','exemption','homestead','General Homestead Exemption: a reduction in equalized assessed value (EAV) for an owner-occupied primary residence, equal to the EAV increase above the property''s 1977 base, capped per year. For taxable year 2023 and after the cap is $10,000 in counties of 3,000,000+ inhabitants, $8,000 in contiguous counties, and $6,000 in all other counties.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":6000,"benefit_unit":"usd","locally_variable":true,"notes":"Benefit is a cap on the EAV reduction. TY2023+: $10,000 (counties 3,000,000+), $8,000 (contiguous counties), $6,000 (all other counties). benefit_value reflects the all-other-counties cap; higher in Cook and collar counties."}'::jsonb,'35 ILCS 200/15-175','https://www.ilga.gov/Legislation/ILCS/details?ActID=596&ChapterID=8&ChapAct=FullText','2026-06-14',2026),
  ('IL','state','exemption','senior','Senior Citizens Homestead Exemption: owner-occupant aged 65 or older who is liable for the property taxes gets an annual EAV reduction. For taxable year 2023 and after the maximum reduction is $8,000 in counties of 3,000,000+ inhabitants and contiguous counties, and $5,000 in all other counties.','{"age_min":65,"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":5000,"benefit_unit":"usd","locally_variable":true,"notes":"TY2023+: $8,000 (counties 3,000,000+ and contiguous counties), $5,000 (all other counties). benefit_value reflects the all-other-counties amount."}'::jsonb,'35 ILCS 200/15-170','https://www.ilga.gov/Legislation/ILCS/details?ActID=596&ChapterID=8&ChapAct=FullText','2026-06-14',2026),
  ('IL','state','exemption','circuit_breaker','Low-Income Senior Citizens Assessment Freeze Homestead Exemption (''senior freeze''): owner-occupant aged 65+ whose total household income does not exceed the statutory maximum gets the EAV of the residence frozen at a base-year amount. Maximum household income is $65,000 for taxable years 2018-2025, rising to $75,000 for taxable year 2026.','{"age_min":65,"income_max":65000,"income_unit":"usd_per_year","primary_residence_required":true,"ownership_required":true,"benefit_kind":"assessment_freeze","locally_variable":false,"notes":"Income test is on total household income. Max income per statute: $65,000 (TY2018-2025); $75,000 (TY2026); $77,000 (TY2027); $79,000 (TY2028 and thereafter). income_max=65000 reflects the current TY2018-2025 limit. (Note: amounts are fixed statutory step figures, not formula-indexed.)"}'::jsonb,'35 ILCS 200/15-172','https://www.ilga.gov/Legislation/ILCS/details?ActID=596&ChapterID=8&ChapAct=FullText','2026-06-14',2026),
  ('IL','state','exemption','disability','Homestead Exemption for Persons with Disabilities: an owner-occupant who is a person with a disability and is liable for the property taxes receives a $2,000 annual reduction in EAV.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":2000,"benefit_unit":"usd","locally_variable":false,"notes":"Flat $2,000 EAV reduction beginning taxable year 2007. Requires the property be the primary residence of the person with a disability who is liable for the taxes."}'::jsonb,'35 ILCS 200/15-168','https://www.ilga.gov/Legislation/ILCS/details?ActID=596&ChapterID=8&ChapAct=FullText','2026-06-14',2026),
  ('IL','state','payment',NULL,'Property tax is paid in two installments in most (non-accelerated) counties: the first installment becomes delinquent and bears interest after the later of June 1 or the bill''s stated first-installment due date; the second after the later of September 1 or its stated due date. Cook County (3,000,000+) uses accelerated billing with different dates. Actual bill due dates are set locally.','{"installments":[{"label":"First installment","due_month":6,"due_day":1},{"label":"Second installment","due_month":9,"due_day":1}],"delinquent_after_desc":"First installment delinquent after the later of June 1 or the stated first-installment due date; second installment after the later of September 1 or its stated due date (non-accelerated counties). Cook County accelerated: first installment after March 1, second after August 1.","locally_variable":true}'::jsonb,'35 ILCS 200/21-15; 35 ILCS 200/21-25','https://www.ilga.gov/legislation/ILCS/details?ActID=596&ChapterID=8&SeqStart=70000000&SeqEnd=76000000&Print=True','2026-06-14',2026),
  ('IL','state','delinquency_redemption',NULL,'Illinois is a tax-lien (certificate) state: delinquent taxes are sold at the annual tax sale. The general redemption period is 2.5 years from the date of sale (1 year for vacant non-farm, commercial, industrial, or 7+ residential-unit property). Redemption requires paying the certificate amount plus an accrued penalty equal to the penalty bid at sale, which increases by the penalty-bid amount every 6 months (certificate amount times the penalty bid for the first 6 months, times 2 for months 6-12, times 3 for months 12-18, etc.). Delinquent-tax interest before sale is 1.5%/month (0.75%/month for tax year 2023+ in counties of 3,000,000+).','{"redemption_period_months":30,"tax_sale_kind":"tax_lien","late_interest_pct_per_year":18,"locally_variable":false,"notes":"Redemption period: 30 months (2.5 years) general; 12 months for vacant non-farm, commercial, industrial, or 7+ residential-unit property (35 ILCS 200/21-350); extendable by certificate holder. Pre-sale delinquency interest: 1.5%/month = 18%/yr (0.75%/month for TY2023+ in counties of 3,000,000+, per 35 ILCS 200/21-15). Post-sale penalty is the auction ''penalty bid'' (variable, set at sale): certificate amount times the penalty bid if redeemed within 6 months, times 2 within 12 months, times 3 within 18 months, etc. \u2014 increments by one penalty-bid multiple each 6-month period (NOT a geometric doubling), not a fixed statutory percentage."}'::jsonb,'35 ILCS 200/21-350; 35 ILCS 200/21-355; 35 ILCS 200/21-15','https://www.ilga.gov/legislation/ILCS/details?ActID=596&ChapterID=8&SeqStart=70000000&SeqEnd=76000000&Print=True','2026-06-14',2026),
  ('IN','state','assessment_appeal',NULL,'A real-property assessment appeal must be filed by June 15 of the assessment year (if the assessment notice was mailed before May 1; otherwise June 15 of the year the tax statement is mailed). The appeal is filed with the township/county assessor and heard first by the county property tax assessment board of appeals; a county-board determination may then be appealed to the Indiana Board of Tax Review within 45 days.','{"deadline_kind":"fixed_date","deadline_month":6,"deadline_day":15,"deadline_desc":"For real property assessed after 12/31/2018: by June 15 of the assessment year if the notice of assessment was mailed before May 1, else June 15 of the year the tax statement is mailed. Non-value claims (wrong person, denied deduction/exemption, clerical error) may be raised up to 3 years after taxes were first due. Indiana Board of Tax Review petition is due within 45 days of the county board''s determination notice.","review_body":"County property tax assessment board of appeals (county board), then Indiana Board of Tax Review","locally_variable":false}'::jsonb,'Ind. Code 6-1.1-15-1.1(b); Ind. Code 6-1.1-15-3(d)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-15-1.1','2026-06-14',2026),
  ('IN','state','exemption','homestead','The standard homestead deduction reduces the assessed value of an owner-occupied principal residence (including up to one acre) by the lesser of 60% of the homestead''s assessed value or $48,000 (for assessment dates after December 31, 2022).','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"fixed_amount","benefit_value":48000,"benefit_unit":"usd","locally_variable":false,"notes":"Deduction is the LESSER of 60% of the homestead''s assessed value or $48,000 (for assessment dates after 12/31/2022; $45,000 before 1/1/2023). Applies to a homestead the individual owns or buys under a recorded contract; limited to a single dwelling plus up to one acre."}'::jsonb,'Ind. Code 6-1.1-12-37(c)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-12-37','2026-06-14',2026),
  ('IN','state','exemption','senior','An owner at least 65 years old may deduct the lesser of one-half of the assessed value of the real property or $14,000, provided income and assessed-value limits are met (income not exceeding $30,000 single / $40,000 joint or shared-ownership, cost-of-living adjusted from the 1/1/2023 assessment date; property assessed value not exceeding $240,000).','{"age_min":65,"income_max":40000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":14000,"benefit_unit":"usd","locally_variable":false,"notes":"Real-property deduction equals the lesser of one-half (1/2) of assessed value or $14,000. Eligibility caps: adjusted gross income not exceeding $30,000 (single) / $40,000 (joint or shared-ownership), cost-of-living adjusted annually beginning the 1/1/2023 assessment date; property assessed value not exceeding $240,000. Surviving spouse may qualify."}'::jsonb,'Ind. Code 6-1.1-12-9(b)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-12-9','2026-06-14',2026),
  ('IN','state','exemption','disabled_veteran','A veteran who served at least 90 days with an honorable discharge and is totally disabled (or at least age 62 with at least a 10% disability) may deduct $14,000 from the assessed value of an owned/contract-bought residence, subject to a statewide assessed-value limit.','{"age_min":62,"ownership_required":true,"benefit_kind":"fixed_amount","benefit_value":14000,"benefit_unit":"usd","locally_variable":false,"notes":"$14,000 deduction. Requires 90+ days military service, honorable discharge, and either total disability OR age 62+ with disability of at least 10%. Subject to an assessed-value ceiling that rose over time ($175,000 for 2017-2019 assessment dates, $200,000 for 2020-2023). Surviving spouse may qualify. This is the IC 6-1.1-12-14 deduction; a separate IC 6-1.1-12-13 deduction ($24,960) exists for partial wartime/service-connected disability."}'::jsonb,'Ind. Code 6-1.1-12-14(a)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-12-14','2026-06-14',2026),
  ('IN','state','exemption','disability','A blind individual or an individual with a disability who occupies the property as their residence may deduct $12,480 from assessed value, provided taxable gross income for the preceding calendar year did not exceed $17,000.','{"income_max":17000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":12480,"benefit_unit":"usd","locally_variable":false,"notes":"$12,480 deduction for a blind person or person with a disability. Income test: taxable gross income for the preceding calendar year not exceeding $17,000. Property must be principally used and occupied as the individual''s residence. Proof of disability via Social Security disability eligibility or physician examination."}'::jsonb,'Ind. Code 6-1.1-12-11(a)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-12-11','2026-06-14',2026),
  ('IN','state','payment',NULL,'Property taxes assessed for a year are due in two equal installments on May 10 and November 10 of the following year. Counties may allow alternative or monthly schedules, and a small-bill ordinance may make tax under $25 due in one installment on May 10.','{"installments":[{"label":"First installment (spring)","due_month":5,"due_day":10},{"label":"Second installment (fall)","due_month":11,"due_day":10}],"delinquent_after_desc":"Each installment becomes delinquent if not paid by its due date; a penalty attaches in the year of initial delinquency (a 30-day cure window can limit the penalty to 5% if no prior delinquency on the parcel).","locally_variable":false,"notes":"Statewide framework: May 10 and November 10. County council may require one installment for liabilities under $25 (due May 10), and counties may adopt alternative or monthly/partial-payment schedules under IC 6-1.1-22-9.5/9.7."}'::jsonb,'Ind. Code 6-1.1-22-9(a)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-22-9','2026-06-14',2026),
  ('IN','state','delinquency_redemption',NULL,'After a tax sale, the owner generally has one year from the date of sale to redeem. Redemption requires 110% of the minimum bid if redeemed within 6 months (115% if redeemed after 6 months up to one year), plus 5% per annum on any surplus over the minimum bid and on subsequently-paid taxes, plus costs. Indiana is a tax-lien/certificate state: the buyer receives a certificate of sale and a tax deed issues only after the redemption period expires.','{"late_penalty_pct":10,"late_interest_pct_per_year":5,"redemption_period_months":12,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"Redemption period: 1 year after the date of sale (120 days for certain agency/county-executive-lien situations; no redemption for property on the vacant/abandoned list). Redemption amount: 110% of the minimum bid if redeemed within 6 months, 115% if redeemed after 6 months but within 1 year, plus 5% per annum on the amount of the purchase price exceeding the minimum bid and on subsequently-paid taxes (sales after 6/30/2014), plus costs. Pre-sale delinquency penalty (IC 6-1.1-37-10): 5% of delinquent tax if cured within 30 days and no prior delinquency on the parcel, otherwise 10%. The ''late_penalty_pct'' reflects the 10% delinquency penalty; the ''late_interest_pct_per_year'' (5%) reflects post-sale redemption interest, not a simple flat annual rate."}'::jsonb,'Ind. Code 6-1.1-25-4(a); Ind. Code 6-1.1-25-2(b)-(c); Ind. Code 6-1.1-37-10(a)','https://iga.in.gov/laws/2024/ic/titles/6#6-1.1-25-4','2026-06-14',2026),
  ('KS','state','assessment',NULL,'Real property is appraised at fair market value and assessed at a subclass percentage: residential (incl. multi-family, mobile/manufactured home land, bed-and-breakfast) at 11.5%, vacant lots 12%, commercial/industrial 25%, agricultural-use land 30%, all other rural/urban real property 30%, public utility 33%.','{"assessment_ratio_pct":11.5,"market_value_standard":"fair market value in money (K.S.A. 79-503a); agricultural-use land valued on use-value per K.S.A. 79-1476","locally_variable":false}'::jsonb,'K.S.A. 79-1439; K.S.A. 79-501','https://www.ksrevisor.gov/statutes/chapters/ch79/079_014_0039.html','2026-06-14',2026),
  ('KS','state','assessment_appeal',NULL,'A taxpayer may appeal the classification or appraisal of real property by giving notice to the county appraiser within 30 days after the date the valuation notice was mailed (for personal property, on or before May 15). An informal meeting with the county appraiser is a condition precedent. From the appraiser''s final determination, the taxpayer may appeal to a county/district hearing officer or panel, or (for residential property or value under $3,000,000) to the Small Claims and Expedited Hearings Division of the State Board of Tax Appeals; further appeal lies to the State Board of Tax Appeals.','{"deadline_kind":"relative_to_roll","deadline_desc":"Within 30 days after the date the K.S.A. 79-1460 valuation notice was mailed (real property); on or before May 15 for personal property","review_body":"County appraiser informal meeting (condition precedent), then county/district hearing officer or panel, then State Board of Tax Appeals (Small Claims and Expedited Hearings Division available for residential or value < $3,000,000)","locally_variable":false}'::jsonb,'K.S.A. 79-1448','https://www.ksrevisor.gov/statutes/chapters/ch79/079_014_0048.html','2026-06-14',2026),
  ('KS','state','exemption','homestead','For taxable year 2024 and thereafter, residential-use property is exempt from the statewide school-finance property tax levy on the first $75,000 of its appraised valuation. This is the statewide residential exemption applied against the state school mill levy (not a means-tested or age-based exemption).','{"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":75000,"benefit_unit":"usd","locally_variable":false,"notes":"Exemption applies only against the statewide school levy under K.S.A. 72-5142, not against county/city/other levies. $75,000 appraised-value cap effective for tax year 2024 onward. Prior-year cap ($40,000) noted in summary is not contained in the live statute text and is non-load-bearing context."}'::jsonb,'K.S.A. 79-201x','https://www.ksrevisor.gov/statutes/chapters/ch79/079_002_0001x.html','2026-06-14',2026),
  ('KS','state','payment',NULL,'Real property taxes are due November 1 and a lien attaches on that date (K.S.A. 79-1804). A taxpayer may pay the full amount on or before December 20, or pay the first half by December 20 and the second half by May 10 of the following year. If the tax statement total is $10 or less, the entire amount is due by December 20. Unpaid first-half taxes accrue interest from December 20; remaining taxes unpaid on May 11 accrue interest from May 10. Due dates falling on Saturday/Sunday extend to the next county-treasurer business day.','{"installments":[{"label":"First half (or full payment)","due_month":12,"due_day":20},{"label":"Second half","due_month":5,"due_day":10}],"delinquent_after_desc":"First half delinquent after December 20; full balance delinquent (interest from May 10) on May 11. Due dates falling on Saturday/Sunday extend to next county-treasurer business day.","locally_variable":false}'::jsonb,'K.S.A. 79-2004; K.S.A. 79-1804','https://www.ksrevisor.gov/statutes/chapters/ch79/079_020_0004.html','2026-06-14',2026),
  ('KS','state','delinquency_redemption',NULL,'After real estate is bid off by the county for delinquent taxes, the owner (or mortgagee/heirs/assigns) may redeem. Homestead and most residential real estate has a 3-year redemption period; non-homestead real estate sold for both delinquent taxes and special assessments has a 2-year period; abandoned buildings/land a 1-year period. Redemption requires paying the sale amount plus accrued interest, all delinquent taxes/assessments and interest, and sale/redemption costs. Delinquent-tax interest accrues at the K.S.A. 79-2968 rate plus 5 percentage points per year. After the redemption period expires unredeemed, the property is disposed of by judicial tax foreclosure and sale (K.S.A. 79-2801 et seq.).','{"late_interest_pct_per_year":null,"redemption_period_months":36,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Redemption periods vary by property type: homestead/most residential 3 years (36 months); non-homestead real estate sold for delinquent taxes + special assessments 2 years (24 months); abandoned buildings/land 1 year (12 months). Delinquent-tax interest rate = K.S.A. 79-2968 underpayment rate + 5 percentage points/year (K.S.A. 79-2004); the statutory rate is set annually and not a fixed figure. Disposition after redemption is judicial foreclosure and sale (deed), not a transferable lien certificate."}'::jsonb,'K.S.A. 79-2401a; K.S.A. 79-2004; K.S.A. 79-2801 et seq.','https://www.ksrevisor.gov/statutes/chapters/ch79/079_024_0001a.html','2026-06-14',2026),
  ('KY','state','exemption','homestead','Kentucky''s constitutional homestead exemption is available to owner-occupants who are age 65 or older (or totally disabled) and own and maintain the property as their personal residence. The exemption amount is set in 1972 purchasing-power dollars (Constitution Sec. 170, originally $6,500) and adjusted by the Department of Revenue every two years for cost-of-living. The Department set the value at $49,100 for the 2025-2026 assessment years; that dollar amount is deducted from the assessed value before tax is computed. Eligibility is keyed to ownership/occupancy on the January 1 assessment date. (The senior age-65 track and the totally-disabled track share the same statute and the same dollar exemption.)','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":49100,"benefit_unit":"usd","locally_variable":false,"notes":"Single statewide exemption; covers both age-65+ and totally-disabled owner-occupants (only one exemption per residential unit even if owner is both 65+ and disabled). $49,100 is the 2025-2026 biennium value set by the Kentucky Department of Revenue under KRS 132.810; the statutory base is the Constitution Sec. 170 $6,500 figure expressed in 1972 dollars and adjusted every 2 years per U.S. Dept. of Labor cost-of-living index. Applies to state, county, city, and special-district taxes. Statute text (132.810) supports every element EXCEPT the $49,100 figure, which is verified independently from the official Ky. DOR 2025-2026 determination (revenue.ky.gov)."}'::jsonb,'Ky. Const. Sec. 170; KRS 132.810; Ky. Dept. of Revenue 2025-2026 homestead exemption determination','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=39641','2026-06-14',2026),
  ('KY','state','exemption','senior','Owners age 65 or older who own and occupy the property as their personal residence on the January 1 assessment date qualify for Kentucky''s homestead exemption ($49,100 deducted from assessed value for 2025-2026). This is the same exemption as the homestead/disability exemption under KRS 132.810; Kentucky does not have a separate senior exemption with an income test.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":49100,"benefit_unit":"usd","locally_variable":false,"notes":"No income limit. Same statute and same dollar exemption as the general homestead exemption; the age-65 path does not require annual reapplication. $49,100 is the 2025-2026 biennium value; figure is reset by DOR every 2 years. No income test exists in KRS 132.810 (statute imposes none), confirming the ''no separate senior exemption with income test'' claim."}'::jsonb,'KRS 132.810(2)(a)','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=39641','2026-06-14',2026),
  ('KY','state','exemption','disability','Owners who are totally disabled under a program authorized or administered by a U.S. government agency or any retirement system (in or outside Kentucky), and who own and occupy the property as their personal residence on January 1, qualify for the same homestead exemption ($49,100 for 2025-2026). A disabled owner under age 65 must reapply annually, except service-connected totally disabled veterans and persons found permanently disabled under Social Security Administration / Kentucky Retirement Systems rules, who document once.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":49100,"benefit_unit":"usd","locally_variable":false,"notes":"Totally-disabled track of the same KRS 132.810 homestead exemption. Disability must be classified under a U.S. government agency program or a retirement system. Under-65 disabled owners reapply annually unless they are a service-connected totally disabled veteran or permanently disabled under SSA / Kentucky Retirement Systems rules. $49,100 is the 2025-2026 biennium value, reset by DOR every 2 years (value verified independently via official Ky. DOR; statute supplies all other elements)."}'::jsonb,'KRS 132.810(2)(a),(c),(d)','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=39641','2026-06-14',2026),
  ('KY','state','assessment_appeal',NULL,'To appeal a real-property assessment in Kentucky, the taxpayer must first request a conference with the Property Valuation Administrator (PVA) held during the open-inspection period (the tax roll is open for inspection beginning the first Monday in May for 13 days). A taxpayer still aggrieved appeals to the county board of assessment appeals by filing a written petition with the county clerk no later than one workday following the conclusion of the inspection period (a PVA-requested, DOR-approved extension of up to 25 days is possible). The board cannot consider an untimely appeal.','{"deadline_kind":"relative_to_roll","deadline_month":5,"deadline_desc":"No later than one (1) workday following the conclusion of the tax-roll open-inspection period; the inspection period begins the first Monday in May and runs 13 days (so the appeal deadline falls in mid-to-late May), unless extended up to 25 days by the Department of Revenue on PVA request.","review_body":"County board of assessment appeals (petition filed with the county clerk; PVA conference required first; further appeal to the Kentucky Board of Tax Appeals under KRS 49.220)","locally_variable":true}'::jsonb,'KRS 133.120; KRS 133.045 (inspection period)','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=51502','2026-06-14',2026),
  ('KY','state','payment',NULL,'Kentucky property taxes are due and payable on or before December 31 of the assessment year, collected by the county sheriff. There is a single annual bill (no installments) with a tiered discount/penalty schedule: a 2% discount if paid in full by November 1; face value if paid November 2 through December 31; a 5% penalty if paid January 1-31 of the following year; and a 10% penalty if paid after January 31. (Taxes unpaid become delinquent and are transferred to the county clerk as certificates of delinquency around April.) The state sets this framework; an alternative collection schedule (taxes due two full months after bills are mailed) applies if the regular schedule is delayed.','{"installments":[{"label":"2% discount period (pay in full)","due_month":11,"due_day":1},{"label":"Face value period (no discount/penalty)","due_month":12,"due_day":31}],"delinquent_after_desc":"Due Dec 31 of assessment year. 5% penalty for payment Jan 1-31 of following year; 10% penalty after Jan 31. Unpaid bills become certificates of delinquency held by the county clerk thereafter.","grace_days":0,"locally_variable":false}'::jsonb,'KRS 134.015','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=28365','2026-06-14',2026),
  ('KY','state','delinquency_redemption',NULL,'Kentucky uses a tax-lien (certificate of delinquency) model rather than an immediate tax-deed sale. A delinquent tax becomes a certificate of delinquency that bears simple interest at 12% per annum (KRS 134.125); certificates may be purchased by third parties. No action to collect on (foreclose) a certificate of delinquency may be brought until one year has passed from the date the taxes became delinquent, and any such action must be brought within eleven years (KRS 134.546). The owner can pay/redeem at any time during that period; if the lien is ultimately foreclosed and the property sold, KRS 426.530 provides a further statutory right of redemption.','{"late_interest_pct_per_year":12,"redemption_period_months":12,"tax_sale_kind":"tax_lien","locally_variable":false}'::jsonb,'KRS 134.125; KRS 134.546; KRS 426.530','https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=28449','2026-06-14',2026),
  ('LA','state','assessment_appeal',NULL,'A Louisiana taxpayer who disputes an assessment must first file a complaint with the parish Board of Review during the open-rolls inspection period, then may appeal the Board of Review''s action to the Louisiana Tax Commission, and from there institute suit in district court within 30 days of the Tax Commission''s final decision. The first-level deadline is tied to the assessment-list inspection window: 15 days falling between Aug 15 and Sep 15 (most parishes), or 32 days between Jul 15 and Aug 15 in Orleans Parish.','{"deadline_kind":"window","deadline_month":9,"deadline_day":15,"deadline_desc":"Complaint to parish Board of Review must be filed during the open-rolls inspection period: 15 days beginning no earlier than Aug 15 and ending no later than Sep 15 (non-Orleans parishes); Orleans Parish window is 32 days, Jul 15-Aug 15. Board of Review action may then be appealed to the Louisiana Tax Commission; the Tax Commission''s final decision may be challenged by suit in district court within 30 days.","review_body":"Parish Board of Review (first level), then Louisiana Tax Commission (administrative appeal), then district court (judicial review)","locally_variable":true}'::jsonb,'La. R.S. 47:1992(F); La. R.S. 47:1989; La. R.S. 47:1998(A)(1)(a)','https://www.legis.la.gov/legis/Law.aspx?d=101450','2026-06-14',2026),
  ('LA','state','exemption','homestead','Louisiana grants a homestead exemption on a bona fide homestead (owner-occupied primary residence) equal to $7,500 of assessed valuation. The owner must own and occupy the homestead on or before December 31 of the year the exemption is claimed.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":7500,"benefit_unit":"usd","locally_variable":false,"notes":"Benefit is $7,500 of ASSESSED valuation (Louisiana assesses residential property at 10% of fair market value per La. Const. Art. VII Sec. 18, so this corresponds to roughly $75,000 of market value). Owner must own and occupy on or before Dec 31 of the claim year. Statute exempts the homestead from state, parish, and special ad valorem taxes (verbatim text in 47:1703(A)(1) reads ''state, parish, and special ad valorem taxes''); the prior fact''s parenthetical about municipal taxes is not in the quoted statute text and was dropped."}'::jsonb,'La. R.S. 47:1703(A)(1), (A)(2)','https://www.legis.la.gov/legis/Law.aspx?d=101333','2026-06-14',2026),
  ('LA','state','exemption','agricultural','Louisiana exempts from ad valorem taxation agricultural machinery and other implements used exclusively for agricultural purposes - those immediately and directly employed in cultivation, production, and harvest of crops or in the raising and management of livestock on agricultural lands, plus listed equipment categories.','{"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Full exemption of qualifying agricultural machinery/implements/farm structures (excluding a building used as a principal residence) and timber-logging equipment. Implements the exemption authorized by La. Const. Art. VII Sec. 21. This is an equipment/personal-property exemption, not a land-value reduction. Statute exempts qualifying property ''from ad valorem taxation'' (a full exemption); characterizing it as a 100% reduction is descriptive, the statute does not use a percentage figure."}'::jsonb,'La. R.S. 47:1707','https://www.legis.la.gov/legis/Law.aspx?d=101338','2026-06-14',2026),
  ('LA','state','payment',NULL,'Louisiana property (ad valorem) taxes may be paid once the tax roll is delivered to the parish tax collector and, except as otherwise provided by law, must be paid no later than December 31 of the tax year. Unpaid taxes become delinquent the following day (January 1) and bear interest at 1% per month (non-compounding) from the day after due. Orleans Parish is the statutory exception, with a January/May two-installment option and a February 1 delinquency for the full balance if not paid.','{"installments":[{"label":"Full payment (statewide default)","due_month":12,"due_day":31},{"label":"Orleans Parish 1st installment (optional)","due_month":1,"due_day":31},{"label":"Orleans Parish 2nd installment (optional)","due_month":5,"due_day":31}],"delinquent_after_desc":"Statewide: delinquent the day after December 31 (i.e., January 1). Orleans Parish: full balance delinquent February 1 if January payment/installment not made; elected second installment delinquent the last day of May. Note: statewide delinquent interest is 1%/month non-compounding (47:2127(B)(1)(a)); Orleans Parish delinquency penalty is 10% per annum (47:1997(A)).","locally_variable":true}'::jsonb,'La. R.S. 47:2127(A) (statewide); La. R.S. 47:1997(A) (Orleans Parish installments)','https://www.legis.la.gov/legis/Law.aspx?d=631514','2026-06-14',2026),
  ('MA','state','assessment_appeal',NULL,'Step 1: a property owner contests an assessment by filing an application for abatement with the local board of assessors, due on or before the last day for payment without interest of the first installment of the actual tax bill (G.L. c. 59 sec 59). Step 2: a taxpayer dissatisfied with the assessors'' decision (or with the application being deemed denied after the assessors fail to act within 3 months) appeals to the Appellate Tax Board (or county commissioners) within 3 months of that decision/deemed denial (G.L. c. 59 sec 64). Deadlines are tied to the locally-set tax-bill due date, so the calendar date varies by municipality.','{"deadline_kind":"relative_to_roll","deadline_desc":"Abatement application to local assessors due on or before the last day for payment without interest of the first installment of the actual tax bill (G.L. c. 59 sec 59). Appeal of the assessors'' decision (or deemed denial) to the Appellate Tax Board within 3 months (G.L. c. 59 sec 64).","review_body":"Local board of assessors (initial abatement application), then Massachusetts Appellate Tax Board (or county commissioners) on appeal","locally_variable":true}'::jsonb,'M.G.L. c. 59, sec 59 and sec 64','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter59/Section64','2026-06-14',2026),
  ('MA','state','payment',NULL,'Massachusetts sets the property-tax payment framework at the state level but the specific schedule is chosen locally. Under the optional quarterly system (G.L. c. 59 sec 57C, used by most municipalities) preliminary tax installments are due Aug 1 and Nov 1 and actual-bill installments are due Feb 1 and May 1, with 14% per-annum interest on any installment unpaid after its due date. Under the older annual/semi-annual system (sec 57), taxes are due/payable July 1, with interest at 14% per annum on amounts unpaid after the statutory dates. Which system applies, and exact dates, vary by city/town.','{"installments":[{"label":"Preliminary 1st installment (quarterly system, c.59 s.57C)","due_month":8,"due_day":1},{"label":"Preliminary 2nd installment (quarterly system, c.59 s.57C)","due_month":11,"due_day":1},{"label":"Actual 1st installment (quarterly system, c.59 s.57C)","due_month":2,"due_day":1},{"label":"Actual 2nd installment (quarterly system, c.59 s.57C)","due_month":5,"due_day":1}],"delinquent_after_desc":"Under quarterly system (sec 57C), each installment is delinquent if unpaid after its due date, with 14% per annum interest from the due date. Under annual system (sec 57), interest at 14% per annum accrues on amounts unpaid after the statutory dates (e.g. after Nov 1, or 30 days after a post-Oct-1 mailing; further interest after May 1).","grace_days":null,"locally_variable":true}'::jsonb,'M.G.L. c. 59, sec 57C (quarterly system) and sec 57 (annual system)','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter59/Section57C','2026-06-14',2026),
  ('MA','state','exemption','senior','Massachusetts grants local property-tax exemptions to elderly homeowners under G.L. c. 59, sec 5. Clause 41/41C: base eligibility age 70 (a city/town may by local acceptance lower the age to 65), with statutory base income and whole-estate limits and a base exemption that abates the greater of a fixed dollar amount (e.g. $500/$1,000) or the tax on a fixed valuation (e.g. $4,000). Communities may, by local acceptance (e.g. Clause 41C/41D options), raise the income and asset limits and increase the exemption amount up to 100%, so the operative figures are set locally on top of the state base.','{"age_min":65,"income_max":13000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1000,"benefit_unit":"usd","locally_variable":true,"notes":"State base age is 70; local acceptance under Clause 41C may lower to 65. Base Clause 41C income limit $13,000 single / $15,000 married; communities may raise to $20,000 single / $30,000 married. Base exemption abates the greater of $500 or the tax on $4,000 of valuation; communities may increase the exemption amount by up to 100% (max $1,000) and adopt COLA increases. Operative figures are municipality-specific."}'::jsonb,'M.G.L. c. 59, sec 5, Clause 41 / 41B / 41C','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter59/Section5','2026-06-14',2026),
  ('MA','state','exemption','veteran','Massachusetts grants a property-tax exemption to qualifying veterans (and certain spouses/surviving spouses) under G.L. c. 59, sec 5, Clause 22. The base Clause 22 exemption abates the greater of a fixed $400 or the tax on $2,000 of assessed valuation; higher-tier clauses (22A-22F) grant larger exemptions for greater service-connected disability. Amounts may be increased by local acceptance, so figures vary by municipality.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":400,"benefit_unit":"usd","locally_variable":true,"notes":"Base Clause 22 amount; Clauses 22A through 22F (all present in the statute) grant larger exemptions scaling with service-connected disability (up to full exemption for certain 100% disabled / paraplegic veterans). Communities may increase exemption amounts by local acceptance."}'::jsonb,'M.G.L. c. 59, sec 5, Clause 22 (and 22A-22F)','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter59/Section5','2026-06-14',2026),
  ('MA','state','exemption','disability','Massachusetts grants a property-tax exemption to legally blind persons under G.L. c. 59, sec 5, Clause 37 / 37A. The base exemption abates the greater of the tax on $5,000 of valuation (Clause 37) or $437.50, and Clause 37A provides a flat $500 abatement of actual taxes due for a blind person. Amounts may be increased by local acceptance.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":500,"benefit_unit":"usd","locally_variable":true,"notes":"Clause 37 abates the greater of tax on $5,000 valuation or $437.50; Clause 37A provides a flat $500 abatement. Requires a certificate of legal blindness from the Mass. Commission for the Blind. Communities may increase the amount by local acceptance."}'::jsonb,'M.G.L. c. 59, sec 5, Clause 37 / 37A','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter59/Section5','2026-06-14',2026),
  ('MA','state','exemption','circuit_breaker','Massachusetts provides a statewide refundable income-tax credit (the Senior Circuit Breaker, G.L. c. 62, sec 6(k)) for residents age 65+ whose primary-residence property tax (plus half of water/sewer) exceeds 10% of total Massachusetts income. Unlike the c. 59 sec 5 local exemptions, this is a uniform statewide benefit administered through the income tax. For tax year 2025 the maximum credit is $2,820, the single-filer income limit is $75,000, and the home''s assessed value must not exceed $1,298,000. Thresholds are adjusted annually for inflation under sec 6(k)(4).','{"age_min":65,"income_max":75000,"income_unit":"usd_per_year","ownership_required":false,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":2820,"benefit_unit":"usd","locally_variable":false,"notes":"Tax year 2025 figures (TIR 25-7). Single income limit $75,000 (higher for head-of-household and married filing jointly). Available to both homeowners and renters. Max assessed home value $1,298,000 as of Jan 1, 2025. Annual COLA adjustment per sec 6(k)(4). Claimed on the MA income-tax return, not the municipal tax bill."}'::jsonb,'M.G.L. c. 62, sec 6(k); TIR 25-7','https://www.mass.gov/info-details/massachusetts-senior-circuit-breaker-tax-credit','2026-06-14',2026),
  ('MA','state','delinquency_redemption',NULL,'When Massachusetts property taxes go unpaid, the municipality places the parcel in tax title (a tax taking/lien recorded under G.L. c. 60). The owner (or any party with an interest) may redeem at any time before the treasurer files a petition to foreclose the right of redemption in the Land Court -- Massachusetts has no fixed statutory redemption window; the right persists until foreclosure. Redemption requires paying the tax-title balance plus interest. Per the Affordable Homes Act (Acts of 2024, c. 150, sec 88), the redemption interest rate is 8% per annum for tax titles entered on or after Nov 1, 2024; tax titles created before that date continue to accrue 16% per annum. Massachusetts is a tax-lien (tax-title) state, not a tax-deed-at-auction state.','{"late_penalty_pct":null,"late_interest_pct_per_year":8,"redemption_period_months":null,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"No fixed redemption period: redemption is allowed any time before a petition to foreclose the right of redemption is filed in Land Court (G.L. c. 60 sec 62 / sec 65). Interest 8% per annum from date of sale/taking under the current (post-amendment) statute; per Mass.gov DLS the Affordable Homes Act (Acts of 2024 c.150 sec 88) reduced the rate from 16% to 8% for tax titles entered on or after Nov 1, 2024, with pre-Nov-1-2024 titles continuing at 16%. Also payable: subsequent/intervening taxes and lawful charges, plus recording costs and examination of title/deed of release fees (max $3).","late_penalty_basis":null}'::jsonb,'M.G.L. c. 60, sec 62 (as amended by Acts of 2024, c. 150, sec 88)','https://malegislature.gov/Laws/GeneralLaws/PartI/TitleIX/Chapter60/Section62','2026-06-14',2026),
  ('MD','state','assessment_appeal',NULL,'A taxpayer may appeal a value or classification in a notice of assessment within 30 days of the date of the notice to the Property Tax Assessment Appeal Board for the county where the property is located. A further appeal of a Department final action lies to the Maryland Tax Court within 30 days.','{"deadline_kind":"relative_to_roll","deadline_desc":"Within 30 days from the date of the notice of assessment (appeal to the Property Tax Assessment Appeal Board); a further appeal to the Maryland Tax Court is also within 30 days of the Department''s final action.","review_body":"Property Tax Assessment Appeal Board (county-level), then Maryland Tax Court","locally_variable":false}'::jsonb,'Md. Code, Tax-Property § 14-509; § 14-512','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=14-509&enactments=false','2026-06-14',2026),
  ('MD','state','payment',NULL,'State property tax is due July 1 of each taxable year and may be paid without interest on or before September 30; it is in arrears (delinquent) after September 30. Local jurisdictions set their own billing and may offer semiannual installments.','{"installments":[{"label":"Annual tax due","due_month":7,"due_day":1}],"delinquent_after_desc":"In arrears after September 30 of the tax year (payable without interest on or before September 30).","grace_days":null,"locally_variable":true}'::jsonb,'Md. Code, Tax-Property § 10-102','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=10-102&enactments=false','2026-06-14',2026),
  ('MD','state','exemption','disabled_veteran','A dwelling house owned by a disabled veteran with a permanent 100% service-connected disability (or a disabled active-duty service member, or a qualifying surviving spouse) is fully exempt from property tax on application.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Requires honorable discharge and a U.S. Department of Veterans Affairs declaration of a permanent 100% service-connected disability. Dwelling house limited to not more than 2 families plus lot/curtilage. Surviving spouse (not remarried) and disabled active-duty service members also qualify under the section."}'::jsonb,'Md. Code, Tax-Property § 7-208','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=7-208&enactments=false','2026-06-14',2026),
  ('MD','state','exemption','homestead','The Homestead Property Tax Credit limits the yearly increase in the taxable assessment of an owner-occupied principal residence. The state homestead credit percentage cap is 110% (a 10% maximum annual increase); counties and municipalities may set a lower percentage for their portion of the tax.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"assessment_freeze","benefit_value":10,"benefit_unit":"pct","locally_variable":true,"notes":"Limits taxable assessment growth to at most 10% per year (homestead credit percentage capped at 110% of prior year''s taxable assessment; the percentage may not be less than 100% or exceed 110% for any taxable year). Property must be the homeowner''s principal residence, actually occupied or expected to be occupied for more than 6 months of a 12-month period. Local jurisdictions may adopt a lower cap percentage (>=100%) for their share of the tax. NOTE: cited statute \u00a7 9-105 was NOT present in the local KB (state_law_section_texts); verified by independent re-fetch of the official mgaleg.maryland.gov statute text and corroborated by Maryland SDAT."}'::jsonb,'Md. Code, Tax-Property § 9-105','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=9-105&enactments=false','2026-06-14',2026),
  ('MD','state','exemption','circuit_breaker','The Homeowners'' Property Tax Credit (circuit breaker) reduces property tax for homeowners whose combined gross income does not exceed $60,000 and combined net worth does not exceed $200,000. The credit is the real property tax that exceeds a sliding-scale percentage of combined household income.','{"income_max":60000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","locally_variable":false,"notes":"Net worth must not exceed $200,000 (excluding the dwelling/homesite and qualified retirement accounts). Credit = total real property tax minus: 0% of first $8,000 combined income, 4% of next $4,000, 6.5% of next $4,000, 9% of combined income over $16,000. NOTE: cited statute \u00a7 9-104 was NOT present in the local KB (state_law_section_texts); verified by independent re-fetch of the official mgaleg.maryland.gov statute text and corroborated by Maryland SDAT program page."}'::jsonb,'Md. Code, Tax-Property § 9-104','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=9-104&enactments=false','2026-06-14',2026),
  ('MD','state','delinquency_redemption',NULL,'Maryland sells tax liens via certificate of sale (tax-lien state). The owner may redeem at any time until the right of redemption is finally foreclosed. The statewide redemption interest rate is 6% per year, though many counties set a higher rate (10%-14% in some). A foreclosure complaint may be filed after 6 months from the sale (9 months for owner-occupied residential property).','{"late_interest_pct_per_year":6,"redemption_period_months":6,"tax_sale_kind":"tax_lien","locally_variable":true,"notes":"Redemption rate is 6%/year statewide default; counties may fix a different rate (e.g., Calvert/Caroline/Dorchester/Garrett 10%, Carroll 14%). For owner-occupied residential property the rate may not exceed 10% (\u00a7 14-820(c)). Foreclosure of right of redemption cannot be filed until 6 months after the sale (9 months for owner-occupied residential property); certificate of sale is void if no foreclosure within 2 years. Redemption available until finally foreclosed."}'::jsonb,'Md. Code, Tax-Property § 14-820; § 14-827; § 14-833','https://mgaleg.maryland.gov/mgawebsite/Laws/StatuteText?article=gtp&section=14-820&enactments=false','2026-06-14',2026),
  ('ME','state','exemption','homestead','Maine homestead exemption: $10,000 of just value base plus a $15,000 additional exemption (for tax years beginning on or after April 1, 2020), for a permanent resident who has owned a homestead in Maine for the preceding 12 months. Administered/applied at the municipal level using the municipality''s certified assessment ratio.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":25000,"benefit_unit":"usd","locally_variable":true,"notes":"Base $10,000 (36 M.R.S. \u00a7683(1)) plus additional $15,000 effective for property tax years beginning on or after April 1, 2020 (36 M.R.S. \u00a7683(1-B)) = $25,000 total just-value exemption. Requires 12 months prior Maine homestead ownership and permanent residency. The local assessed value of the exemption is the exemption multiplied by the municipality''s just-value/assessment ratio (\u00a7683(1): assessor shall multiply the amount of the exemption by the ratio of current just value), so the dollar reduction in assessed value varies by municipality (locally_variable)."}'::jsonb,'36 M.R.S. §683(1), (1-B)','https://legislature.maine.gov/legis/statutes/36/title36sec683.html','2026-06-14',2026),
  ('ME','state','exemption','veteran','Maine veteran exemption: up to $6,000 of just value at the veteran''s place of residence for veterans who served during a federally recognized war period and have reached age 62, or who are receiving a U.S. pension/compensation for total disability (service-connected or nonservice-connected). A higher $7,000 amount applies to WWI-era and earlier war-period veterans.','{"age_min":62,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":6000,"benefit_unit":"usd","locally_variable":false,"notes":"$6,000 of just value at place of residence for war-period veterans who have reached age 62 OR are receiving any form of U.S. pension/compensation for total (service-connected or nonservice-connected) disability (36 M.R.S. \u00a7653(1)(C)). $7,000 amount for WWI-and-earlier war-period veterans (\u00a7653(1)(C-1)). Applies to property held individually, in joint tenancy with spouse, or in a revocable living trust for the veteran''s benefit. Statutory exemption amounts are statewide-fixed in the statute (not landlord/locally set); note however that \u00a7653(1)(K) applies the same local just-value-ratio multiplier as the homestead when computing the LOCAL ASSESSED value of the exemption, so the realized assessed-value reduction can vary by municipal ratio. State reimburses municipalities for the revenue loss (\u00a7661 \u2014 50% of post-1978 exemption revenue loss)."}'::jsonb,'36 M.R.S. §653(1)(C), (C-1)','https://legislature.maine.gov/legis/statutes/36/title36sec653.html','2026-06-14',2026),
  ('ME','state','exemption','disability','Maine legally-blind exemption: up to $4,000 of just value of residential real estate at the place of residence for Maine inhabitants who are legally blind as determined by a licensed Doctor of Medicine, Doctor of Osteopathy, or Doctor of Optometry.','{"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":4000,"benefit_unit":"usd","locally_variable":false,"notes":"Maine''s statutory disability-based property tax exemption is the legally-blind exemption: $4,000 of just value of residential real estate at the place of residence (36 M.R.S. \u00a7654-A(1)). Also extends to property held in a revocable living trust and to qualifying shareholders of a cooperative housing corporation. There is no general statutory non-blind ''disability'' assessment exemption verified here; disabled veterans are covered under the \u00a7653 veteran exemption above."}'::jsonb,'36 M.R.S. §654-A(1)','https://legislature.maine.gov/legis/statutes/36/title36sec654-A.html','2026-06-14',2026),
  ('ME','state','assessment_appeal',NULL,'Maine: a taxpayer first applies to the local assessors for an abatement by written application filed within 185 days from commitment. If abatement is denied, the taxpayer may appeal to the local board of assessment review within 60 days after notice of the decision (nonresidential property with an equalized municipal valuation of $1,000,000 or greater may be appealed to the State Board of Property Tax Review).','{"deadline_kind":"relative_to_roll","deadline_desc":"Abatement application: written application filed within 185 days from commitment of the assessment. Appeal of a denial: within 60 days after notice of the decision.","review_body":"Local assessors (abatement application), then local board of assessment review on appeal (or State Board of Property Tax Review for nonresidential property with an equalized municipal valuation of $1,000,000 or greater)","locally_variable":false}'::jsonb,'36 M.R.S. §841(1); 36 M.R.S. §843','https://legislature.maine.gov/legis/statutes/36/title36sec841.html','2026-06-14',2026),
  ('ME','state','payment',NULL,'Maine: property tax due/payment dates and the delinquency date are set locally by the municipality (by vote). The interest rate on delinquent taxes is capped statewide: the maximum rate is set annually by the Treasurer of State and may not exceed the prime rate (WSJ, first business day of the calendar year), rounded up to the next whole percent, plus 3 percentage points.','{"delinquent_after_desc":"Due/payable date(s) and the date interest begins to accrue (the delinquency date) are fixed by municipal vote (36 M.R.S. \u00a7505(2),(4)); they vary by municipality. Many municipalities use a single annual due date or two installments, but the specific dates are local.","locally_variable":true}'::jsonb,'36 M.R.S. §505(2), (4)','https://legislature.maine.gov/legis/statutes/36/title36sec505.html','2026-06-14',2026),
  ('ME','state','delinquency_redemption',NULL,'Maine uses a tax lien mortgage (automatic statutory foreclosure) system. After a tax lien certificate is filed in the registry of deeds, the taxpayer has 18 months to redeem by paying the tax lien mortgage together with interest and costs; if not paid within 18 months, the tax lien mortgage is deemed foreclosed and the right of redemption expires.','{"redemption_period_months":18,"tax_sale_kind":"other","locally_variable":false,"notes":"Maine does not use a competitive tax-lien or tax-deed sale; it uses an automatic tax lien mortgage that forecloses by operation of law 18 months after the tax lien certificate is filed in the registry of deeds (36 M.R.S. \u00a7943). Redemption requires payment of the tax lien mortgage plus interest and costs. The applicable interest rate is the municipality''s delinquent-tax interest rate set under \u00a7505(4) (statewide cap, locally set within it); \u00a7943 itself does not state a separate rate."}'::jsonb,'36 M.R.S. §943','https://legislature.maine.gov/legis/statutes/36/title36sec943.html','2026-06-14',2026),
  ('MI','state','assessment_appeal',NULL,'A property owner protests an assessment to the local Board of Review, which meets beginning the second Monday in March (a township/city may set an alternative Tuesday/Wednesday start that week). Further appeal of the Board of Review''s decision goes to the Michigan Tax Tribunal; the Board notifies the owner in writing by the first Monday in June of its action and of the right and final date to appeal to the Tax Tribunal.','{"deadline_kind":"fixed_date","deadline_month":3,"deadline_day":null,"deadline_desc":"Board of Review meets the second Monday in March (alternative Tuesday/Wednesday start that week permitted by local ordinance); written notice of decision and Tax Tribunal appeal rights by first Monday in June; further appeal to the Michigan Tax Tribunal","review_body":"local Board of Review (first level); Michigan Tax Tribunal (further appeal)","locally_variable":true}'::jsonb,'MCL 211.30','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-30','2026-06-14',2026),
  ('MI','state','exemption','disabled_veteran','Real property used and owned as a homestead by a disabled veteran (or the unremarried surviving spouse of one) is fully exempt from collection of property taxes. The veteran must be a Michigan resident determined by the U.S. Department of Veterans Affairs to be permanently and totally disabled (entitled to benefits at the 100% rate), receiving specially adapted housing assistance, or rated individually unemployable. Application is filed with the local assessor after January 1 and before December 31; for taxes levied on or after January 1, 2025 the exemption continues without reapplication until rescinded or denied.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Full cancellation of taxes on the homestead. Eligible disabled veteran = MI resident determined by U.S. Dept of Veterans Affairs to be permanently and totally disabled at the 100% rate, OR receiving specially-adapted-housing pecuniary assistance, OR rated individually unemployable. Surviving spouse eligible while unremarried. File after Jan 1 and before Dec 31; for taxes levied on/after Jan 1, 2025, continues without reapplication until rescinded/denied."}'::jsonb,'MCL 211.7b','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-7b','2026-06-14',2026),
  ('MI','state','exemption','homestead','Michigan''s Principal Residence Exemption (PRE): an owner who owns and occupies property as a principal residence is exempt from the tax levied by a local school district for school operating purposes (up to 18 mills under MCL 380.1211). Claimed by filing an affidavit with the local tax collecting unit on or before June 1 for the summer levy or November 1 for the winter levy; the exemption then remains in effect for subsequent years until rescinded. Limited to one exemption (a married couple filing jointly may claim only one).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_unit":"pct","locally_variable":false,"notes":"Exempts the principal residence from the local school operating millage (up to 18 mills per the cross-referenced MCL 380.1211 \u2014 the 18-mill figure is NOT stated in 211.7cc itself; 211.7cc says ''to the extent provided under section 1211''), not all property tax. File affidavit on/before June 1 (summer levy) or Nov 1 (winter levy); remains effective in subsequent years until rescinded. Max one exemption; married couple filing jointly limited to one. No age or income limit."}'::jsonb,'MCL 211.7cc','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-7cc','2026-06-14',2026),
  ('MI','state','exemption','circuit_breaker','Poverty / hardship exemption: the principal residence of an owner-occupant who, by reason of poverty, is unable to contribute toward public charges may be exempted in whole or in part from collection of property taxes. The claimant must meet the federal poverty guidelines (or stricter local guidelines) and file annually with the local Board of Review, with income tax returns for all residents. The Board grants a 100% reduction in taxable value or a partial reduction (75%, 50%, 25%, or another state-approved percentage). Application filed after January 1 but before the last day of the Board of Review.','{"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":true,"notes":"Income test = federal poverty guidelines (HHS) or stricter locally-adopted guidelines; local assessing unit sets the specific income and asset levels. Benefit is a 100% reduction in taxable value, or partial 75%/50%/25% (or other state-tax-commission-approved percentage). Apply annually after Jan 1 but before the day prior to the last day of the Board of Review (statute: ''before the day prior to the last day''). Does not apply to corporation-owned property."}'::jsonb,'MCL 211.7u','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-7u','2026-06-14',2026),
  ('MI','state','payment',NULL,'Property tax due dates in Michigan are set locally. Taxing units levy a summer property tax (a lien attaching and due July 1, with interest added after September 14) and/or a winter property tax, with the exact billing/collection dates set by each local tax collecting unit. Any taxes levied in the preceding year that remain unpaid are returned as delinquent to the county treasurer on March 1.','{"installments":[{"label":"Summer levy (lien attaches / due July 1; interest after Sep 14)","due_month":7,"due_day":1},{"label":"Winter levy (local collection; unpaid taxes returned delinquent Mar 1)","due_month":3,"due_day":1}],"delinquent_after_desc":"Taxes levied in the immediately preceding year that remain unpaid are returned as delinquent on March 1 (next business day if March 1 is a weekend/holiday). Summer-levy interest is added on taxes collected after September 14.","locally_variable":true}'::jsonb,'MCL 211.44a; MCL 211.78a(2)','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-78a','2026-06-14',2026),
  ('MI','state','delinquency_redemption',NULL,'When taxes are returned delinquent on March 1, the county adds a 4% county property tax administration fee plus non-compounded interest of 1% per month (or fraction of a month) from the date the taxes first became delinquent. Property delinquent for 12 months or more is forfeited to the county treasurer on the following March 1 (with a $175 forfeiture fee added). The owner may redeem until the March 31 immediately succeeding entry of the circuit-court foreclosure judgment (21 days after judgment in a contested case); after that, fee-simple title vests absolutely in the foreclosing governmental unit with no further redemption. This is a tax-deed (foreclosure-of-title) system, not a tax-lien-certificate sale.','{"late_penalty_pct":4,"late_interest_pct_per_year":12,"redemption_period_months":13,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"4% county property tax administration fee + 1% per month (non-compounded) interest added at delinquency (MCL 211.78a(3)) = 12%/yr (derived from verbatim ''1% per month''). Forfeiture to county treasurer on March 1 after >=12 months delinquent, plus $175 fee (MCL 211.78g(1), verbatim ''$175.00 fee''). Redemption expires the March 31 immediately succeeding entry of the foreclosure judgment; 21 days after judgment in contested cases (MCL 211.78k(5), verbatim). redemption_period_months=13 is an approximate derivation from the statutory timeline, NOT a verbatim statutory period \u2014 appropriately hedged. Court may extend/withhold for minor heirs, incompetence, no means of support, or substantial financial hardship (78k(4)). Title vests absolutely with no further redemption thereafter (tax-deed system, 78k(5)(b)/(6))."}'::jsonb,'MCL 211.78a(3); MCL 211.78g(1); MCL 211.78k(5)','https://www.legislature.mi.gov/Laws/MCL?objectName=mcl-211-78k','2026-06-14',2026),
  ('MN','state','assessment_appeal',NULL,'First-level review is the Local Board of Appeal and Equalization (town/city), which meets between April 1 and May 31 each year. The next level is the County Board of Appeal and Equalization, which convenes after the second Friday in June (no valid action after June 30). Owners typically appear before the local board first; formal Tax Court petitions under chapter 278 are a separate track.','{"deadline_kind":"window","deadline_desc":"Local Board of Appeal and Equalization meetings held between April 1 and May 31; County Board meets after the second Friday in June and may not act after June 30. Exact local-board meeting date is set by the county assessor and printed on the valuation notice.","review_body":"Local Board of Appeal and Equalization (town/city), then County Board of Appeal and Equalization","locally_variable":true}'::jsonb,'Minn. Stat. § 274.01 (Board of Appeal and Equalization); Minn. Stat. § 274.14 (county board meeting dates)','https://www.revisor.mn.gov/statutes/cite/274.01','2026-06-14',2026),
  ('MN','state','exemption','homestead','Homestead market value exclusion reduces taxable market value before net tax capacity is computed for owner-occupied class 1a/1b and the house+garage+1 acre of class 2a homesteads. For a homestead valued at $95,000 or less the exclusion is 40% of market value; between $95,000 and $517,200 it is $38,000 minus 9% of value over $95,000; at $517,200 or more there is no exclusion.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":38000,"benefit_unit":"usd","locally_variable":false,"notes":"Maximum exclusion is $38,000 at a $95,000 market value, phasing out to $0 at $517,200. Below $95,000 the exclusion equals 40% of market value."}'::jsonb,'Minn. Stat. § 273.13, subd. 35 (Homestead market value exclusion)','https://www.revisor.mn.gov/statutes/cite/273.13','2026-06-14',2026),
  ('MN','state','exemption','disabled_veteran','Homestead market value exclusion for veterans with a service-connected disability of 70% or more (as certified by the U.S. Department of Veterans Affairs) who were honorably discharged. $150,000 of market value is excluded for a 70%+ disability rating; $300,000 is excluded for a total (100%) and permanent disability. Application must be filed with the assessor by December 31 of the first assessment year for which the exclusion is sought.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":300000,"benefit_unit":"usd","locally_variable":false,"notes":"Two tiers: $150,000 excluded for 70%+ service-connected disability; $300,000 excluded for total (100%) and permanent disability. Carries over to a qualifying surviving spouse and, in some cases, a primary family caregiver. Application deadline: December 31 of the first assessment year sought."}'::jsonb,'Minn. Stat. § 273.13, subd. 34 (Homestead of veteran with a disability or family caregiver)','https://www.revisor.mn.gov/statutes/cite/273.13','2026-06-14',2026),
  ('MN','state','payment',NULL,'Where taxes on a parcel exceed $100, the tax is paid in two installments: the first half due before May 16 and the second half before the following October 16. Parcels of $100 or less are paid in full by the first-half due date. Late payment triggers a penalty of 2% on homestead property / 4% on nonhomestead property, escalating monthly. Bills/collection are administered locally by the county treasurer.','{"installments":[{"label":"First half","due_month":5,"due_day":16},{"label":"Second half","due_month":10,"due_day":16}],"delinquent_after_desc":"Penalty (2% homestead / 4% nonhomestead) imposed if an installment is unpaid as of its due date; taxes remaining unpaid become delinquent the following January 1 (interest commences then).","grace_days":0,"locally_variable":true}'::jsonb,'Minn. Stat. § 279.01, subd. 1 (Due dates; penalties)','https://www.revisor.mn.gov/statutes/cite/279.01','2026-06-14',2026),
  ('MN','state','delinquency_redemption',NULL,'Minnesota uses a state tax-judgment / forfeiture model: delinquent parcels are sold to the State of Minnesota at a tax judgment sale. The general redemption period is three years from the date of sale to the state (shortened to one year for targeted-community and certain other lands, and as little as five weeks for qualifying abandoned/vacant properties). Interest on delinquent taxes, penalties, and costs accrues at the rate set under § 270C.40, subd. 5, capped at 14% per annum.','{"redemption_period_months":36,"late_interest_pct_per_year":14,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Three-year general redemption from sale to the state; one year for targeted communities / certain facilities; five weeks for qualifying abandoned/vacant properties (\u00a7\u00a7 281.173, 281.174). Interest rate is variable per \u00a7 270C.40 subd. 5 with a 14% per-annum cap; a county board may set a lower rate. On expiration without redemption the property forfeits to the state (forfeiture/tax-deed model, not a transferable tax-lien certificate sale)."}'::jsonb,'Minn. Stat. § 281.17 (Period of redemption); Minn. Stat. § 279.03, subd. 1a (Interest rate on delinquent taxes)','https://www.revisor.mn.gov/statutes/cite/281.17','2026-06-14',2026),
  ('MO','state','assessment_appeal',NULL,'A property owner who feels aggrieved by their assessment may appeal to the county Board of Equalization. The appeal must be lodged with the county clerk (BOE secretary) before the second Monday in July; the board may extend the filing time at its discretion. The BOE meets the third Monday in July. Further appeal lies to the State Tax Commission (filed by Sept 30, or within 30 days of the BOE''s final action, whichever is later) and then to circuit court.','{"deadline_kind":"fixed_date","deadline_month":7,"deadline_day":null,"deadline_desc":"Before the second Monday in July (filed with county clerk as BOE secretary); BOE may extend at its discretion. Second-level appeal to State Tax Commission due by Sept 30 of the ruling year, or within 30 days of the BOE''s final action, whichever is later.","review_body":"County Board of Equalization (first level); Missouri State Tax Commission (second level); circuit court (judicial review / exemption & situs disputes)","locally_variable":false}'::jsonb,'Mo. Rev. Stat. §§ 137.275, 137.385, 138.010, 138.110, 138.430','https://revisor.mo.gov/main/OneSection.aspx?section=137.385','2026-06-14',2026),
  ('MO','state','assessment',NULL,'Missouri assessment ratios are set by statute statewide (not locally variable): residential real property (subclass 1) at 19%, agricultural/horticultural (subclass 2) at 12%, commercial (subclass 3) at 32%, and tangible personal property at 33-1/3% of true value in money. Real property is reassessed on a two-year cycle: new assessed values are determined as of January 1 of each odd-numbered year and carry through the following even-numbered year.','{"assessment_ratio_pct":19,"market_value_standard":"true value in money","reassessment_cycle_years":2,"locally_variable":false}'::jsonb,'Mo. Rev. Stat. § 137.115','https://revisor.mo.gov/main/OneSection.aspx?section=137.115','2026-06-14',2026),
  ('MO','state','exemption','senior','Senior real property tax credit (SB 190, 2023, as amended): a county may grant a property tax credit to eligible taxpayers age 62 or older who own and occupy a homestead as their primary residence and are liable for the real property taxes. The credit equals the ''eligible credit amount'' — the difference between the taxpayer''s current-year real property tax liability on the homestead and the liability in their initial credit year — effectively freezing the homestead''s tax liability at the initial-year level. County must adopt an ordinance or pass a referendum to offer it; therefore availability and operation are locally variable.','{"age_min":62,"income_max":null,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","benefit_value":null,"benefit_unit":null,"locally_variable":true,"notes":"Statutory framework; each county must adopt by ordinance or referendum. Credit = current-year homestead real property tax liability minus liability in the initial credit year (freezes the TAX LIABILITY owed at the initial-year level, not the assessed value). Initial-year liability is bumped for new construction/improvements or annexation into a new taxing jurisdiction. No statutory income cap (income_max null)."}'::jsonb,'Mo. Rev. Stat. § 137.1050','https://revisor.mo.gov/main/OneSection.aspx?section=137.1050','2026-06-14',2026),
  ('MO','state','exemption','other','Statutory list of property exempt from state, county, and local taxation: government-owned property; nonprofit cemeteries; real and personal property used exclusively for religious worship, schools/colleges, or purely charitable purposes (investment property held for income is not exempt); household goods and personal-use articles owned and used in the home; certain leased motor vehicles used by exempt organizations; all property belonging to congressionally chartered, 501(c)(19) veterans'' organizations; and solar energy systems not held for resale. These are use/ownership-based exemptions, not owner-occupant homestead exemptions.','{"ownership_required":null,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","locally_variable":false,"notes":"Use-and-ownership exemptions (government, charitable/religious/educational, cemeteries, household goods, veterans'' organizations, solar). Missouri has NO general owner-occupant homestead percentage exemption at the state level; owner-occupant relief comes via the \u00a7137.1050 senior credit (county-adopted) and the state circuit-breaker income-tax credit (separate from property tax assessment)."}'::jsonb,'Mo. Rev. Stat. § 137.100','https://revisor.mo.gov/main/OneSection.aspx?section=137.100','2026-06-14',2026),
  ('MO','state','payment',NULL,'Real and personal property taxes are due and payable to the county collector by December 31; taxes remaining unpaid on January 1 become delinquent and a penalty accrues after the first day of January. The exact installment options and billing dates are set locally (e.g., counties may adopt installment ordinances under §§ 139.052 / 139.053). Payments mailed are deemed paid as of the postmark date.','{"installments":[{"label":"Annual payment due","due_month":12,"due_day":31}],"delinquent_after_desc":"Real estate unpaid on the first day of January is delinquent (\u00a7140.010); the collector adds the \u00a7140.100 penalty after the first day of January next ensuing (\u00a7139.100). Mailed payments deemed paid as of postmark date. The Dec 31 due day is the direct consequence of the Jan-1 delinquency line, not an independently stated due-date statute.","grace_days":null,"locally_variable":true}'::jsonb,'Mo. Rev. Stat. §§ 139.100, 140.010, 139.052, 139.053','https://revisor.mo.gov/main/OneSection.aspx?section=139.100','2026-06-14',2026),
  ('MO','state','delinquency_redemption',NULL,'Missouri is a tax-lien-certificate state: at the delinquent land tax sale the purchaser receives a certificate of purchase, not an immediate deed. Pre-sale delinquency carries an 18% per-year penalty (capped at 2% per month for lands redeemed before sale). After a first- or second-offering sale, the owner/lienholder/occupant has an absolute right to redeem for one year (and a defeasible right until the purchaser obtains the deed); redemption cost includes interest at the certificate rate not exceeding 10% annually, plus 8% per annum on subsequently-paid taxes. Third-offering sales carry only a 90-day redemption period; post-third-offering sales have no redemption period.','{"late_penalty_pct":18,"late_interest_pct_per_year":10,"redemption_period_months":12,"tax_sale_kind":"tax_lien","locally_variable":false}'::jsonb,'Mo. Rev. Stat. §§ 140.100, 140.250, 140.340, 140.405','https://revisor.mo.gov/main/OneSection.aspx?section=140.340','2026-06-14',2026),
  ('MS','state','assessment',NULL,'Mississippi assesses property at a percentage of true (market) value set by the state constitution: single-family owner-occupied residential real property (Class I) is assessed at 10% of true value; all other real property (Class II) at 15%. County assessors set the true-value appraisal, but the assessment ratios are uniform statewide and fixed by the constitution.','{"assessment_ratio_pct":10,"market_value_standard":"true value (current use for Class I and Class II real property)","reassessment_cycle_years":null,"locally_variable":false,"notes":"Class I (single-family owner-occupied residential) = 10%; Class II (all other real property) = 15%; Class III personal property = 15%; Class IV public utility = 30%; Class V motor vehicles. Ratios are constitutional and uniform statewide; counties perform the appraisal. VERIFICATION NOTE: the cited source_url (HC 9, 2023) is a House Concurrent Resolution proposing to amend Section 112 (to cut the Class V motor-vehicle ratio from 30% to 15%), not the operative codified constitution; the quoted Class I/Class II language is nonetheless verbatim-present in HC 9 and the 10%/15% ratios match the operative constitution per FindLaw (Miss. Const. art. 4, \u00a7 112). A stronger source_url would be the codified constitution itself.","verification_corroboration":"Class I 10% and Class II 15% confirmed against FindLaw codes.findlaw.com Miss. Const. art. 4 \u00a7 112; full five-class text (Class III 15%, Class IV 30%, Class V motor vehicles) confirmed via constitution-section search."}'::jsonb,'Miss. Const. art. 4, § 112','https://billstatus.ls.state.ms.us/documents/2023/html/HC/HC0009IN.htm','2026-06-14',2026),
  ('MS','state','assessment_appeal',NULL,'A property owner dissatisfied with the assessment must file written objections with the chancery/board clerk, who hears them at the board of supervisors'' equalization meeting held on the first Monday of August. Objections not timely filed are conclusive and the assessment stands. (After the board acts, a further appeal lies to circuit court within statutory limits.) The review body is the county board of supervisors sitting as the board of equalization.','{"deadline_kind":"relative_to_roll","deadline_month":8,"deadline_day":null,"deadline_desc":"Written objections must be filed for/at the board of supervisors'' equalization meeting held on the first Monday of August; failure to file makes the assessment conclusive.","review_body":"County board of supervisors (sitting as board of equalization)","locally_variable":false,"verification_corroboration":"Section 27-35-89 ''first Monday of August'' meeting to hear objections and Section 27-35-93 ''present objections thereto in writing ... All persons who fail to file objections shall be concluded by the assessment'' both confirmed verbatim against the codified Mississippi Code (Justia 2024)."}'::jsonb,'Miss. Code Ann. §§ 27-35-89, 27-35-93','https://billstatus.ls.state.ms.us/documents/2013/html/HB/1300-1399/HB1303IN.htm','2026-06-14',2026),
  ('MS','state','exemption','homestead','Mississippi grants a regular homestead exemption to qualified owner-occupants under 65 who are not totally disabled. It is a tax credit against ad valorem taxes on the home, scaled by assessed value per a statutory table, capped at $300. Applications are filed only in the county tax assessor''s office between January 1 and April 1 of the year claimed.','{"age_min":null,"income_max":null,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":300,"benefit_unit":"usd","locally_variable":false,"notes":"Regular exemption (owner under 65, not totally disabled): a credit set by the \u00a727-33-75(1) table that rises with assessed value, capped at $300 per the DOR. Must own and occupy as primary residence and be eligible by January 1; apply Jan 1-Apr 1 at the county tax assessor.","verification_corroboration":"DOR homestead-exemption page Tier 1 ''tax credit of up to $300 (based on property value)'' and ''between January 1 and April 1'' county Tax Assessor window confirmed via dor.ms.gov-scoped search; corroborated by MSU Extension and county assessor pages."}'::jsonb,'Miss. Code Ann. § 27-33-75(1)','https://www.dor.ms.gov/county-services/homestead-exemption','2026-06-14',2026),
  ('MS','state','exemption','senior','Qualified homeowners who have reached 65 by January 1 (or are totally disabled) are exempt from all ad valorem taxes on the assessed value of the homestead up to the first $7,500 of assessed value (equivalent to roughly the first $75,000 of true value at the 10% residential ratio). The same age-65 standard covers totally-disabled owners and certain unremarried surviving spouses.','{"age_min":65,"income_max":null,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":7500,"benefit_unit":"usd","locally_variable":false,"notes":"Owner must reach age 65 (or be totally disabled) by January 1 of the claim year. Exemption is on the first $7,500 of ASSESSED value (DOR frames this as the first $75,000 of TRUE value at the 10% residential ratio). Totally-disabled owners qualify on the same terms regardless of age; certain unremarried surviving spouses also qualify.","verification_corroboration":"$7,500 figure CONFIRMED CURRENT for 2026. Adversarial check: secondary blogs (appealdesk.com, askdoss.com) claimed a $7,500->$12,500 bump effective 1/1/2026, but the bill that would have done so (HB1255, 2025) DIED IN COMMITTEE on 02/26/2025 per BillTrack50 and was never enacted. The actually-enacted HB 812 (2025) only amends \u00a7 27-33-75 to extend a veterans'' surviving-spouse exemption; it does NOT raise the general over-65/disabled cap. DOR''s live homestead page and the codified statute both still state ''$7,500 of assessed value'' / ''first $75,000 of true value.'' The $7,500 in the evidence quote is the operative law."}'::jsonb,'Miss. Code Ann. §§ 27-33-67(2), 27-33-75(2)','https://billstatus.ls.state.ms.us/documents/2023/html/HB/0600-0699/HB0664IN.htm','2026-06-14',2026),
  ('MS','state','exemption','disability','Homeowners who are totally disabled (e.g., classified totally disabled under the federal Social Security Act, Railroad Retirement Act, or another federal act approved by the Department of Revenue) qualify for the same exemption as owners 65 and older, regardless of age: exempt from ad valorem taxes on the first $7,500 of the homestead''s assessed value. Proof of total disability is required.','{"age_min":null,"income_max":null,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":7500,"benefit_unit":"usd","locally_variable":false,"notes":"Totally-disabled owners qualify on the same $7,500-assessed-value terms as the over-65 tier, no age minimum. Acceptable proof includes total disability under 42 USC 416(i) (Social Security), the Railroad Retirement Act, or another federal act approved by DOR. Must be totally disabled by January 1 of the claim year.","verification_corroboration":"DOR homestead-exemption page Age/Disability tier text (''at least 65 years of age, or totally disabled, by January 1 ... exempt from taxes on the first $7,500 of assessed value'') and the acceptable-proof list (42 USCS Section 416(i) Social Security, Railroad Retirement Act, or any other federal act approved by DOR) confirmed verbatim via dor.ms.gov-scoped search. $7,500 confirmed current (HB1255 $12,500 bump died in committee; see senior entry)."}'::jsonb,'Miss. Code Ann. §§ 27-33-67(2), 27-33-75(2)','https://www.dor.ms.gov/county-services/homestead-exemption','2026-06-14',2026),
  ('MS','state','delinquency_redemption',NULL,'After land is sold for delinquent taxes, the owner (or any interested party) may redeem within two (2) years of the sale by paying the chancery clerk all taxes for which the land was sold, all sale costs, 5% damages on those taxes, and interest at 1.5% per month from the date of sale. Mississippi sells a tax lien at the sale; a tax deed (title) issues only if the property is not redeemed within the two-year period — a hybrid structure.','{"late_penalty_pct":5,"late_interest_pct_per_year":18,"redemption_period_months":24,"tax_sale_kind":"hybrid","locally_variable":false,"notes":"Redemption interest is 1.5% per MONTH (~18%/yr) on taxes and costs, plus 5% damages on the taxes for which the land was sold, plus all sale costs. Two-year redemption runs from the day of sale (infants/persons of unsound mind get an extended right). Lien-then-deed: chancery clerk issues a tax deed only after the 2-year redemption lapses with notice satisfied.","verification_corroboration":"Section 27-45-3 ''within two (2) years after the day of sale ... five percent (5%) damages ... interest ... at the rate of one and one-half percent (1-1/2%) per month'' confirmed verbatim against codified Mississippi Code (Justia/FindLaw). 1.5%/month = 18%/yr and the 5% damages and 2-year/hybrid lien-then-deed structure corroborated by multiple tax-sale references. Note: this 1.5%/month is the REDEMPTION interest under \u00a7 27-45-3, distinct from the \u00a7 27-41-9 delinquency interest (1% per month) addressed in the rejected payment fact."}'::jsonb,'Miss. Code Ann. § 27-45-3','https://billstatus.ls.state.ms.us/documents/2023/html/HB/0200-0299/HB0226IN.htm','2026-06-14',2026),
  ('MT','state','payment',NULL,'Property taxes are paid in two installments: the first half is due by 5 p.m. November 30 (or within 30 days after the tax notice is postmarked, whichever is later) and the second half by 5 p.m. May 31. A primary-residence taxpayer may elect a seven-payment monthly alternative schedule (15-16-122) running Nov 30 through May 31. Unpaid amounts become delinquent and accrue interest at 5/6 of 1% per month plus a 2% penalty. If a due date falls on a Saturday or holiday, payment without penalty is allowed the next business day.','{"installments":[{"label":"First half","due_month":11,"due_day":30},{"label":"Second half","due_month":5,"due_day":31}],"delinquent_after_desc":"First half delinquent after 5 p.m. Nov 30 (or 30 days after notice postmark, whichever is later); second half delinquent after 5 p.m. May 31. Delinquency draws interest at 5/6 of 1% per month plus a 2% penalty.","grace_days":0,"locally_variable":false}'::jsonb,'Mont. Code Ann. § 15-16-102 (Time for Payment -- Penalty for Delinquency)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0160/part_0010/section_0020/0150-0160-0010-0020.html','2026-06-14',2026),
  ('MT','state','assessment',NULL,'Montana real property (class three, class four residential/commercial, and class ten) is revalued on a 2-year reappraisal cycle; all other property is revalued annually. Reappraisal of class three, four, and ten property is complete on December 31 of every second year of the cycle. Valuation is to market value as determined by the Department of Revenue.','{"assessment_ratio_pct":null,"market_value_standard":"market value as determined by the Department of Revenue","reassessment_cycle_years":2,"locally_variable":false}'::jsonb,'Mont. Code Ann. § 15-7-111 (Periodic Reappraisal of Certain Taxable Property)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0070/part_0010/section_0110/0150-0070-0010-0110.html','2026-06-14',2026),
  ('MT','state','assessment_appeal',NULL,'An owner dissatisfied with the Department of Revenue''s appraisal or classification may request an informal classification and appraisal review by submitting a written objection within 30 days from the date on the classification and appraisal notice (20 days for centrally assessed property). After the informal review, the taxpayer may appeal to the County Tax Appeal Board, and then to the Montana Tax Appeal Board, having first exhausted County Board remedies. To be eligible for a refund on an appeal, taxes must be paid under protest.','{"deadline_kind":"relative_to_roll","deadline_month":null,"deadline_day":null,"deadline_desc":"Written objection / informal review request to Department of Revenue within 30 days from the date on the classification and appraisal notice (20 days for centrally assessed property); then County Tax Appeal Board, then Montana Tax Appeal Board.","review_body":"Department of Revenue (informal review) -> County Tax Appeal Board -> Montana Tax Appeal Board","locally_variable":false}'::jsonb,'Mont. Code Ann. § 15-7-102 (Notice of Classification, Market Value, and Taxable Value to Owners -- Appeals); § 15-15-104 (Appeal to Montana Tax Appeal Board)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0070/part_0010/section_0020/0150-0070-0010-0020.html','2026-06-14',2026),
  ('MT','state','exemption','disabled_veteran','The residential real property of a qualified veteran (rated 100% disabled, or paid at the 100% disabled rate, for a service-connected disability) or the veteran''s qualifying surviving spouse receives a reduced tax rate (a percentage multiplier applied to the standard class-four rate). The benefit is income-graduated: at the lowest income tiers the rate multiplier is 0% (property effectively pays no tax), rising to 20%, 30%, or 50% as income increases. Property must be the primary residence owned and occupied by the veteran (or, if deceased, the unmarried surviving spouse). Qualifying income levels are adjusted annually by the PCE inflation factor.','{"age_min":null,"income_max":59554,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":null,"benefit_unit":"pct","locally_variable":false,"notes":"Veteran must be rated 100% disabled (service-connected) or paid at the 100% rate, per a U.S. Dept of Veterans Affairs letter. Income-graduated rate multiplier on standard class-four rate: 0% / 20% / 30% / 50%. For a qualified veteran, top qualifying income bracket is $59,554 single / $68,705 married (50% multiplier). Surviving spouse must be unmarried, owner-occupant; surviving-spouse income brackets run $0-$51,911. Income thresholds inflation-adjusted annually (figures shown are pre-adjustment statutory tiers)."}'::jsonb,'Mont. Code Ann. § 15-6-311 (Disabled Veteran Program)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0060/part_0030/section_0110/0150-0060-0030-0110.html','2026-06-14',2026),
  ('MT','state','exemption','circuit_breaker','The Property Tax Assistance Program (PTAP) provides graduated property tax relief to citizens with limited or fixed incomes. The first $350,000 in market value of qualifying residential real property is taxed at the standard class-four rate multiplied by a percentage figure (20%, 50%, or 70%) based on the applicant''s income. Qualifying income levels are adjusted annually by the PCE inflation factor, and the $350,000 market-value cap is adjusted after each reappraisal cycle.','{"age_min":null,"income_max":37019,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":null,"benefit_unit":"pct","locally_variable":false,"notes":"Income-based rate multiplier (20% / 50% / 70%) applied to first $350,000 market value of residential property. Top qualifying income tier: $27,621 single / $37,019 married-or-head-of-household (70% multiplier). Income levels inflation-adjusted annually; $350k cap adjusted each reappraisal cycle. Figures shown are pre-adjustment statutory tiers. Eligibility requirements set by 15-6-302."}'::jsonb,'Mont. Code Ann. § 15-6-305 (Property Tax Assistance Program -- Fixed or Limited Income -- Inflation Adjustments)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0060/part_0030/section_0050/0150-0060-0030-0050.html','2026-06-14',2026),
  ('MT','state','exemption','homestead','Beginning in tax year 2026, the owner of a principal residence may apply for a homestead reduced tax rate (the reduced class-four residential rate under 15-6-134(3)(b)(i)). The owner applies electronically or by mail on a department form between December 1 of the immediately preceding year and March 1. Once approved, the reduced rate continues until ownership changes, the owner stops using the dwelling as a principal residence, or the owner applies for the rate on a different residence. Class-four residential property owned by an entity is generally not eligible (a grantor revocable trust may apply on the grantor''s behalf).','{"age_min":null,"income_max":null,"income_unit":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":null,"benefit_unit":"pct","locally_variable":false,"notes":"Reduced class-four residential rate per 15-6-134(3)(b)(i). Apply Dec 1 (prior year) to Mar 1; applications postmarked/received after Mar 1 apply to the following tax year. No age or income test. Effective tax year 2026; owners who received the 2024 rebate auto-qualify. Entity-owned residential property generally ineligible."}'::jsonb,'Mont. Code Ann. § 15-6-405 (Homestead Reduced Tax Rate -- Application -- Limitations)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0060/part_0040/section_0050/0150-0060-0040-0050.html','2026-06-14',2026),
  ('MT','state','delinquency_redemption',NULL,'Montana uses a tax-lien system. The county treasurer attaches a tax lien to delinquent property no later than the first working day in August. Redemption of the property tax lien may be made by the owner or other interested party until the first working day in August, 3 years after attachment of the lien (2 years for certain unimproved subdivided lots with delinquent special-improvement-district assessments). After the redemption period, a tax deed may issue. Delinquent taxes draw interest at 5/6 of 1% per month (10% per year) plus a 2% penalty; redemption requires payment of the lien amount plus penalties, interest, and costs.','{"late_penalty_pct":2,"late_interest_pct_per_year":10,"redemption_period_months":36,"tax_sale_kind":"tax_lien","locally_variable":false}'::jsonb,'Mont. Code Ann. § 15-18-111 (Time for Redemption -- Interested Party); § 15-17-125 (Attachment of Tax Lien); § 15-16-102 (delinquency interest/penalty rate)','https://mca.legmt.gov/bills/mca/title_0150/chapter_0180/part_0010/section_0110/0150-0180-0010-0110.html','2026-06-14',2026),
  ('NC','state','exemption','senior','Elderly or disabled homestead exclusion: a qualifying owner who is at least 65 OR totally and permanently disabled, a NC resident, with prior-year income at or below the annually-adjusted income eligibility limit, excludes from taxation the GREATER of $25,000 or 50% of the appraised value of their permanent residence. The income limit base was $25,000 (taxable year beginning July 2008) and is adjusted each year by the Social Security COLA; current-year limit is set annually by the NC Dept. of Revenue. An owner receiving this exclusion may not receive other property tax relief.','{"age_min":65,"income_max":25000,"income_unit":"usd_per_year","income_note":"Statutory base $25,000 for TY beginning July 2008; adjusted annually by Social Security COLA, set each year by NC Dept. of Revenue. Current-year figure not the base.","ownership_required":true,"primary_residence_required":true,"disability_alternative":"Totally and permanently disabled qualifies in lieu of age 65","benefit_kind":"exempt_value_cap","benefit_value":"greater of $25,000 or 50% of appraised value","benefit_unit":"usd","locally_variable":false,"notes":"Permanent residence includes dwelling, dwelling site up to one acre, and related improvements; may be single-family, a unit in a multi-family complex, or a manufactured home. Married applicants must combine both spouses'' income."}'::jsonb,'N.C. Gen. Stat. § 105-277.1','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_12.html','2026-06-14',2026),
  ('NC','state','exemption','disabled_veteran','Disabled veteran homestead exclusion: the first $45,000 of appraised value of a permanent residence owned and occupied by a qualifying owner is excluded from taxation. A qualifying owner is a NC-resident honorable-service veteran with a service-connected permanent and total disability (or who received 38 U.S.C. § 2101 benefits, or whose death was service-connected), or the un-remarried surviving spouse of such a veteran. No age or income limit. Recipient may not receive other property tax relief.','{"income_max":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":45000,"benefit_unit":"usd","locally_variable":false,"notes":"No age or income test. Surviving spouse (not remarried) of a qualifying disabled veteran also qualifies. Disability must be service-connected, permanent, and total, certified by US Dept. of Veterans Affairs or another federal agency as of January 1 preceding the taxable year."}'::jsonb,'N.C. Gen. Stat. § 105-277.1C','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_12.html','2026-06-14',2026),
  ('NC','state','exemption','circuit_breaker','Property tax homestead circuit breaker: a qualifying owner (at least 65 or totally and permanently disabled, NC resident, who has owned AND occupied the residence as a permanent residence for at least 5 consecutive years, with prior-year income not more than 150% of the income eligibility limit) may DEFER the portion of current-year tax exceeding a fixed percentage of income — 4.0% of income up to the income eligibility limit, 5.0% for income between 100% and 150% of that limit. Deferred amount is a deferred tax (lien), not a permanent forgiveness.','{"age_min":65,"income_max":37500,"income_unit":"usd_per_year","income_note":"Limit is 150% of the annually-adjusted income eligibility limit; 150% of the $25,000 statutory base = $37,500, but the base is COLA-adjusted annually so the current threshold is higher. Figure shown is from the statutory base, not the current-year value.","ownership_required":true,"primary_residence_required":true,"min_ownership_years":5,"benefit_kind":"pct_reduction","benefit_value":"tax capped at 4.0% of income up to the limit, 5.0% for income 100-150% of limit; excess deferred","benefit_unit":"pct","locally_variable":false,"notes":"Tax above the income-percentage cap is DEFERRED (becomes deferred taxes / lien), not exempted. Owner must elect circuit breaker instead of the 105-277.1 exclusion."}'::jsonb,'N.C. Gen. Stat. § 105-277.1B','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_12.html','2026-06-14',2026),
  ('NC','state','assessment_appeal',NULL,'A taxpayer appeals listing, appraisal, or assessment of property to the county board of equalization and review. The request for a hearing must be made in writing or by personal appearance before the board PRIOR TO ITS ADJOURNMENT. The board first meets between the first Monday in April and the first Monday in May; in a non-revaluation year it adjourns on or before the third Monday after its first meeting (longer if needed, but generally not later than July 1); in a revaluation year it completes its duties on or before December 1. Further appeal lies to the state Property Tax Commission (sitting as the State Board of Equalization and Review).','{"deadline_kind":"window","deadline_month":null,"deadline_day":null,"deadline_desc":"Request for hearing must be filed before the county board of equalization and review adjourns. Board first meets between first Monday in April and first Monday in May; in non-revaluation years it adjourns on or before the third Monday after its first meeting; in revaluation years it completes duties on or before December 1. Exact adjournment date is published by each county annually.","review_body":"County board of equalization and review (first level); N.C. Property Tax Commission, sitting as State Board of Equalization and Review (appeal level)","locally_variable":true}'::jsonb,'N.C. Gen. Stat. § 105-322(e),(g); § 105-290','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_21.html','2026-06-14',2026),
  ('NC','state','payment',NULL,'Property taxes are due and payable September 1 of the fiscal year for which they are levied. They may be paid at par through January 5; taxes paid on or after January 6 are delinquent and accrue interest: 2% for the period January 6 to February 1, then 3/4% per month (or fraction) thereafter until paid. These due/delinquency dates and interest rates are set statewide by statute (not locally variable), though localities may add prepayment discount schedules.','{"installments":[{"label":"Annual levy due date","due_month":9,"due_day":1}],"delinquent_after_desc":"Payable at par if paid before January 6 following the September 1 due date; delinquent (interest-bearing) on and after January 6.","grace_days":null,"locally_variable":false,"notes":"Single annual bill (not statutory installments). Localities may, with NC Dept. of Revenue approval, adopt prepayment discount schedules. Mailed payments deemed received on USPS postmark date."}'::jsonb,'N.C. Gen. Stat. § 105-360(a)','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_26.html','2026-06-14',2026),
  ('NC','state','delinquency_redemption',NULL,'North Carolina enforces delinquent property taxes by judicial foreclosure of the tax lien (an action in the nature of a mortgage foreclosure under § 105-374, or in rem under § 105-375), culminating in a tax-deed sale of the property — NOT a sale of tax-lien certificates. There is no fixed post-sale statutory redemption period: the owner may redeem only by paying all taxes, penalties, interest, and costs BEFORE confirmation of the foreclosure sale (i.e. before the upset-bid period closes and the sale is confirmed). Once the sale is confirmed, the right to redeem is extinguished. Delinquency interest is the § 105-360 schedule (2% Jan 6-Feb 1, then 3/4% per month).','{"late_penalty_pct":null,"late_interest_pct_per_year":null,"late_interest_note":"Per \u00a7 105-360: 2% for Jan 6-Feb 1, then 0.75% per month (~9%/yr) thereafter.","redemption_period_months":0,"redemption_note":"No fixed post-sale redemption period. Redemption permitted only before confirmation of the foreclosure sale (before the upset-bid period expires); extinguished on confirmation.","tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Foreclosure is judicial (in the General Court of Justice) in the nature of a mortgage foreclosure, or in rem under \u00a7 105-375. Not a tax-lien-certificate state. CITATION CORRECTED: redemption-before-confirmation language is in \u00a7 105-374(e), not the (c2) shown in the source facts (105-374 has subsections (a)-(r) with no (c2))."}'::jsonb,'N.C. Gen. Stat. § 105-374(e); see also § 105-375','https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/ByArticle/Chapter_105/Article_26.html','2026-06-14',2026),
  ('ND','state','assessment_appeal','local_equalization','ND uses tiered local equalization/review boards as the primary assessment-appeal path. A taxpayer petitions the local board of equalization: city equalization proceedings are held within the first fifteen days of April, organized-township proceedings in the month of April, and the county board of equalization meets no later than June 10. Each published equalization notice must state the taxpayer''s right to appear and petition for correction of the assessment.','{"deadline_kind":"window","deadline_month":4,"deadline_day":15,"deadline_desc":"City equalization within first 15 days of April; township equalization during April; county board of equalization by June 10. Appear before the applicable local board of review/equalization to petition for correction.","review_body":"Local (city/township) board of equalization, then county board of equalization, then state board of equalization","locally_variable":true}'::jsonb,'N.D.C.C. § 57-02-51; § 57-02-52','https://ndlegis.gov/cencode/t57c02.pdf','2026-06-14',2026),
  ('ND','state','assessment_appeal','invalid_assessment_action','Alternative/secondary path: a taxpayer who claims an assessment or tax is invalid, inequitable, or unjust (among the enumerated grounds in § 57-23-04) may file a written application for abatement or refund with the county auditor on or before November 1 of the year following the year in which the tax becomes delinquent. The board of county commissioners hears the application; any person aggrieved by the decision may appeal in the manner provided by law (to district court).','{"deadline_kind":"fixed_date","deadline_month":11,"deadline_day":1,"deadline_desc":"File written abatement/refund application with county auditor on or before November 1 of the year following the year in which the tax becomes delinquent","review_body":"Board of county commissioners (with appeal as provided by law / to district court)","locally_variable":false}'::jsonb,'N.D.C.C. § 57-23-04','https://ndlegis.gov/cencode/t57c23.pdf','2026-06-14',2026),
  ('ND','state','exemption','senior','Homestead credit for persons 65 or older OR permanently and totally disabled, subject to income limits. If income is not over $40,000: 100% reduction of the homestead''s taxable valuation up to a maximum reduction of $9,000 of taxable valuation. If income is over $40,000 but not over $70,000: 50% reduction up to a maximum reduction of $4,500 of taxable valuation. Applies to the owner-occupied homestead; one credit per household of spouses/dependents.','{"age_min":65,"income_max":70000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":9000,"benefit_unit":"usd","locally_variable":false,"notes":"Also available to permanently and totally disabled persons regardless of age. Two income tiers: income <= $40,000 = 100% reduction capped at $9,000 of taxable valuation; income > $40,000 and <= $70,000 = 50% reduction capped at $4,500 of taxable valuation. Income includes most retirement/social-security/public-assistance income with statutory exclusions. Does not reduce special assessments. Renters meeting subsection-1 criteria can claim a partial rent-as-property-tax refund (max $600) instead."}'::jsonb,'N.D.C.C. § 57-02-08.1','https://ndlegis.gov/cencode/t57c02.pdf','2026-06-14',2026),
  ('ND','state','exemption','disabled_veteran','Property tax credit for a disabled veteran with a service-connected disability of 50% or greater (or extra-schedular individual unemployability paid at the 100% rate), discharged under honorable conditions or retired, or the surviving spouse. Credit applies against the first $9,000 of taxable valuation of the owned and occupied homestead, equal to the percentage of the veteran''s certified disability rating. A surviving spouse receiving VA dependency and indemnity compensation receives a 100% credit.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":9000,"benefit_unit":"usd","locally_variable":false,"notes":"Minimum 50% service-connected disability rating required. Credit = certified disability percentage applied against first $9,000 of taxable valuation of homestead. Surviving spouse receiving VA dependency and indemnity compensation gets 100% credit. Two married disabled veterans combined cannot exceed 100% of $9,000. Does not reduce special assessments. First-time claim filed with county auditor via affidavit + VA certificate."}'::jsonb,'N.D.C.C. § 57-02-08.8','https://ndlegis.gov/cencode/t57c02.pdf','2026-06-14',2026),
  ('ND','state','exemption','homestead','Primary residence credit: a taxpayer is entitled to a credit against property tax due on the taxpayer''s parcel of primary residential property, limited to $1,600. The credit may not reduce special-assessment liability, may not exceed the property tax due on the parcel, and is applied after other exemptions/credits/discounts. Only one credit per parcel; a trust may not claim more than one parcel.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"fixed_amount","benefit_value":1600,"benefit_unit":"usd","locally_variable":false,"notes":"Credit capped at $1,600 against tax due; cannot exceed the property tax due on the parcel; applied after other exemptions/credits/discounts; does not reduce special assessments. One credit per parcel of primary residential property."}'::jsonb,'N.D.C.C. § 57-02-08.9','https://ndlegis.gov/cencode/t57c02.pdf','2026-06-14',2026),
  ('ND','state','payment',NULL,'All real and personal property taxes become due January 1 following the levy year. The first installment of real estate taxes becomes delinquent after March 1; if not paid by then it is subject to a 3% penalty, an additional 3% on May 1, an additional 3% on July 1, and an additional 3% on October 15. The second installment of real estate taxes becomes delinquent after October 15 and, if unpaid, is subject to a 6% penalty.','{"installments":[{"label":"First installment (real estate)","due_month":3,"due_day":1},{"label":"Second installment (real estate)","due_month":10,"due_day":15}],"delinquent_after_desc":"Taxes due January 1; first installment delinquent after March 1 (3% penalty, +3% May 1, +3% July 1, +3% Oct 15); second installment delinquent after October 15 (6% penalty)","grace_days":0,"locally_variable":false,"notes":"12% per annum simple interest accrues on unpaid PERSONAL property taxes from January 1 of the following year. Real-estate-tax dates are set statewide by statute, not locally."}'::jsonb,'N.D.C.C. § 57-20-01','https://ndlegis.gov/cencode/t57c20.pdf','2026-06-14',2026),
  ('ND','state','delinquency_redemption',NULL,'North Dakota is a tax-deed state with no post-foreclosure redemption period. On or before June 1 each year the county auditor gives notice of foreclosure of the tax lien for property delinquent two or more years; the foreclosure date is October 1 after service of notice. Failure to satisfy (redeem) the tax lien before the foreclosure date passes the owner''s interest to the county and forecloses all rights of satisfaction; after foreclosure the auditor issues a tax deed passing the property in fee to the county. Redemption is therefore only available BEFORE the October 1 foreclosure date.','{"late_penalty_pct":null,"late_interest_pct_per_year":12,"redemption_period_months":0,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Tax-deed system, not a tax-lien-certificate sale. Foreclosure occurs only after 2+ years of delinquency: notice by June 1, foreclosure date October 1. No statutory post-foreclosure redemption window \u2014 the owner/mortgagee/lienholder must satisfy the lien BEFORE the October 1 foreclosure date or all rights of satisfaction are foreclosed and title passes in fee to the county. The 12% per-annum figure is the simple interest on unpaid personal property taxes under \u00a7 57-20-01."}'::jsonb,'N.D.C.C. § 57-28-01; § 57-28-02; § 57-28-08; § 57-28-09','https://ndlegis.gov/cencode/t57c28.pdf','2026-06-14',2026),
  ('NE','state','assessment_appeal',NULL,'Real-property valuation protests are filed with the county clerk and decided by the county board of equalization; a protest must be signed and filed on or before June 30. The board''s decision may be appealed to the Tax Equalization and Review Commission (TERC) on or before August 24 (extended to September 10 in counties that adopt the extended-hearing resolution).','{"deadline_kind":"fixed_date","deadline_month":6,"deadline_day":30,"deadline_desc":"Protest signed and filed with county clerk on or before June 30; county board of equalization hears protests June 1 to July 25 (Aug 10 in counties >100,000 that adopt extension resolution). Appeal to TERC by Aug 24 (Sept 10 if extended).","review_body":"County Board of Equalization (first level); Tax Equalization and Review Commission (appeal)","locally_variable":false}'::jsonb,'Neb. Rev. Stat. 77-1502; 77-1510','https://nebraskalegislature.gov/laws/statutes.php?statute=77-1502','2026-06-14',2026),
  ('NE','state','payment',NULL,'All property taxes are due and payable on December 31 following the date of levy. The first half of the tax becomes delinquent May 1 and the second half September 1; in counties with population over 100,000 the first half is delinquent April 1 and the second half August 1. Real-property taxes become a first lien on the property when due.','{"installments":[{"label":"First half","due_month":5,"due_day":1},{"label":"Second half","due_month":9,"due_day":1}],"delinquent_after_desc":"Taxes due Dec 31; first half delinquent May 1, second half delinquent Sept 1 the following year. In counties over 100,000 population: first half delinquent April 1, second half August 1.","grace_days":null,"locally_variable":false}'::jsonb,'Neb. Rev. Stat. 77-203; 77-204','https://nebraskalegislature.gov/laws/statutes.php?statute=77-203','2026-06-14',2026),
  ('NE','state','delinquency_redemption',NULL,'Delinquent real-property taxes are collected through a tax sale that issues a certificate of purchase (tax-lien system). The owner, occupant, lienholder, or interest-holder may redeem at any time before the purchaser files an application for a treasurer''s tax deed. Redemption requires paying the certificate amount plus interest at the rate in section 45-104.01 (currently fourteen percent per annum) from date of purchase, plus subsequently paid taxes with like interest and statutory fees.','{"late_penalty_pct":null,"late_interest_pct_per_year":14,"redemption_period_months":null,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"No fixed redemption-period length: the right to redeem runs until the certificate purchaser files an application for a tax deed with the county treasurer (purchaser generally cannot apply for the deed until 3 years after the sale per 77-1837(1)(b); a shorter 2-year window applies to vacant/abandoned property purchased by a land bank under 77-1837(1)(a)). Redemption interest is the delinquent-tax rate set by 45-104.01, currently 14% per annum."}'::jsonb,'Neb. Rev. Stat. 77-1824; 45-104.01','https://nebraskalegislature.gov/laws/statutes.php?statute=77-1824','2026-06-14',2026),
  ('NE','state','exemption','disabled_veteran','A mobile home is exempt from taxation if owned and occupied by a disabled or blind honorably (or general under honorable conditions) discharged veteran of the U.S. Armed Forces whose disability or blindness is recognized by the U.S. Department of Veterans Affairs as service-connected. Application is made to the county assessor on or before April 1 of every year; the assessor decides within 20 days and the taxpayer may appeal to the county board of equalization within 20 days of notice.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"full_exemption","benefit_value":null,"benefit_unit":"usd","locally_variable":false,"notes":"Full exemption of the mobile home from taxation (not a value cap). Applies to a mobile home (not a site-built residence). Veteran''s service-connected disability/blindness must be VA-recognized. Annual application due April 1. This is the narrow mobile-home veteran exemption (77-202.24); the broader veteran homestead exemption is under Ch. 77 Art. 35 (e.g., 77-3506). VERIFY NOTE: benefit_kind corrected from ''exempt_value_cap'' to ''full_exemption'' to match the statute''s ''shall be exempt from taxation'' language; original benefit_value was already null so no figure changed."}'::jsonb,'Neb. Rev. Stat. 77-202.24; 77-202.25','https://nebraskalegislature.gov/laws/statutes.php?statute=77-202.24','2026-06-14',2026),
  ('NE','state','exemption','homestead','Nebraska''s homestead exemption exempts a percentage of the ''exempt amount'' on the homestead of qualified claimants (including persons 65 and older and certain disabled persons) from taxation. The relief percentage is graduated by household income with separate income tables for married/closely related claimants versus single claimants, and the income thresholds and exempt amount/maximum value are adjusted annually. Owners must file the homestead exemption application (Form 458) with the county assessor after February 1 and on or before June 30 of each year.','{"age_min":65,"income_max":null,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":null,"benefit_unit":"pct","locally_variable":false,"notes":"Relief is a percentage of the statutory ''exempt amount'' (the lesser of a set dollar value or a percentage of the homestead''s assessed value), graduated 0-100% by household income. Income limits and the exempt-amount/maximum-value figures are CPI-adjusted annually by the Dept. of Revenue (see annual Homestead Exemption Category Requirements Table); do not hardcode a single income or dollar figure. VERIFY NOTE: age_min=65 is accurate to the Nebraska program but the cited sections 77-3507 and 77-3512 use the generic term ''qualified claimants'' and do NOT themselves enumerate the over-65/disabled categories (those are defined in 77-3502 / 77-3506 et seq.); the quote-backed elements here are the income-graduated pct-reduction benefit and the Feb 1-June 30 filing window."}'::jsonb,'Neb. Rev. Stat. 77-3507; 77-3512','https://nebraskalegislature.gov/laws/statutes.php?statute=77-3507','2026-06-14',2026),
  ('NH','state','assessment_appeal',NULL,'An aggrieved taxpayer must first apply in writing to the selectmen/assessors for an abatement by March 1 following the date of the tax notice. If denied (or no action), the taxpayer may then appeal by September 1 to either the NH Board of Tax and Land Appeals (BTLA) or the superior court.','{"deadline_kind":"fixed_date","deadline_month":3,"deadline_day":1,"deadline_desc":"Abatement application to selectmen/assessors due by March 1 following the date of notice of tax (RSA 76:16). Subsequent appeal to the Board of Tax and Land Appeals or superior court due on or before September 1 after the notice of tax (RSA 76:16-a / 76:17).","review_body":"Local selectmen/assessors first; then NH Board of Tax and Land Appeals (BTLA) or the superior court","locally_variable":false}'::jsonb,'RSA 76:16 and RSA 76:16-a','https://gc.nh.gov/rsa/html/V/76/76-16.htm','2026-06-14',2026),
  ('NH','state','exemption','veteran','Standard veterans'' tax credit of $50 subtracted yearly from the property tax on the veteran''s residential property. A town/city may instead adopt an optional veterans'' tax credit of $51 up to $750 (which replaces, and is not in addition to, the standard credit). Requires NH residency, a qualifying war/armed-conflict veteran (90+ days active service, honorable discharge), or qualifying spouse/surviving spouse.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":50,"benefit_unit":"usd","locally_variable":true,"notes":"Standard credit is a fixed $50. If the municipality adopts the optional credit under RSA 72:27-a it ranges $51-$750 (locally set, replaces the standard). This is a credit against tax owed, not an assessed-value reduction."}'::jsonb,'RSA 72:28','https://gc.nh.gov/rsa/html/V/72/72-28.htm','2026-06-14',2026),
  ('NH','state','exemption','disabled_veteran','Standard tax credit of $700 in property taxes for a veteran with total and permanent service-connected disability (or who is a double amputee/paraplegic from a service-connected injury), or the surviving spouse, applied to the principal residence. A town/city may adopt an optional credit of $701 up to $5,000. Separately, RSA 72:36-a fully exempts from all taxation the homestead of a 100%-disabled veteran whose home was specially adapted via a VA SAH/SHA grant.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":700,"benefit_unit":"usd","locally_variable":true,"notes":"Standard credit $700; optional credit $701-$5,000 if adopted by municipality (RSA 72:35 I-a). Requires VA certification of total/permanent service-connected disability. RSA 72:36-a is a separate full homestead exemption for specially-adapted (VA SAH/SHA) homes of 100% disabled veterans."}'::jsonb,'RSA 72:35 (and RSA 72:36-a)','https://gc.nh.gov/rsa/html/V/72/72-35.htm','2026-06-14',2026),
  ('NH','state','exemption','senior','Elderly exemption (RSA 72:39-a/72:39-b) reduces the assessed value of the qualifying elderly resident''s principal residence. The state sets eligibility floors: at least 3 consecutive years NH residency before April 1; minimum income limits no less than $13,400 single / $20,400 married; and net-asset limits no less than $35,000 (excluding the residence and up to 2 acres). The actual exemption dollar amounts and the exact income/asset limits (by age band, e.g. 65-74, 75-79, 80+) are set by each city or town.','{"age_min":65,"income_max":13400,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","locally_variable":true,"notes":"State sets only the minimum floors: income limit not less than $13,400 (single) / $20,400 (married); net assets not less than $35,000 (excluding residence + up to 2 acres); 3-year NH residency. Exemption dollar amounts and age-band thresholds (65-74 / 75-79 / 80+) are set by each municipality under RSA 72:39-b. Benefit is a reduction of assessed value."}'::jsonb,'RSA 72:39-a (conditions) and RSA 72:39-b','https://gc.nh.gov/rsa/html/V/72/72-39-a.htm','2026-06-14',2026),
  ('NH','state','exemption','disability','Two distinct disability exemptions reduce the assessed value of a qualifying resident''s principal residence. RSA 72:37 gives a legally blind resident an exemption of $15,000 of assessed value (a town/city may increase it). RSA 72:37-b lets a city/town optionally grant a yearly exemption (amount set locally) to a resident eligible for federal Social Security disability benefits (Title II or Title XVI).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":15000,"benefit_unit":"usd","locally_variable":true,"notes":"RSA 72:37 (blind): $15,000 of assessed value exempt; municipality may add more. RSA 72:37-b (disabled): optional exemption, amount and income/asset limits set by each municipality, for persons eligible under SSA Title II/XVI. Benefit is a reduction of assessed value."}'::jsonb,'RSA 72:37 (blind) and RSA 72:37-b (disabled)','https://gc.nh.gov/rsa/html/V/72/72-37.htm','2026-06-14',2026),
  ('NH','state','payment',NULL,'New Hampshire does not set a single statewide property-tax due date; municipalities bill and collect locally (annual, semi-annual, or quarterly cycles). The state frames timelines via the notice-of-tax mechanism in RSA 76:1-a, after which abatement/appeal deadlines run. Interest on delinquent taxes accrues under RSA 76:13 (8% per annum, generally from December 1 after assessment unless a bill is mailed later).','{"installments":[],"delinquent_after_desc":"Delinquency and interest accrual are set under municipal billing and RSA 76/RSA 80; specific due dates vary by city/town. Interest on delinquent taxes accrues at 8% per annum under RSA 76:13, generally from December 1 after assessment (or 30 days after mailing if a bill is sent on/after Nov 2 and before April 1).","locally_variable":true}'::jsonb,'RSA 76:1-a (notice of tax); local billing under RSA Chapter 76; RSA 76:13 (interest)','https://gc.nh.gov/rsa/html/V/76/76-16.htm','2026-06-14',2026),
  ('NH','state','delinquency_redemption',NULL,'NH uses a tax-lien-then-deed procedure. After unpaid taxes, a real estate tax lien is executed; the owner (or other party with a legal interest) may redeem at any time before the collector gives a tax deed by paying the recorded lien amount plus 14% per annum interest. The collector executes the tax deed to the lienholder 2 years after the lien execution, so the effective redemption window is 24 months from lien execution.','{"late_interest_pct_per_year":14,"redemption_period_months":24,"tax_sale_kind":"hybrid","locally_variable":false}'::jsonb,'RSA 80:69 (redemption / 14% interest) and RSA 80:76 (tax deed after 2 years)','https://gc.nh.gov/rsa/html/V/80/80-69.htm','2026-06-14',2026),
  ('NJ','state','assessment_appeal',NULL,'Property tax assessment appeals are filed with the County Board of Taxation. The general deadline is April 1 of the tax year. Where a municipal revaluation or reassessment has been undertaken, the deadline is May 1. Burlington, Gloucester, and Monmouth counties follow an alternative assessment calendar with a January 15 deadline. Owners of property assessed over $1,000,000 may appeal directly to the NJ State Tax Court. An appeal of a County Board judgment must be filed with the Tax Court within 45 days of the judgment.','{"deadline_kind":"fixed_date","deadline_month":4,"deadline_day":1,"deadline_desc":"On or before April 1; May 1 where a municipal revaluation/reassessment was undertaken; January 15 for Burlington, Gloucester, and Monmouth counties (alternate assessment calendar). Direct NJ State Tax Court filing allowed when assessment exceeds $1,000,000. Appeal of a County Board judgment must be filed with Tax Court within 45 days of that judgment.","review_body":"County Board of Taxation (first level); NJ State Tax Court (direct for assessments > $1,000,000, and on appeal of a County Board judgment within 45 days)","locally_variable":false}'::jsonb,'N.J.S.A. 54:3-21','https://www.nj.gov/treasury/taxation/lpt/lpt-appeal.shtml','2026-06-14',2026),
  ('NJ','state','exemption','senior','Annual $250 property tax deduction for residents age 65 or older, or disabled, who own and occupy the home and have been a legal NJ resident for at least one year prior to October 1, subject to an income limit. The same statute covers qualifying disabled persons and surviving spouses (age 55+). The statutory income limit is $10,000 per year, excluding (with restrictions) Social Security or comparable federal/state pension, disability, and retirement benefits under one of three categories.','{"age_min":65,"income_max":10000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":250,"benefit_unit":"usd","locally_variable":false,"notes":"Also available to qualifying disabled persons and to unmarried surviving spouses/civil union partners (age 55+). Statutory income limit is $10,000/year, excluding income under one of three permitted categories (incl. Social Security). Be a legal resident of NJ for at least 1 year prior to October 1; own and occupy your home as of October 1 of the pretax year; age 65+/disabled as of December 31 of the pretax year. The nj.gov page links to the annually-published Income Guidelines rather than printing the $10,000 figure; the figure is set by codified statute N.J.S.A. 54:4-8.41 (''$10,000.00 ... each year thereafter'')."}'::jsonb,'N.J.S.A. 54:4-8.40 et seq. (income limit at 54:4-8.41)','https://www.nj.gov/treasury/taxation/lpt/lpt-seniordeduction.shtml','2026-06-14',2026),
  ('NJ','state','exemption','veteran','Annual $250 property tax deduction for honorably discharged veterans with active-duty United States Armed Forces service who own and occupy a NJ home. Also available to surviving spouses/civil union/domestic partners (who have not remarried or formed a new civil union/domestic partnership) of a qualifying veteran.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":250,"benefit_unit":"usd","locally_variable":false,"notes":"Honorable discharge plus active-duty service in the U.S. Armed Forces required. Reservists and National Guard personnel must have been called to active duty service to qualify; active duty for training is ineligible. Surviving spouse must not have remarried or formed a new registered civil union/domestic partnership. The nj.gov Division of Taxation page prints no N.J.S.A. citation; the deduction derives from N.J. Const. Art. VIII, Sec. 1, par. 3 and N.J.S.A. 54:4-8.10 et seq."}'::jsonb,'N.J.S.A. 54:4-8.11 et seq. (N.J. Const. Art. VIII, Sec. 1, par. 3)','https://www.nj.gov/treasury/taxation/lpt/lpt-veterans.shtml','2026-06-14',2026),
  ('NJ','state','exemption','disabled_veteran','Full property tax exemption on the principal/primary residence of an honorably discharged veteran certified by the U.S. Department of Veterans Affairs as 100% permanently and totally disabled from active-duty service-connected disability. Surviving spouses/civil union/domestic partners of a qualifying veteran (who have not remarried) may also qualify.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Requires a U.S. Department of Veterans Affairs certification of active-duty service-connected disability stating the veteran is 100% permanently and totally disabled. Veteran must own and occupy the dwelling house as main home and residence. Surviving spouse/civil union/domestic partner of a qualifying veteran (not remarried) also may qualify. Full (100%) exemption. The nj.gov Division of Taxation page prints no N.J.S.A. citation; the exemption derives from N.J.S.A. 54:4-3.30 et seq."}'::jsonb,'N.J.S.A. 54:4-3.30 et seq.','https://www.nj.gov/treasury/taxation/lpt/lpt-disabledvet.shtml','2026-06-14',2026),
  ('NM','state','assessment_appeal',NULL,'A property owner protests value, classification, allocation, or denial of an exemption/value-limitation by filing a petition with the county assessor. The deadline is the later of April 1 of the tax year (when the valuation notice was mailed with the prior year''s tax bill) or 30 days after the assessor mails the notice of valuation; in all other cases, 30 days after the notice of valuation is mailed. The assessor then schedules a hearing before the county valuation protests board.','{"deadline_kind":"relative_to_roll","deadline_month":4,"deadline_day":1,"deadline_desc":"Later of April 1 of the tax year or 30 days after the assessor mails the notice of valuation; in all other cases 30 days after the notice of valuation is mailed.","review_body":"County valuation protests board","locally_variable":false}'::jsonb,'NMSA 1978, § 7-38-24(A) (Laws 2026, Ch. 9, § 4)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','exemption','homestead','New Mexico''s head-of-family exemption (its homestead-equivalent) exempts up to $2,000 of the taxable value of residential property owned by the head of a family who is a New Mexico resident (or held in a qualifying grantor trust). ''Head of a family'' includes a married person (only one spouse per household), a widow/widower, a head of household supporting a related person, or a single person. Claimable only once per tax year and in only one county.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":2000,"benefit_unit":"usd","locally_variable":false,"notes":"Applies to taxable (assessed) value; New Mexico residency required; one claim per tax year, one county only. Must be claimed under \u00a7 7-38-17."}'::jsonb,'NMSA 1978, § 7-37-4(A) (Laws 1993, Ch. 343, § 1)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','exemption','senior','Assessment-freeze (value limitation) for a single-family dwelling owned and occupied by a person 65 or older (or disabled) whose modified gross income for the prior year did not exceed $35,000 (2020 base, adjusted annually for inflation). The valuation for property-tax purposes cannot exceed the assessed value in the tax year the owner first qualifies and applies. Apply by filing proof of eligibility with the county assessor no later than 30 days after the assessor mails the notice of valuation; once proof of income is filed for three consecutive years, the assessor applies the limitation automatically until eligibility changes.','{"age_min":65,"income_max":35000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","locally_variable":false,"notes":"Also available to disabled owners regardless of age. $35,000 is the 2020 base ''modified gross income'' ceiling, inflation-adjusted each year (rounded down to nearest $100); NMTRD publishes the current figure by Dec 1. Applies to single-family dwelling occupied as residence; does not apply to value increases from physical improvements/zoning changes or to the first year a residence is valued."}'::jsonb,'NMSA 1978, § 7-36-21.3(A)-(B), (F) (Laws 2020, Ch. 73, § 1)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','exemption','veteran','A veteran (or the veteran''s unmarried surviving spouse) who is a New Mexico resident may exempt a set dollar amount of taxable value: $4,000 for tax years 2006-2024, $10,000 for tax year 2025, and for 2026 and later the $10,000 amount adjusted annually for inflation. ''Veteran'' means a person honorably discharged from the U.S. armed forces who served at least 90 days of active duty (with a service-connected-disability exception to the 90-day rule).','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":10000,"benefit_unit":"usd","locally_variable":false,"notes":"$10,000 is the tax-year-2025 amount; 2026+ is $10,000 inflation-adjusted (rounded down to nearest $100), published by NMTRD by Dec 1 of the prior year. Was $4,000 for 2006-2024. Unmarried surviving spouse also qualifies. Must be claimed under \u00a7 7-38-17."}'::jsonb,'NMSA 1978, § 7-37-5(A)-(C) (Laws 2025, Ch. 10, § 1)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','exemption','disabled_veteran','A disabled veteran (honorably discharged with a federally-determined permanent service-connected disability) who occupies the property as a principal residence is exempt from property taxation in an amount equal to the disability percentage (per federal determination) multiplied by the taxable value remaining after the regular veteran exemption is deducted. A 100% service-connected disability yields a full exemption. The exemption continues for a surviving spouse who was married to the veteran at death and continues to occupy the property as a principal residence.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_unit":"pct","locally_variable":false,"notes":"Benefit = (federal disability %) x (taxable value after the \u00a7 7-37-5 veteran exemption is deducted). 100% disability = full exemption. Surviving spouse retains it while continuing to occupy as principal residence. Prior law granted a flat 100% exemption; Laws 2026, Ch. 9 changed it to a percentage-of-disability formula. Must be claimed under \u00a7 7-38-17."}'::jsonb,'NMSA 1978, § 7-37-5.1(A)-(C) (Laws 2026, Ch. 9, § 1)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','payment',NULL,'Property taxes of $10 or more are payable to the county treasurer in two equal installments: the first due November 10 of the year the tax bill is prepared and mailed, and the second due April 10 of the following year. Interest accrues if taxes are not paid within 30 days after they are due. These due dates are fixed statewide by statute (not set locally).','{"installments":[{"label":"First half","due_month":11,"due_day":10},{"label":"Second half","due_month":4,"due_day":10}],"delinquent_after_desc":"Interest accrues on unpaid taxes from the 30th day after they are due; an installment unpaid by that point is delinquent.","grace_days":30,"locally_variable":false,"notes":"Statewide statutory dates (Nov 10 / Apr 10). A board of county commissioners may, by ordinance, require taxes under $10 to be paid in a single Nov 10 payment, but the installment dates themselves are fixed by state law."}'::jsonb,'NMSA 1978, § 7-38-38(A) (Laws 1987, Ch. 166, § 2); § 7-38-49','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NM','state','delinquency_redemption',NULL,'New Mexico is a tax-DEED state. There is no traditional post-sale redemption period: the owner''s right to cure runs before the sale. Delinquent taxes accrue interest at 1% per month (12%/yr) from the 30th day after due, plus a civil penalty of 1% per month capped at 5% (minimum $5). Real property may be sold for delinquent taxes only after 3 years from the first delinquency date, and the owner may pay all delinquent taxes, penalties, interest and costs (or enter an installment agreement) up to 5:00 p.m. the day before the sale to stop it. Once a tax deed is issued it conveys the former owner''s interest, and after 2 years from the sale the former owner can no longer even bring an action challenging the conveyance.','{"late_penalty_pct":5,"late_interest_pct_per_year":12,"redemption_period_months":0,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Penalty = 1%/month capped at 5% of delinquent taxes (min $5; 50% or $50 if fraud). Interest = 1%/month from the 30th day after due. No post-sale redemption window; the cure right is the 3-year pre-sale period (pay or enter installment agreement by 5pm the day before sale). Tax deed conveys title; after 2 years from sale the former owner is barred from challenging the conveyance (\u00a7 7-38-70(C))."}'::jsonb,'NMSA 1978, §§ 7-38-49, 7-38-50(A), 7-38-65(A), 7-38-70(B)-(C)','https://realfile.tax.newmexico.gov/Property%20Tax%20Code.pdf','2026-06-14',2026),
  ('NV','state','assessment_appeal',NULL,'A taxpayer protesting a county-assessor valuation appears before the County Board of Equalization; for property placed on the unsecured tax roll (assessed May 1 to December 15), the appeal must be filed on or before the following January 15 (next business day if Jan 15 is a weekend/holiday). A County Board decision may then be appealed to the State Board of Equalization on or before March 10.','{"deadline_kind":"fixed_date","deadline_month":1,"deadline_day":15,"deadline_desc":"Unsecured-roll protest to the County Board of Equalization due on or before January 15 (next business day if Jan 15 falls on a Saturday, Sunday or holiday). Further appeal to the State Board of Equalization due on or before March 10 (NRS 361.360).","review_body":"County Board of Equalization (county-level), with appeal to the State Board of Equalization","locally_variable":false}'::jsonb,'Nev. Rev. Stat. (NRS) 361.355(2); see also NRS 361.360(1)','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec355','2026-06-14',2026),
  ('NV','state','payment',NULL,'Real-property taxes are due on the third Monday of August. If the tax on a parcel exceeds $100 it may be paid in four approximately equal installments due the third Monday of August, the first Monday of October, the first Monday of January, and the first Monday of March. A 10-day grace follows each installment before a late penalty attaches (4% on a missed first installment, escalating with each additional missed installment).','{"installments":[{"label":"1st installment (third Monday of August)","due_month":8,"due_day":null},{"label":"2nd installment (first Monday of October)","due_month":10,"due_day":null},{"label":"3rd installment (first Monday of January)","due_month":1,"due_day":null},{"label":"4th installment (first Monday of March)","due_month":3,"due_day":null}],"delinquent_after_desc":"A penalty attaches if an installment is not paid within 10 days following its due date; 4% on a single missed installment, escalating to 5%/6%/7% as additional installments go unpaid.","grace_days":10,"locally_variable":false}'::jsonb,'Nev. Rev. Stat. (NRS) 361.483','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec483','2026-06-14',2026),
  ('NV','state','delinquency_redemption',NULL,'If delinquent real-property taxes are not paid, on the first Monday in June the county tax receiver issues a certificate to the county treasurer (as trustee for the State and county) to hold the property. The property is subject to redemption within 2 years (1 year if determined abandoned) after issuance of the certificate, by paying the taxes, penalties and costs plus interest at 10 percent per annum, assessed monthly. After the redemption period expires with no redemption, a deed is delivered to the county treasurer as trustee.','{"late_penalty_pct":null,"late_interest_pct_per_year":10,"redemption_period_months":24,"tax_sale_kind":"hybrid","locally_variable":false}'::jsonb,'Nev. Rev. Stat. (NRS) 361.5648(2)(d); see also NRS 361.585','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec5648','2026-06-14',2026),
  ('NV','state','exemption','veteran','A qualifying wartime/qualifying-service veteran who is a bona fide Nevada resident and received an honorable discharge is exempt from taxation to the extent of $2,000 of assessed valuation (statutory base figure; NRS 361.155 provides for annual CPI adjustment of exemption amounts). Claimed by affidavit filed with the county assessor.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":2000,"benefit_unit":"usd","locally_variable":false,"notes":"$2,000 is the statutory base of assessed (not full cash) value; the actual dollar amount is adjusted annually for CPI under NRS 361.090(8), so the effective figure exceeds the base. Requires bona fide NV residency, qualifying period of active duty (or qualifying campaign/expedition medal), and honorable discharge."}'::jsonb,'Nev. Rev. Stat. (NRS) 361.090(1)','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec090','2026-06-14',2026),
  ('NV','state','exemption','disabled_veteran','A bona fide Nevada resident veteran with a permanent service-connected disability (honorably discharged), or the surviving spouse of such a veteran, is entitled to a graduated exemption: up to $20,000 assessed value for total permanent disability, $15,000 for 80-99% disability, and $10,000 for 60-79% disability (statutory base figures; CPI-adjusted annually under NRS 361.091).','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":20000,"benefit_unit":"usd","locally_variable":false,"notes":"Graduated by disability rating against assessed valuation: $20,000 base for total permanent disability; $15,000 for 80-99%; $10,000 for 60-79%. Statutory base figures, adjusted annually for CPI under NRS 361.091(10). Extends to the surviving spouse of a qualifying disabled veteran (NRS 361.091(1),(6))."}'::jsonb,'Nev. Rev. Stat. (NRS) 361.091(2)','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec091','2026-06-14',2026),
  ('NV','state','exemption','other','Nevada surviving-spouse exemption: the property of a surviving spouse who is a bona fide Nevada resident is exempt from taxation to the extent of $1,000 of assessed valuation (statutory base; CPI-adjusted annually under NRS 361.080(6)). Allowed in only one county per family; forfeited in any fiscal year beginning after remarriage.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":1000,"benefit_unit":"usd","locally_variable":false,"notes":"Surviving-spouse exemption (not a senior/age-based exemption). $1,000 statutory base of assessed value, CPI-adjusted annually under NRS 361.080(6). Requires bona fide NV residency; allowed in only one county to the same family; lost in any fiscal year beginning after remarriage (NRS 361.080(4)). Nevada NRS Chapter 361 has no general homestead or senior-65+ property-tax exemption among its owner-personal exemptions; the main owner exemptions are veteran, disabled-veteran, surviving-spouse, and blind."}'::jsonb,'Nev. Rev. Stat. (NRS) 361.080(1)','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec080','2026-06-14',2026),
  ('NV','state','exemption','disability','Nevada blind-persons exemption: the property of a person who is blind and a bona fide Nevada resident is exempt from taxation to the extent of $3,000 of assessed valuation (statutory base; CPI-adjusted annually under NRS 361.085(5)). Requires a licensed physician''s certificate of blindness on first claim; allowed in only one county per person.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":3000,"benefit_unit":"usd","locally_variable":false,"notes":"Exemption for persons who are blind (a disability exemption, not age-based). $3,000 statutory base of assessed value, CPI-adjusted annually under NRS 361.085(5). Requires bona fide NV residency and, on first claim, a licensed physician''s certificate of blindness (NRS 361.085(3)); allowed in only one county per person."}'::jsonb,'Nev. Rev. Stat. (NRS) 361.085(1)','https://www.leg.state.nv.us/NRS/NRS-361.html#NRS361Sec085','2026-06-14',2026),
  ('OH','state','assessment_appeal',NULL,'A complaint contesting a parcel''s valuation/assessment must be filed with the county auditor on or before March 31 of the ensuing tax year (or the close of first-half collection, whichever is later); the county Board of Revision hears it. A Board of Revision decision may then be appealed to the state Board of Tax Appeals within 30 days of the mailed notice.','{"deadline_kind":"fixed_date","deadline_month":3,"deadline_day":31,"deadline_desc":"On or before March 31 of the ensuing tax year, or the date of closing of first-half real-property tax collection for the current year, whichever is later. Onward appeal to Board of Tax Appeals within 30 days of mailed Board of Revision decision (ORC 5717.01).","review_body":"County Board of Revision (first level); Ohio Board of Tax Appeals (appeal level)","locally_variable":false}'::jsonb,'Ohio Rev. Code § 5715.19(A)(1); § 5717.01','https://codes.ohio.gov/ohio-revised-code/section-5715.19','2026-06-14',2026),
  ('OH','state','assessment',NULL,'The state tax commissioner directs and supervises assessment of all real property to true value under uniform rules; taxable value is computed by applying an assessment percentage set by the commissioner, not to exceed 35 percent of true value. Actual reappraisal is administered by county auditors on a county-by-county cycle.','{"assessment_ratio_pct":35,"market_value_standard":"true value in money","locally_variable":true}'::jsonb,'Ohio Rev. Code § 5715.01(A); § 323.152(A)(1)(c)(ii)','https://codes.ohio.gov/ohio-revised-code/section-5715.01','2026-06-14',2026),
  ('OH','state','exemption','senior','Homestead exemption for owner-occupants age 65 or older (or qualifying surviving spouses): shields $25,000 of the true value of the homestead from taxation, subject to a total-income limit of $30,000 (annually adjusted by the GDP deflator and certified by the tax commissioner). Applied for with the county auditor.','{"age_min":65,"income_max":30000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":25000,"benefit_unit":"usd","locally_variable":false,"notes":"Income threshold ($30,000 base) is adjusted annually by the GDP deflator and certified to county auditors. ''Sixty-five years of age or older'' means having attained age 64 prior to Jan 1 of the application year. $25,000 is the exempted true-value amount; the dollar tax reduction = $25,000 x assessment % (<=35%) x effective tax rate. Income = modified adjusted gross income of owner and spouse for the preceding year."}'::jsonb,'Ohio Rev. Code § 323.152(A)(1); § 323.151(B),(C)','https://codes.ohio.gov/ohio-revised-code/section-323.152','2026-06-14',2026),
  ('OH','state','exemption','disability','Homestead exemption for owner-occupants who are permanently and totally disabled: shields $25,000 of the true value of the homestead, subject to the same $30,000 total-income limit as the senior exemption. Requires a physician/agency disability certification filed with the county auditor.','{"income_max":30000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":25000,"benefit_unit":"usd","locally_variable":false,"notes":"''Permanently and totally disabled'' = impairment making the person unable to work at substantially remunerative employment for at least 12 months, or certification as permanently/totally disabled by a state/federal agency. Same $25,000 true-value exemption and $30,000 GDP-deflator-adjusted income cap as the age-65+ track. Application requires a signed physician/psychologist certificate or agency certificate."}'::jsonb,'Ohio Rev. Code § 323.152(A)(1); § 323.151(D); § 323.153(A)(1)','https://codes.ohio.gov/ohio-revised-code/section-323.152','2026-06-14',2026),
  ('OH','state','exemption','disabled_veteran','Enhanced homestead exemption for disabled veterans (total VA disability rating, or total rating based on individual unemployability, for a service-connected disability): shields $50,000 of the true value of the homestead, with no income limit. Application must include written confirmation from the U.S. Department of Veterans Affairs.','{"income_max":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":50000,"benefit_unit":"usd","locally_variable":false,"notes":"''Disabled veteran'' = honorably discharged/released veteran with a total disability rating (or total rating for compensation based on individual unemployability) for service-connected disability per 38 CFR Part 4. No total-income test (unlike the age-65+/disability tracks). $50,000 true-value exemption, in lieu of the standard $25,000 reduction. Applies to only one homestead. $50,000 base amount is also GDP-deflator adjusted. Application requires VA confirmation letter."}'::jsonb,'Ohio Rev. Code § 323.152(A)(2)(a); § 323.151(F); § 323.153(A)(1)','https://codes.ohio.gov/ohio-revised-code/section-323.152','2026-06-14',2026),
  ('OH','state','payment',NULL,'Real property taxes are payable to the county treasurer in two installments: the full amount (or one-half plus all delinquent taxes) by December 31, and the remaining half by June 20 of the next year. A 10 percent penalty is charged on each installment unpaid by its deadline; interest then accrues on delinquent balances at the state-prescribed rate. Exact collection-period closing dates are administered locally by the county treasurer.','{"installments":[{"label":"First half (or full amount)","due_month":12,"due_day":31},{"label":"Second half","due_month":6,"due_day":20}],"delinquent_after_desc":"First-half taxes are delinquent if one-half of current taxes plus all delinquent taxes are not paid by Dec 31; second-half/total taxes are delinquent if not paid by the following June 20. County treasurers may set/extend exact closing dates per ORC 323.17.","grace_days":0,"locally_variable":true}'::jsonb,'Ohio Rev. Code § 323.12(A); § 323.121(A)(1)','https://codes.ohio.gov/ohio-revised-code/section-323.12','2026-06-14',2026),
  ('OH','state','delinquency_redemption',NULL,'Ohio uses both tax-lien certificate sales and direct tax foreclosure (a hybrid). Delinquent land may be redeemed by paying all taxes, assessments, penalties, interest, and charges any time before foreclosure is instituted, and afterward up until an entry of confirmation of sale is filed (or expiration of an alternative redemption period). Where a tax certificate was sold, redemption requires paying the certificate redemption price plus interest accruing at 18 percent per year.','{"late_penalty_pct":10,"late_interest_pct_per_year":18,"redemption_period_months":null,"tax_sale_kind":"hybrid","locally_variable":true,"notes":"10% penalty per unpaid installment (ORC 323.121). Redemption is not a fixed post-sale window: delinquent land may be redeemed before foreclosure proceedings begin, and after they begin up until the entry of confirmation of sale is filed (or expiration of an alternative redemption period under ORC 323.78/323.65). For tax-certificate parcels, the redeemer pays the certificate redemption price plus 18%/yr interest on the certificate purchase price (ORC 5721.38(B)(2)); a redemption payment plan up to one year from certificate sale is available (5721.38(C)). Certificate-system interest is simple interest (5721.41). The general delinquent-tax interest rate on unpaid taxes is set per ORC 5703.47 (varies by year)."}'::jsonb,'Ohio Rev. Code § 5721.25; § 5721.38(B)(2); § 5721.41','https://codes.ohio.gov/ohio-revised-code/section-5721.38','2026-06-14',2026),
  ('OK','state','exemption','homestead','Every homestead is exempt from ad valorem taxation to the extent of $1,000 of assessed valuation.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":1000,"benefit_unit":"usd","locally_variable":false,"notes":"Applies to assessed valuation (not fair cash value). Homestead defined in 68 O.S. \u00a7 2888."}'::jsonb,'68 O.S. § 2889','https://oksenate.gov/sites/default/files/2019-12/os68.pdf','2026-06-14',2026),
  ('OK','state','exemption','senior_valuation_freeze','Senior valuation limitation: homestead fair-cash-value freeze for qualifying owners under Okla. Const. Art. X § 8C; application due by March 15.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","locally_variable":false,"notes":"Limits (freezes) the fair cash value of the homestead under Article X, Section 8C of the Oklahoma Constitution. Qualification age (65+) and the gross-household-income ceiling are set by the constitutional provision (\u00a7 8C). Application on or before March 15, or within 30 days of a notice of valuation increase, whichever is later. No annual reapplication once qualified. Gross household income defined per 68 O.S. \u00a7 2890."}'::jsonb,'68 O.S. § 2890.1; Okla. Const. art. X, § 8C','https://oksenate.gov/sites/default/files/2019-12/os68.pdf','2026-06-14',2026),
  ('OK','state','exemption','senior_relief_credit','Property tax relief credit for heads of household 65+ or totally disabled with gross household income not exceeding $12,000; credit equals taxes paid exceeding 1% of household income, capped at $200.','{"age_min":65,"income_max":12000,"income_unit":"usd_per_year","ownership_required":false,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":200,"benefit_unit":"usd","locally_variable":false,"notes":"Also available to any totally disabled head of household (no age minimum for the disability path). Relief is the amount of property taxes paid exceeding 1% of gross household income, not to exceed $200. Claimant must have been an Oklahoma resident/domiciled the entire preceding calendar year. Administered by the Oklahoma Tax Commission; taken as an income tax credit. One claim per household per year."}'::jsonb,'68 O.S. §§ 2905-2907','https://oksenate.gov/sites/default/files/2019-12/os68.pdf','2026-06-14',2026),
  ('OK','state','exemption','disabled_veteran','Head of household certified by the U.S. Dept. of Veterans Affairs with a 100% permanent service-connected disability (and the surviving spouse) is exempt on the full fair cash value of the homestead.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Exemption is for the FULL fair cash value of the homestead (effectively 100% of taxable value). Requires honorable discharge and USDVA certification of 100% permanent disability sustained through military action/accident or service-contracted disease, or receipt of compensation at the 100% rate. Surviving spouse of qualifying veteran also eligible. Must own and occupy the homestead as residence on January 1. Apply via OTC Form 998. Authorized by Okla. Const. art. X, \u00a7 8E."}'::jsonb,'Okla. Const. art. X, § 8E (OTC Form 998)','https://oklahoma.gov/tax/individuals/exemptions.html','2026-06-14',2026),
  ('OK','state','payment',NULL,'Ad valorem taxes become due November 1. Full payment or first half is due before January 1; if at least half is paid the remainder is due before April 1. Delinquent taxes accrue 1.5% interest per month.','{"installments":[{"label":"First half (or full)","due_month":12,"due_day":31},{"label":"Second half","due_month":3,"due_day":31}],"delinquent_after_desc":"Taxes become due Nov 1. If less than one-half is paid before Jan 1, the entire levy becomes delinquent Jan 1. If the first half (or more) is paid before Jan 1, the remainder must be paid before Apr 1 or becomes delinquent on that date. Bills of $25.00 or less must be paid in full before Jan 1.","locally_variable":false,"notes":"Delinquent taxes bear interest at 1.5% per month (or major fraction), capped at 100% of the unpaid tax. Statewide statutory schedule (not locally set)."}'::jsonb,'68 O.S. § 2913','https://oksenate.gov/sites/default/files/2019-12/os68.pdf','2026-06-14',2026),
  ('OR','state','payment',NULL,'Oregon property tax is paid in three equal installments due November 15, February 15, and May 15. A 3% discount is allowed if the full amount is paid on or before November 15 (2% on two-thirds if two-thirds paid by Nov 15). Interest accrues at 1 and 1/3 percent per month on unpaid installments (interest dates Dec 15, Feb 15, May 15). The state sets these statewide dates; the county tax collector administers billing. (No installment option allowed if total property tax is under $40.)','{"installments":[{"label":"First one-third","due_month":11,"due_day":15},{"label":"Second one-third","due_month":2,"due_day":15},{"label":"Final one-third","due_month":5,"due_day":15}],"delinquent_after_desc":"Interest accrues at 1 and 1/3 percent per month on any installment not paid by its interest date: Dec 15 (first one-third), Feb 15 (second one-third), May 15 (final one-third)","grace_days":0,"locally_variable":false}'::jsonb,'ORS 311.505','https://www.oregonlegislature.gov/bills_laws/ors/ors311.html','2026-06-14',2026),
  ('OR','state','assessment_appeal',NULL,'A property owner (or a person who holds an interest in the property that obligates them to pay the tax) may petition the county Property Value Appeals Board for relief. Petitions are filed with the clerk of the board during the period beginning when tax statements are mailed or otherwise delivered for the current tax year and ending December 31.','{"deadline_kind":"fixed_date","deadline_month":12,"deadline_day":31,"deadline_desc":"Filed from the date current-year tax statements are mailed or otherwise delivered through December 31","review_body":"Property Value Appeals Board (county)","locally_variable":false}'::jsonb,'ORS 309.100','https://www.oregonlegislature.gov/bills_laws/ors/ors309.html','2026-06-14',2026),
  ('OR','state','exemption','disabled_veteran','Disabled veterans certified at 40% or more disability (and certain surviving unmarried spouses) receive an exemption of a fixed dollar amount of the assessed value of the homestead or personal property. The statutory base amounts are $15,000 (40%+ disability; the physician-certified path is income-limited to gross income no more than 185% of federal poverty guidelines) and $18,000 (service-connected 40%+ disability). The exemption amount increases each year to equal 103% of the prior tax year''s amount, so live figures exceed the statutory base.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":18000,"benefit_unit":"usd","income_max":null,"income_unit":"usd_per_year","locally_variable":false,"notes":"Statutory base amounts: $15,000 for 40%+ disability (the physician-certified path under subsection (2)(b) requires prior-year total gross income no more than 185% of federal poverty guidelines); $18,000 for service-connected 40%+ disability. Exemption amount equals 103% of prior tax year''s amount, so live indexed figures are higher than the statutory base. Surviving unmarried spouse of a qualifying veteran may also claim. The specific current-year indexed dollar amount is set by annual indexing and is not stated in the statute text."}'::jsonb,'ORS 307.250','https://www.oregonlegislature.gov/bills_laws/ors/ors307.html','2026-06-14',2026),
  ('OR','state','exemption','senior','Oregon''s Senior and Disabled Property Tax Deferral program lets homeowners age 62+ (or a person with a disability) defer payment of property taxes on their homestead. This is a deferral, not a permanent reduction: the state pays the taxes, records a lien, and the deferred amount is repaid later with interest. Deferral may not be granted if filers together have household income of $70,000 or more or net worth of $500,000 or more. The income threshold is CPI-recomputed for tax years beginning on or after July 1, 2027. The claim is filed with the county assessor after January 1 and on or before April 15 (late filing allowed through December 1 with a fee).','{"age_min":62,"income_max":70000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","benefit_value":null,"benefit_unit":null,"locally_variable":false,"notes":"DEFERRAL (state pays tax, lien recorded, repaid with interest) \u2014 NOT an exemption or value reduction; benefit_kind ''assessment_freeze'' is an approximation of the deferral mechanism. Age 62+ on or before April 15, OR a person with a disability as of April 15 regardless of age. Deferral barred if household income >= $70,000 or net worth >= $500,000. Income limit CPI-recomputed (rounded to nearest $500) for tax years beginning on or after July 1, 2027. Claim filed with county assessor after January 1 and on or before April 15; late filing allowed through December 1 with a fee equal to 10% of prior-year taxes (min $20, max $150, CPI-indexed)."}'::jsonb,'ORS 311.668; ORS 311.672','https://www.oregonlegislature.gov/bills_laws/ors/ors311.html','2026-06-14',2026),
  ('OR','state','delinquency_redemption',NULL,'Real property is subject to tax foreclosure once three years have elapsed from the earliest date of delinquency. After a foreclosure judgment the property is sold to the county and held for a two-year redemption period, during which an interested party may redeem by paying the full judgment amount plus interest as provided by law, a 5% penalty, and a fee. The judgment bears interest at the legal rate from the date of entry. If unredeemed, the property is deeded to the county (tax-deed system).','{"late_penalty_pct":5,"late_interest_pct_per_year":null,"redemption_period_months":24,"tax_sale_kind":"tax_deed","locally_variable":false}'::jsonb,'ORS 312.010; ORS 312.120; ORS 312.090','https://www.oregonlegislature.gov/bills_laws/ors/ors312.html','2026-06-14',2026),
  ('PA','state','assessment_appeal',NULL,'Annual property assessment appeals are filed with the county Board of Assessment Appeals on or before September 1 (the county commissioners may set an earlier date, no earlier than August 1). The same procedures/deadlines apply to exemption requests. A board decision may be appealed to the court of common pleas within 30 days of the mailing date.','{"deadline_kind":"fixed_date","deadline_month":9,"deadline_day":1,"deadline_desc":"On or before September 1 to the county Board of Assessment Appeals; county commissioners may designate an earlier date no earlier than August 1. Court-of-common-pleas appeal of the board decision is within 30 days of the mailing date of the decision.","review_body":"County Board of Assessment Appeals (then court of common pleas on further appeal)","locally_variable":true}'::jsonb,'53 Pa.C.S. § 8844(c) (Consolidated County Assessment Law); appeal-to-court window per § 8844(e)(2.1)(i)','gam DB: state_law_section_texts WHERE state_code=''PA'' AND law_category=''property_tax'' AND section_number=''8844''','2026-06-14',2026),
  ('PA','state','assessment',NULL,'Counties assess real property at a value based on an established predetermined ratio (EPR), which may not exceed 100% of actual value; the ratio is set by the county board of commissioners by ordinance. Counties may use current market value or adopt a base-year market value. The ratio and reassessment cycle are county-determined (no statewide reassessment cycle).','{"assessment_ratio_pct":100,"market_value_standard":"actual value (current market value or county-adopted base-year market value); EPR may not exceed 100% of actual value","reassessment_cycle_years":null,"locally_variable":true}'::jsonb,'53 Pa.C.S. § 8842(a) (Consolidated County Assessment Law)','gam DB: state_law_section_texts WHERE state_code=''PA'' AND law_category=''property_tax'' AND section_number=''8842''','2026-06-14',2026),
  ('PA','state','exemption','homestead','Homestead/farmstead exclusion under the Taxpayer Relief Act reduces the taxable assessed value of an owner-occupied primary residence. The exclusion is locally adopted; a political subdivision may not authorize an exclusion exceeding one-half (50%) of the median assessed value of homestead property. Owners must file a homestead application with the assessor not later than March 1 (December 1 of the prior year in cities of the first class).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":50,"benefit_unit":"pct","locally_variable":true,"notes":"Benefit is a reduction in taxable assessed value (uniform dollar amount per homestead in the jurisdiction); statutory ceiling is 50% of the median assessed value of homestead property in the political subdivision. Application deadline March 1 (Dec 1 prior year for cities of the first class). Only a primary residence / domicile of a natural-person owner qualifies."}'::jsonb,'53 Pa.C.S. §§ 8584(b), 8586(a)(1) (Title 53, Ch. 85 — Taxpayer Relief Act, Act 1 of Special Session 1 of 2006)','https://www.legis.state.pa.us/WU01/LI/LI/CT/HTM/53/00.085..HTM','2026-06-14',2026),
  ('PA','state','exemption','senior','The Property Tax/Rent Rebate (PTRR) program provides a rebate of property taxes (or rent) paid, for Pennsylvanians age 65+, widows/widowers age 50+, and people with disabilities age 18+. Maximum income limit for rebate applicants is $48,110/year (income limits are indexed to cost of living). Maximum standard rebate is $1,000; certain applicants qualify for supplemental rebates up to $500 (total max $1,500).','{"age_min":65,"income_max":48110,"income_unit":"usd_per_year","ownership_required":false,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1000,"benefit_unit":"usd","locally_variable":false,"notes":"State-administered rebate (not a local assessment exemption); covers homeowners and renters. Age tiers: 65+; widows/widowers 50+; people with disabilities 18+. Maximum standard rebate $1,000; supplemental rebates up to $500 (total max $1,500) for property taxes exceeding 15% of income or residence in Philadelphia/Scranton/Pittsburgh. Income limit $48,110 verified against the PA.gov PTRR page as of June 2026; figures change annually with COLA indexing \u2014 annual refresh required."}'::jsonb,'Senior Citizens Property Tax and Rent Rebate Assistance Act (act of March 11, 1971, P.L. 104, No. 3); administered by PA Department of Revenue','https://www.pa.gov/agencies/revenue/ptrr','2026-06-14',2026),
  ('PA','state','exemption','other','Institutional/use-based real estate exemptions: churches and places of regularly stated religious worship, burial grounds, purely public charities (hospitals, universities, colleges), public property used for public purposes, public libraries/museums, and certain veterans''-organization-owned property are exempt from county/municipal/school real estate taxes. These are use/ownership exemptions, not owner-homestead exemptions; an exemption request follows the same procedures and deadlines as an assessment appeal (filed with the board by September 1).','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Full exemption from real estate taxes for qualifying religious, charitable, educational, public, library/museum, and veterans''-organization property. Read in pari materia with the Institutions of Purely Public Charity Act (Act 55 of 1997). Not an individual owner-occupant exemption. Exemption requests use the \u00a7 8844(c) appeal procedure/deadline."}'::jsonb,'53 Pa.C.S. § 8812(a) (Consolidated County Assessment Law — Exemptions from taxation); exemption-request procedure per § 8844(c)(2)','gam DB: state_law_section_texts WHERE state_code=''PA'' AND law_category=''property_tax'' AND section_number=''8812''','2026-06-14',2026),
  ('PA','state','payment',NULL,'Real estate tax due dates, discounts, and penalties are set by the taxing district. Statewide framework: at least a 2% discount if the full amount is paid within two months of the tax notice; up to a 10% penalty if not paid within four months of the tax notice; taxes become delinquent after December 31 (and are then returned to the county tax claim bureau). Taxing districts may permit payment in up to four installments by ordinance/resolution (no discount on installments).','{"installments":[],"delinquent_after_desc":"Delinquent after December 31 of the year levied (then returned to the county tax claim bureau between January 1 and the county return date, no later than the last day of April). Specific due dates, discount/penalty rates, and any installment schedule are set locally by each taxing district.","grace_days":null,"locally_variable":true}'::jsonb,'72 P.S. § 5511.10 (Local Tax Collection Law § 10 — Discounts; Penalties); § 5511.11 (§ 11 — Installment Payment of Taxes); return date per 72 P.S. § 5860.306 (RETSL § 306)','gam DB: state_law_section_texts WHERE state_code=''PA'' AND law_category=''property_tax'' AND section_number IN (''10'',''11'',''306'')','2026-06-14',2026),
  ('PA','state','delinquency_redemption',NULL,'Under the Real Estate Tax Sale Law (RETSL — the general statute for most counties), there is NO redemption after the actual (upset) tax sale: title passes to the purchaser (tax-deed/upset-sale state). The owner''s only cure is to discharge the claim before the sale by paying all delinquent taxes, interest, penalties, and costs. Returned delinquent taxes bear simple interest at 9% per annum. The upset sale is scheduled no earlier than the second Monday of September and before October 1. (Note: cities/counties under the Municipal Claims and Tax Liens Act have a separate post-sale redemption period; RETSL counties do not.)','{"late_penalty_pct":10,"late_interest_pct_per_year":9,"redemption_period_months":0,"tax_sale_kind":"tax_deed","locally_variable":true,"notes":"RETSL: no redemption after the actual sale (\u00a7 501(c)). Pre-sale discharge is available up to the actual sale (\u00a7 501(a)). 9% per annum simple interest on returned delinquent taxes (\u00a7 306(a)). Upset sale date: no earlier than the second Monday of September and before October 1 (\u00a7 601(a)). The 10% late penalty figure cross-references the Local Tax Collection Law \u00a7 10 ''up to ten per centum'' penalty (pre-delinquency). Separate Municipal Claims and Tax Liens Act (53 P.S. \u00a7 7101 et seq.) governs first/second-class cities and provides a different (post-sale, ~9-month) redemption \u2014 locally variable by which statute applies."}'::jsonb,'72 P.S. §§ 5860.501(c), 5860.306(a), 5860.601(a) (Real Estate Tax Sale Law, Act 542 of 1947); 10% pre-delinquency penalty per 72 P.S. § 5511.10(a) (Local Tax Collection Law)','gam DB: state_law_section_texts WHERE state_code=''PA'' AND law_category=''property_tax'' AND section_number IN (''501'',''306'',''601'')','2026-06-14',2026),
  ('RI','state','assessment',NULL,'Rhode Island property is assessed at full and fair cash value as of December 31 (12:00 A.M. midnight) each year, which is the statutory date of assessment. Municipalities must conduct a full revaluation within 9 years of the prior revaluation and a statistical update of real property every 3 years from the last revaluation. Assessment ratio is effectively 100% of fair cash value; actual assessed values and any town-level wrinkles are set locally.','{"assessment_ratio_pct":100,"market_value_standard":"full and fair cash value","reassessment_cycle_years":9,"update_cycle_years":3,"assessment_date_month":12,"assessment_date_day":31,"locally_variable":true}'::jsonb,'R.I. Gen. Laws §§ 44-5-1, 44-5-12, 44-5-11.6','https://webserver.rilegislature.gov/Statutes/TITLE44/44-5/INDEX.htm','2026-06-14',2026),
  ('RI','state','assessment_appeal',NULL,'A person aggrieved by an assessment may file an appeal in the local office of tax assessment on or before November 15 of each year, but not less than 90 days after the first tax payment is due. The assessor has until December 31 to decide. If still aggrieved (or if the assessor does not decide by December 31, but not before 45 days after filing), the taxpayer may appeal to the local tax board of review within 30 days of the assessor''s decision (or by January 31 if no decision by December 31). A further petition to Superior Court is available within 30 days of the board''s written decision and notice thereof.','{"deadline_kind":"fixed_date","deadline_month":11,"deadline_day":15,"deadline_desc":"File with local office of tax assessment on or before November 15, but not less than 90 days after the first tax payment is due; then local tax board of review within 30 days of assessor decision (or by January 31 if no decision by December 31); then Superior Court within 30 days of board''s written decision and notice.","review_body":"Local office of tax assessment, then local tax board of review, then Superior Court","locally_variable":false}'::jsonb,'R.I. Gen. Laws § 44-5-26','https://webserver.rilegislature.gov/Statutes/TITLE44/44-5/44-5-26.htm','2026-06-14',2026),
  ('RI','state','payment',NULL,'Every city and town must offer the option to pay property tax in equal quarterly installments free of interest if paid on time; the specific amounts and due dates are set in the municipality''s tax-levy resolution (locally variable). If any installment is not paid by the last day of its installment period, the whole unpaid balance becomes due and carries a penalty set by the municipality at not less than 6% nor more than 18% per annum (Cranston capped at 12%). A municipality may instead choose to require payment of only the late installment with interest on that installment.','{"installments":[],"installment_count_default":4,"installment_frequency":"quarterly","delinquent_after_desc":"Unpaid installment after the last day of its installment period accelerates the whole remaining balance, with penalty 6%-18% per annum (Cranston max 12%); specific installment due dates set locally.","grace_days":null,"locally_variable":true}'::jsonb,'R.I. Gen. Laws §§ 44-5-7, 44-5-8','https://webserver.rilegislature.gov/Statutes/TITLE44/44-5/44-5-7.htm','2026-06-14',2026),
  ('RI','state','delinquency_redemption',NULL,'Rhode Island uses a tax-deed-subject-to-redemption (hybrid) system: at a tax sale the collector delivers a deed to the purchaser that conveys the land subject to the right of redemption. Anyone with an interest in the land may redeem at any time before a foreclosure petition is filed. The redemption penalty is 10% of the purchase price if redeemed within 6 months of the collector''s sale, plus an additional 1% of the purchase price for each succeeding month, together with intervening taxes paid plus interest at 1% per month. A purchaser/holder may petition Superior Court to foreclose the right of redemption only after one year from the sale.','{"late_penalty_pct":10,"late_penalty_window_months":6,"late_penalty_additional_pct_per_month":1,"late_interest_pct_per_year":12,"redemption_period_months":12,"tax_sale_kind":"hybrid","locally_variable":false}'::jsonb,'R.I. Gen. Laws §§ 44-9-12, 44-9-19, 44-9-25','https://webserver.rilegislature.gov/Statutes/TITLE44/44-9/INDEX.htm','2026-06-14',2026),
  ('RI','state','exemption','veteran','Rhode Island grants a statewide veterans'' property-tax exemption with a baseline exempt value of $1,000 for qualifying honorably-discharged (or other-than-dishonorable) wartime/conflict veterans, and for the unmarried widow/widower of such a veteran. The actual exemption amount is heavily overridden upward by individual cities and towns (e.g., Burrillville $4,000, Cranston up to $3,000, Lincoln up to $10,000, Cumberland up to $23,772 by ordinance), so the benefit value is locally variable above the $1,000 floor.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":1000,"benefit_unit":"usd","locally_variable":true,"notes":"Statewide baseline $1,000 exempt value; many municipalities set much higher amounts by ordinance. Qualifying service periods and unmarried surviving spouse covered."}'::jsonb,'R.I. Gen. Laws § 44-3-4','https://webserver.rilegislature.gov/Statutes/TITLE44/44-3/44-3-4.htm','2026-06-14',2026),
  ('RI','state','exemption','senior','Rhode Island''s age-65+ owner exemption is a local-option program: individual cities and towns may, by ordinance, exempt real estate owned and occupied by residents over age 65 (measured as of the preceding December 31), with each municipality setting its own exemption value (e.g., Central Falls up to $7,500, Cranston up to $9,000). There is no statewide fixed dollar amount; the age-65 threshold is the common statutory element and the benefit value is locally variable.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":null,"benefit_unit":"usd","locally_variable":true,"notes":"Local-option exemption enabled per city/town by ordinance; each municipality sets eligibility age (commonly 65, some 70/75 tiers) and the exempt amount. Age measured as of preceding December 31."}'::jsonb,'R.I. Gen. Laws § 44-3-13','https://webserver.rilegislature.gov/Statutes/TITLE44/44-3/44-3-13.htm','2026-06-14',2026),
  ('RI','state','exemption','disability','Rhode Island''s exemption for totally (100%) disabled owners is a local-option program: city or town councils may, by ordinance, provide for a freeze of the tax rate and valuation (or, in some towns, a fixed exempt dollar amount such as Warren''s $20,480) on property of a head of household who is 100% disabled and unable to work. Eligibility (e.g., SSA/VA disability determination, income limits in some towns) and the benefit are set locally and vary by municipality.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","benefit_value":null,"benefit_unit":"usd","locally_variable":true,"notes":"100% disabled, unable to work, head of household. Local-option; some towns freeze rate/valuation, others grant a fixed exempt amount (e.g., Warren $20,480). Eligibility criteria set by local ordinance."}'::jsonb,'R.I. Gen. Laws § 44-3-15','https://webserver.rilegislature.gov/Statutes/TITLE44/44-3/44-3-15.htm','2026-06-14',2026),
  ('RI','state','exemption','blind','Rhode Island grants a statewide exemption for legally blind / visually impaired persons of $6,000 of assessed value (certified by a licensed physician or by RI Services for the Blind and Visually Impaired). A handful of towns are carved out with different amounts, so the floor is statewide $6,000 with local variation in the exceptions.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":6000,"benefit_unit":"usd","locally_variable":true,"notes":"Statewide baseline $6,000 exempt value for the legally blind; certain towns excepted with different amounts. Subtype recorded as disability (blindness)."}'::jsonb,'R.I. Gen. Laws § 44-3-12','https://webserver.rilegislature.gov/Statutes/TITLE44/44-3/44-3-12.htm','2026-06-14',2026),
  ('RI','state','exemption','circuit_breaker','Rhode Island provides a statewide income-based Property Tax Relief Credit (claimed on form RI-1040H) for homeowners and renters who are age 65 or older and/or disabled and domiciled in RI for the full calendar year. The credit equals property taxes accrued (or 20% of gross rent, for renters) exceeding a percentage of household income, capped at a maximum credit of $600 for tax years beginning on or after January 1, 2022 (CPI-adjusted annually beginning 2023). Claims must be filed with the Division of Taxation on or before April 15 of the year the credit is applied.','{"age_min":65,"income_max":null,"income_unit":"usd_per_year","ownership_required":false,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":600,"benefit_unit":"usd","filing_deadline_month":4,"filing_deadline_day":15,"locally_variable":false,"notes":"Statewide credit (RI-1040H). Eligible if 65+ OR disabled. Max credit $600 for tax years 2022+, CPI-adjusted from 2023. Household-income ceiling set in the statutory table in 44-33-9 and also CPI-adjusted annually; the specific income cap figure is not reproduced verbatim in the retrieved statute text, so income_max left null rather than guessed. Renters compute property taxes accrued as 20% of gross rent."}'::jsonb,'R.I. Gen. Laws §§ 44-33-3, 44-33-6, 44-33-9','https://webserver.rilegislature.gov/Statutes/TITLE44/44-33/INDEX.htm','2026-06-14',2026),
  ('SC','state','assessment',NULL,'Owner-occupied legal residence (plus up to 5 contiguous acres) is assessed at 4% of fair market value; most other real property is assessed at 6%. Ratios are set uniformly statewide by statute.','{"assessment_ratio_pct":4,"market_value_standard":"fair_market_value","locally_variable":false,"notes":"4% applies to owner-occupied legal residence (Section 12-43-220(c)); 6% for other real property and inventory (Section 12-43-220(e)/(b)); manufacturers/utilities 10.5% (Section 12-43-220(a)). Ratio is uniform statewide, not locally set."}'::jsonb,'S.C. Code Ann. Section 12-43-220','https://www.scstatehouse.gov/code/t12c043.php','2026-06-14',2026),
  ('SC','state','exemption','senior','Homestead exemption: the first $50,000 of fair market value of the dwelling place is exempt from county, municipal, school, and special assessment real estate property taxes for a person age 65+ (or totally and permanently disabled, or legally blind) who has been a SC resident at least one year and holds fee simple title or a life estate. Application must be made before July 16 of the tax year.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":50000,"benefit_unit":"usd","locally_variable":false,"notes":"Same exemption also available to persons totally and permanently disabled or legally blind regardless of age. Residency: at least one year in SC. Application deadline: before July 16 of the tax year (Section 12-37-250(A)(3))."}'::jsonb,'S.C. Code Ann. Section 12-37-250','https://www.scstatehouse.gov/code/t12c037.php','2026-06-14',2026),
  ('SC','state','exemption','disability','The dwelling house in which a paraplegic or hemiplegic person resides, plus a lot not exceeding one acre owned in fee or for life (or jointly with a spouse), is exempt from all property taxation upon satisfactory proof of disability to the Department of Revenue. Available to a non-remarried surviving spouse who resides in the dwelling.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Applies to paraplegic/hemiplegic owner-residents; dwelling must be the domicile. Surviving spouse keeps exemption if not remarried, resides there, and holds fee or life estate."}'::jsonb,'S.C. Code Ann. Section 12-37-220(B)(2)(a)','https://www.scstatehouse.gov/code/t12c037.php','2026-06-14',2026),
  ('SC','state','assessment_appeal',NULL,'In a year with a property tax assessment notice, the taxpayer must give the county assessor written notice of objection within 90 days after the assessor mails the assessment notice. In years with no notice, the taxpayer may appeal at any time (an appeal filed before the first penalty date applies to that tax year). The county board of assessment appeals is the review body.','{"deadline_kind":"relative_to_roll","deadline_desc":"Written objection within 90 days after the assessor mails the property tax assessment notice","review_body":"County board of assessment appeals (after written objection to and conference with the county assessor)","locally_variable":false}'::jsonb,'S.C. Code Ann. Section 12-60-2510(A)(3); Section 12-60-2530','https://www.scstatehouse.gov/code/t12c060.php','2026-06-14',2026),
  ('SC','state','payment',NULL,'All property taxes are due and payable between September 30 and January 15 after their assessment each year. Taxes are delinquent if not paid before January 16 (or 30 days after mailing of tax notices, whichever is later). Counties may offer optional installment payment plans.','{"installments":[{"label":"Annual payment window opens","due_month":9,"due_day":30},{"label":"Annual payment due by","due_month":1,"due_day":15}],"delinquent_after_desc":"Delinquent if not paid before January 16, or 30 days after mailing of tax notices, whichever occurs later","locally_variable":true,"notes":"Collection is by the county treasurer. Optional installment plans authorized under Section 12-45-75 are adopted locally by county ordinance, so installment specifics are locally variable."}'::jsonb,'S.C. Code Ann. Section 12-45-70(A); Section 12-45-180(A)','https://www.scstatehouse.gov/code/t12c045.php','2026-06-14',2026),
  ('SC','state','delinquency_redemption',NULL,'Late penalties on delinquent property tax: 3% added if not paid before January 16, an additional 7% if not paid before February 2, and an additional 5% if not paid before March 17, after which the treasurer issues a tax execution. After a delinquent tax sale, the owner (or a grantee, mortgage, or judgment creditor) may redeem the real estate within 12 months by paying taxes, penalties, costs, and interest of 3%/6%/9%/12% of the bid amount depending on the quarter of the redemption period in which redemption occurs. A tax deed is issued if not redeemed.','{"late_penalty_pct":15,"redemption_period_months":12,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Late_penalty_pct=15 is the cumulative maximum (3% + 7% + 5%) reached by March 17 before execution. Redemption interest is tiered by quarter: first 3 months 3%, months 4-6 6%, months 7-9 9%, last 3 months 12% of the bid amount (Section 12-51-90(B)), capped at the forfeited-land-commission bid amount. Tax deed becomes incontestable after a further 12 months."}'::jsonb,'S.C. Code Ann. Section 12-45-180(A); Section 12-51-90','https://www.scstatehouse.gov/code/t12c051.php','2026-06-14',2026),
  ('SD','state','assessment_appeal',NULL,'First-level appeal is to the LOCAL board of equalization; the property owner must notify the clerk of the local board no later than the Thursday preceding the third Monday in March. A further appeal to the county board of equalization is perfected by filing written notice with the county auditor on or before the first Tuesday in April; the county board hears appeals de novo. Owner-occupied classification appeals go directly to the county board.','{"deadline_kind":"relative_to_roll","deadline_month":3,"deadline_day":null,"deadline_desc":"Local board: notify clerk no later than the Thursday preceding the third Monday in March. County board: file written notice with county auditor on or before the first Tuesday in April.","review_body":"Local board of equalization (township/municipality), then county board of equalization (de novo), then circuit court","locally_variable":false}'::jsonb,'SDCL 10-11-16; SDCL 10-11-22; SDCL 10-11-23; SDCL 10-11-25; SDCL 10-11-26','https://sdlegislature.gov/Statutes/10-11-16','2026-06-14',2026),
  ('SD','state','assessment',NULL,'Real property in South Dakota is assessed at full and true (market) value, and property taxes are levied on valuations where the median level of assessment represents eighty-five percent of market value as determined by the Department of Revenue. The director of equalization adjusts valuations so the median level of assessment is at least 85% of market value before the notice of assessment.','{"assessment_ratio_pct":85,"market_value_standard":"full and true (market) value; median level of assessment must represent 85% of market value as determined by the Department of Revenue","reassessment_cycle_years":null,"locally_variable":false}'::jsonb,'SDCL 10-13-37; SDCL 10-3-41','https://sdlegislature.gov/Statutes/10-13-37','2026-06-14',2026),
  ('SD','state','exemption','senior','Senior/disabled assessment freeze (SDCL ch. 10-6A): an owner-occupant of a single-family dwelling who is 65+ or disabled may freeze the assessed value of the dwelling at a base year if household income is under $55,000 (single-member household) or under $65,000 (multiple-member household), has owned an owner-occupied dwelling and been a SD resident at least five years, and resided in the dwelling at least 200 days of the prior calendar year. Application is annual, due on or before April 1. Beginning January 1, 2026, the income caps increase annually by a CPI/Social-Security index factor.','{"age_min":65,"income_max":65000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"assessment_freeze","benefit_value":null,"benefit_unit":null,"locally_variable":false,"notes":"Income cap is $55,000 single-member / $65,000 multiple-member household. Age 65+ OR disabled qualifies (per ch. 10-6A eligibility). Annual application due on or before April 1 (SDCL 10-6A-4). Income caps index annually starting Jan 1, 2026. Denial appeal: hearing before the secretary of revenue within 30 days (SDCL 10-6A-9)."}'::jsonb,'SDCL 10-6A-1; SDCL 10-6A-2; SDCL 10-6A-4; SDCL 10-6A-9','https://sdlegislature.gov/Statutes/10-6A-2','2026-06-14',2026),
  ('SD','state','exemption','disabled_veteran','A veteran rated permanently and totally disabled from a service-connected disability who owns and occupies the dwelling (classified owner-occupied) receives a partial exemption of $200,000 of the full and true value of the dwelling. The same $200,000 exemption extends to a surviving spouse of such a veteran or a surviving spouse receiving dependency and indemnity compensation for the veteran''s service-connected death.','{"age_min":null,"income_max":null,"income_unit":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":200000,"benefit_unit":"usd","locally_variable":false,"notes":"$200,000 of full and true value exempt. Requires permanent and total service-connected disability rating. Surviving-spouse extension under SDCL 10-4-41. Apply on a form prescribed by the secretary of revenue; missed deadline can be cured via abatement/refund petition to county commissioners under ch. 10-18."}'::jsonb,'SDCL 10-4-40; SDCL 10-4-41','https://sdlegislature.gov/Statutes/10-4-40','2026-06-14',2026),
  ('SD','state','exemption','disability','A dwelling owned and occupied by a paraplegic veteran (or a veteran with the loss or loss of use of both lower extremities), or the unremarried widow/widower of such a veteran, occupied for the full calendar year, is fully exempt from taxation (SDCL 10-4-24.10). Separately, a dwelling owned and occupied by a non-veteran paraplegic / person with loss of use of both lower extremities receives an income-based percentage reduction of the property tax due: 100% reduction up to $14,000 household income (single-member) or $18,500 (multiple-member), phasing down to 0% at $18,000 / $22,000 respectively.','{"age_min":null,"income_max":22000,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Two distinct benefits. (a) Paraplegic/disabled VETERAN or unremarried surviving spouse: FULL exemption, no income test (SDCL 10-4-24.10). (b) Non-veteran paraplegic income-based reduction (SDCL 10-4-24.11-.13): single-member schedule 100%<$14k, 75% $14k-15k, 50% $15k-17k, 25% $17k-18k, 0% at/above $18k; multiple-member 100%<$18.5k, 75% $18.5k-19.5k, 50% $19.5k-21k, 25% $21k-22k, 0% at/above $22k. Dwelling must have been owned/occupied the full prior calendar year."}'::jsonb,'SDCL 10-4-24.10; SDCL 10-4-24.11; SDCL 10-4-24.12; SDCL 10-4-24.13','https://sdlegislature.gov/Statutes/10-4-24.10','2026-06-14',2026),
  ('SD','state','exemption','homestead','South Dakota has no general homestead exemption against local property tax. The SDCL 10-4-24 homestead exemption applies only to the (historically) state-levied tax to defray state expenses and expressly does NOT exempt the homestead from county, township, municipal, or school taxes. The functional owner-occupant benefit is the separate ''owner-occupied single-family dwelling'' tax classification (SDCL 10-13-39 / 10-13-40), which is a reduced-rate classification, not an exempt-value amount; the owner-occupant certificate is due by March 15.','{"age_min":null,"income_max":null,"income_unit":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":null,"benefit_unit":null,"locally_variable":false,"notes":"No dollar-amount homestead exemption against local tax. SDCL 10-4-24 only exempts homestead from state-level tax and explicitly NOT from county/township/municipal/school tax. Owner-occupied classification (10-13-39/10-13-40) is the principal-residence benefit: a separate, lower-rate tax classification. Owner-occupant certificate due by March fifteenth; classification persists until ownership transfer or change in use. Classification appeals go directly to the county board of equalization (10-11-23)."}'::jsonb,'SDCL 10-4-24; SDCL 10-13-39; SDCL 10-13-40','https://sdlegislature.gov/Statutes/10-4-24','2026-06-14',2026),
  ('SD','state','payment',NULL,'Real estate taxes are payable in two installments. The first half is accepted through April 30 (delinquent May 1) and the second half is accepted through October 31 (delinquent November 1). If April 30 or October 31 falls on a weekend, payment is due the last business day of the month. Delinquent taxes accrue interest beginning the first business day after the due date at the rate set by SDCL 54-3-16.','{"installments":[{"label":"First half","due_month":4,"due_day":30},{"label":"Second half","due_month":10,"due_day":31}],"delinquent_after_desc":"First half delinquent May 1; second half delinquent November 1. Interest begins on May 1 / Nov 1 (and the first day of each month thereafter) at the Category G rate under SDCL 54-3-16.","grace_days":0,"locally_variable":true}'::jsonb,'SDCL 10-21-23; SDCL 10-21-25; SDCL 54-3-16','https://sdlegislature.gov/Statutes/10-21-23','2026-06-14',2026),
  ('SD','state','delinquency_redemption',NULL,'Delinquent real property taxes are sold via a tax certificate. The owner (or any party with an interest) may redeem at any time before a tax deed is issued by paying the taxes, interest, penalties, and costs. The tax-certificate holder cannot initiate a proceeding for a tax deed until at least three years after the tax-certificate sale, and the proceeding must be completed within six years of the sale. South Dakota is a tax-lien (tax certificate) state.','{"late_penalty_pct":null,"late_interest_pct_per_year":null,"redemption_period_months":36,"tax_sale_kind":"tax_lien","locally_variable":false}'::jsonb,'SDCL 10-25-1; SDCL 10-25-16; SDCL 10-25-18; SDCL 10-25-19; SDCL 10-24-1','https://sdlegislature.gov/Statutes/10-25-1','2026-06-14',2026),
  ('TN','state','assessment_appeal',NULL,'A disputed assessment must first be appealed to the county board of equalization, which convenes its regular session on June 1 each year (next business day if June 1 is a weekend). The exact local filing deadline is set by the county assessor. Appeals from the county board to the State Board of Equalization must be filed by August 1 of the tax year, or within 45 days of the date the local board''s notice was sent, whichever is later.','{"deadline_kind":"fixed_date","deadline_month":6,"deadline_day":1,"deadline_desc":"County board of equalization convenes its regular session June 1 (or next business day); a disputed assessment must be appealed there first or it becomes final. State Board appeal deadline is August 1 of the tax year or 45 days after local board notice, whichever is later.","review_body":"County Board of Equalization (first level), then State Board of Equalization (appeal)","locally_variable":true}'::jsonb,'Tenn. Code Ann. § 67-1-404 (county board convenes June 1); Tenn. Code Ann. § 67-5-1412 / § 67-5-1407 (county board complaints); Tenn. Code Ann. § 67-5-1412(b) / § 67-5-508 (State Board appeal deadline)','https://comptroller.tn.gov/boards/state-board-of-equalization/sboe-resources/county-board-of-equalization.html','2026-06-14',2026),
  ('TN','state','exemption','senior','Tennessee property tax relief (a state reimbursement program, not an exemption) for low-income elderly homeowners. Owner must be 65 or older by Dec 31 of the tax year, own and occupy the home as primary residence, and have total household income (applicant, spouse, co-owner, resident remainder) at or below the annual limit. Relief is calculated on the first portion of the home''s market value (capped). For 2025 the maximum 2024 income limit is $37,530 and relief is calculated on the first $32,700 of market value.','{"age_min":65,"income_max":37530,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":32700,"benefit_unit":"usd","locally_variable":false,"notes":"State-funded reimbursement of property tax paid, not a direct exemption. Income limit ($37,530 for 2025, based on 2024 income) is adjusted annually by the Comptroller per the Social Security COLA, rounded to the nearest $10. Relief is calculated on the first $32,700 of market value. Application deadline is 35 days after the delinquency date and taxes must be paid by then."}'::jsonb,'Tenn. Code Ann. § 67-5-702 (Elderly Low Income Homeowners)','https://comptroller.tn.gov/content/dam/cot/pa/documents/tax-relief/TaxReliefBrochure.pdf','2026-06-14',2026),
  ('TN','state','exemption','disability','Tennessee property tax relief for low-income totally and permanently disabled homeowners. Owner must be disabled on or before Dec 31 of the tax year, own and occupy the home as primary residence, and have total household income at or below the annual limit (same limit as the elderly program: $37,530 for 2025). Relief is calculated on the first $32,700 of market value.','{"income_max":37530,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":32700,"benefit_unit":"usd","locally_variable":false,"notes":"State-funded reimbursement program. Disability must exist on or before 12/31 of the tax year. Same income limit and $32,700 market-value cap as the elderly program. Income limit adjusted annually by the Comptroller per Social Security COLA."}'::jsonb,'Tenn. Code Ann. § 67-5-703 (Disabled Homeowners)','https://comptroller.tn.gov/content/dam/cot/pa/documents/tax-relief/TaxReliefBrochure.pdf','2026-06-14',2026),
  ('TN','state','exemption','disabled_veteran','Tennessee property tax relief for disabled veteran homeowners. Owner must own and occupy the home as primary residence and meet a qualifying service-connected disability (paraplegia/permanent paralysis of both legs and lower body, loss or loss of use of two or more limbs from any service-connected cause, legal blindness, 100% permanent total disability as a former POW, or service-connected permanent and total disability per the VA). No income limit applies. Relief is calculated on the first $175,000 of market value. Surviving spouses (who have not remarried, married at time of death) of qualifying or combat-related/deployment-related deceased veterans also qualify on the same $175,000 cap.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":175000,"benefit_unit":"usd","income_max":null,"locally_variable":false,"notes":"No income limit for disabled veterans. Relief calculated on the first $175,000 of market value. Qualifying disabilities: paraplegia/permanent paralysis of both legs and lower body, loss or loss of use of 2+ limbs from any service-connected cause, legal blindness, 100% permanent total disability as a POW, or service-connected permanent and total disability per the VA. Surviving spouse (not remarried, married at time of death) extends to combat-related or deployment-related service deaths. Effective assessed value = first $175,000 market value x 25%."}'::jsonb,'Tenn. Code Ann. § 67-5-704 (Disabled Veteran''s Residence)','https://comptroller.tn.gov/content/dam/cot/pa/documents/tax-relief/TaxReliefBrochure.pdf','2026-06-14',2026),
  ('TN','state','assessment',NULL,'Tennessee assesses real property at a percentage of fair market (appraised) value that varies by classification: farm/residential 25%, commercial/industrial 40%, and public utility 55%. Counties must conduct a countywide reappraisal of all real property on a 4-, 5-, or 6-year cycle.','{"assessment_ratio_pct":25,"market_value_standard":"fair market value (appraised value); residential/farm assessed at 25%, commercial/industrial at 40%, public utility at 55%","reassessment_cycle_years":6,"locally_variable":true}'::jsonb,'Tenn. Code Ann. § 67-5-801 (classification and assessment ratios); Tenn. Code Ann. § 67-5-1601 (reappraisal cycle)','https://comptroller.tn.gov/office-functions/pa/property-taxes/how-to-figure-your-tax-bill.html','2026-06-14',2026),
  ('TN','state','payment',NULL,'Property tax due dates and the delinquency date in Tennessee are set locally by the county (and city) - county trustees bill and collect, and the date taxes become delinquent varies by jurisdiction. The state frames the timing but does not set a single statewide due date. Relief applications must be filed within 35 days after the local delinquency date, and taxes must be paid by then.','{"installments":[],"delinquent_after_desc":"Set locally by each county (and municipality). County trustees bill and collect; delinquency date varies by jurisdiction. State does not set a single statewide due/delinquency date for real property tax.","grace_days":null,"locally_variable":true}'::jsonb,'Tenn. Code Ann. tit. 67, ch. 5 (collection by county trustees; local due/delinquency dates)','https://comptroller.tn.gov/content/dam/cot/pa/documents/tax-relief/TaxReliefBrochure.pdf','2026-06-14',2026),
  ('TN','state','delinquency_redemption',NULL,'Tennessee uses a court-ordered (judicial) delinquent tax sale; redemption runs from the entry of the order confirming the sale. The default redemption period is one year, but the court may order a shorter period based on the length of delinquency: 180 days if more than 5 but less than 8 years delinquent, 90 days if 8 or more years delinquent, and 30 days for vacant/abandoned property regardless of delinquency length. To redeem, the owner pays the purchase price plus interest at 12% per annum accruing from the date the purchaser pays the clerk.','{"late_penalty_pct":null,"late_interest_pct_per_year":12,"redemption_period_months":12,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Default redemption period is one year from entry of the order confirming the sale; court may shorten to 180 days (delinquent >5 but <8 years), 90 days (delinquent 8+ years), or 30 days (vacant/abandoned property). Redemption interest is 12% per annum accruing from the date the purchaser pays the purchase price to the clerk until the motion to redeem is filed. Sale is judicial/court-confirmed (tax-deed style, not a tax-lien certificate system)."}'::jsonb,'Tenn. Code Ann. § 67-5-2701 (Procedure for redemption of property)','https://www.ctas.tennessee.edu/eli/redemption','2026-06-14',2026),
  ('TX','state','assessment_appeal',NULL,'A property owner who wants to protest the appraised value must file a written notice of protest with the appraisal review board (ARB) by May 15, or by the 30th day after the appraisal district''s notice of appraised value was delivered, whichever is later.','{"deadline_kind":"relative_to_roll","deadline_month":5,"deadline_day":15,"deadline_desc":"May 15, or the 30th day after the date the notice of appraised value was delivered under Sec. 25.19, whichever is later","review_body":"Appraisal Review Board (ARB) of the county appraisal district","locally_variable":false}'::jsonb,'Tex. Tax Code § 41.44(a)','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.41.htm','2026-06-14',2026),
  ('TX','state','exemption','homestead','An adult is entitled to a school-district residence-homestead exemption of $140,000 of the appraised value of the homestead, plus a $3,000 county residence-homestead exemption; taxing units may additionally adopt local optional homestead exemptions (minimum $3,000).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":140000,"benefit_unit":"usd","locally_variable":true,"notes":"School-district exemption is $140,000 (Sec. 11.13(b)); a separate $3,000 county exemption applies under Sec. 11.13(a). Taxing units may adopt optional local homestead exemptions of at least $3,000 (Sec. 11.13(d)/(e)/(f)). Eligibility fixed by qualifications on January 1 (Sec. 11.42(a))."}'::jsonb,'Tex. Tax Code § 11.13(a)-(b)','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.11.htm','2026-06-14',2026),
  ('TX','state','exemption','senior','An individual who is disabled or 65 or older is entitled to an additional school-district residence-homestead exemption of $60,000 of appraised value (on top of the general $140,000 homestead exemption); the homestead''s school taxes are also frozen at the first-qualifying-year amount.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":60000,"benefit_unit":"usd","locally_variable":false,"notes":"Sec. 11.13(c) grants the additional $60,000 school-district exemption to a person who is disabled OR 65+. Sec. 11.26 (DB title ''LIMITATION OF SCHOOL TAX ON HOMESTEADS OF ELDERLY OR DISABLED'') freezes/caps the school-district tax on the homestead. Counties/municipalities/junior college districts may also adopt a parallel freeze under Sec. 11.261 (DB title ''LIMITATION OF COUNTY, MUNICIPAL, OR JUNIOR COLLEGE DISTRICT TAX ON HOMESTEADS OF DISABLED AND ELDERLY''). The $60,000 amount and age-65 trigger are verbatim-verified; the freeze characterization is supported by the section titles but the freeze mechanics were not separately quoted."}'::jsonb,'Tex. Tax Code § 11.13(c)','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.11.htm','2026-06-14',2026),
  ('TX','state','exemption','disabled_veteran','A disabled veteran awarded 100 percent disability compensation due to a service-connected disability with a rating of 100 percent disabled or of individual unemployability is entitled to a total exemption from taxation of the full appraised value of the veteran''s residence homestead.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"100% / individual-unemployability rating = total exemption of full appraised value (Sec. 11.131(b)). Surviving spouse may carry over the exemption if not remarried (Sec. 11.131(c)-(d), confirmed in DB text). Veterans with a partial disability rating receive a tiered exemption under Sec. 11.22, and donated homesteads under Sec. 11.132 \u2014 referenced for context, not quoted here."}'::jsonb,'Tex. Tax Code § 11.131(b)','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.11.htm','2026-06-14',2026),
  ('TX','state','payment',NULL,'Property taxes are due on receipt of the tax bill and become delinquent if not paid before February 1 of the year following the year in which the tax was imposed. Bills are issued and collected by local taxing units.','{"installments":[{"label":"Full payment due","due_month":2,"due_day":1}],"delinquent_after_desc":"Delinquent if not paid before February 1 of the year following the year in which imposed","locally_variable":true,"notes":"Sec. 31.02(a) sets the statewide delinquency date of February 1. Tax rates, bill issuance, and collection are handled by local taxing units / county tax assessor-collectors, so dollar amounts and split-payment options vary locally. Split-payment and over-65/disabled installment options exist under Secs. 31.03 and 31.031 (referenced for context, not quoted)."}'::jsonb,'Tex. Tax Code § 31.02(a)','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.31.htm','2026-06-14',2026),
  ('TX','state','delinquency_redemption',NULL,'A delinquent tax incurs a 6% penalty the first month plus 1% per additional month (12% total once delinquent on July 1), and interest of 1% per month. After a tax sale, the owner of a residence-homestead or agricultural-use property may redeem within 2 years by paying a redemption premium of 25% (year 1) or 50% (year 2); other property has a 180-day redemption period.','{"late_penalty_pct":12,"late_interest_pct_per_year":12,"redemption_period_months":24,"tax_sale_kind":"tax_deed","locally_variable":false,"notes":"Penalty: 6% first month + 1% each additional month, reaching a flat 12% once delinquent on July 1 (Sec. 33.01(a)); interest accrues at 1% per month = 12%/yr (Sec. 33.01(c)). Redemption (Sec. 34.21(a)/(e)): residence-homestead, agricultural-use land, and mineral interests = 2-year redemption with a 25% premium in year 1 / 50% in year 2 on the aggregate total; all OTHER real property = 180-day redemption period (premium capped at 25%). Texas sells a redeemable tax deed subject to the owner''s statutory right of redemption."}'::jsonb,'Tex. Tax Code §§ 33.01, 34.21','https://statutes.capitol.texas.gov/Docs/TX/htm/TX.34.htm','2026-06-14',2026),
  ('UT','state','assessment',NULL,'Utah taxes all tangible property at fair market value as of the January 1 lien date. Residential property receives a statewide 45% reduction (the ''residential exemption''), so a primary residence is effectively assessed/taxed on 55% of fair market value. The exemption is limited to one primary residence per household and no more than one acre of land per residential unit.','{"assessment_ratio_pct":55,"market_value_standard":"fair_market_value_as_of_january_1_lien_date","residential_exemption_pct_reduction":45,"reassessment_cycle_years":5,"locally_variable":false,"notes":"Residential exemption = 45% reduction in value (Sec 59-2-103(3)); residence taxed on remaining 55%. Limited to one primary residence per household (Sec 59-2-103(6)(a)) and max one acre per residential unit (Sec 59-2-103(5)). County assessors update values annually via mass appraisal and complete a detailed property-characteristics review at least once every five years (Sec 59-2-303.1(2)-(3))."}'::jsonb,'Utah Code Ann. Sec 59-2-103','https://le.utah.gov/xcode/Title59/Chapter2/59-2-S103.html','2026-06-14',2026),
  ('UT','state','assessment_appeal',NULL,'A taxpayer appeals real property valuation/equalization to the County Board of Equalization on or before the LATER of September 15 of the current year OR the last day of a 45-day period beginning the day the county auditor mails the valuation notice. The county board hears the appeal; its decision may be further appealed to the Utah State Tax Commission (Sec 59-2-1006).','{"deadline_kind":"window","deadline_month":9,"deadline_day":15,"deadline_desc":"On or before the later of September 15 of the current calendar year, or the last day of a 45-day period beginning when the county auditor provides the valuation notice under Sec 59-2-919.1.","review_body":"County Board of Equalization (further appeal to Utah State Tax Commission under Sec 59-2-1006)","locally_variable":false}'::jsonb,'Utah Code Ann. Sec 59-2-1004(3)','https://le.utah.gov/xcode/Title59/Chapter2/59-2-S1004.html','2026-06-14',2026),
  ('UT','state','exemption','disabled_veteran','Veterans with a Disability Exemption: a veteran with a service-connected disability of more than 10% (or their unmarried surviving spouse or minor orphans) receives an exemption of up to a statutorily indexed amount of taxable value of a primary residence and non-business personal property, scaled to the percentage of disability. The 2025 indexed maximum published by the Utah State Tax Commission is $521,620 of taxable value. File by September 1.','{"primary_residence_required":true,"disability_pct_min":10,"benefit_kind":"exempt_value_cap","benefit_value":521620,"benefit_unit":"usd","benefit_scales_with_disability_pct":true,"application_deadline_month":9,"application_deadline_day":1,"locally_variable":false,"notes":"Max exempt taxable value is inflation-indexed annually; $521,620 is the figure on the 2025 Property Tax Relief Table. Disability must be >10%; exemption amount is based on percentage of disability. Administered by the county. Applies to a primary residence and non-business personal property."}'::jsonb,'Utah Code Ann. Sec 59-2-1903 & 59-2-1904','https://files.tax.utah.gov/propertytax/media/tax-relief.pdf','2026-06-14',2026),
  ('UT','state','exemption','circuit_breaker','Circuit Breaker Homeowner''s Credit (low-income senior relief): an owner-occupant who is 66 or older (or an unmarried surviving spouse) and is a Utah resident for the entire year with household income below the annually indexed limit ($42,623 for the 2025 program) receives a property tax credit of up to $1,312 based on household income, plus an additional Homeowner''s Valuation Reduction equal to the tax on 20% of the home''s fair market value. File annually by September 1 with the county.','{"age_min":66,"income_max":42623,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1312,"benefit_unit":"usd","application_deadline_month":9,"application_deadline_day":1,"locally_variable":false,"notes":"Income limit and credit cap are inflation-indexed; $42,623 income / $1,312 credit are the 2025 figures. credit is ''up to $1,312 based on annual household income'' (a maximum, sliding by income). Unmarried surviving spouse qualifies. Separate Homeowner''s Valuation Reduction gives an additional credit equal to tax on 20% of fair market value. A parallel Renter''s Credit (file by Dec 31 with the Tax Commission) exists for renters."}'::jsonb,'Utah Code Ann. Sec 59-2-1202 to 59-2-1220','https://files.tax.utah.gov/propertytax/media/tax-relief.pdf','2026-06-14',2026),
  ('UT','state','exemption','senior','Indigent Abatement (discretionary county relief): an owner-occupant who is 65 or older, disabled, or in extreme hardship, with household income below the indexed limit ($42,623 for 2025) and residing at the property at least 10 months of the year, may receive an abatement of one-half of the tax due, capped at $1,312 (whichever is less). File annually by September 1 with the county.','{"age_min":65,"income_max":42623,"income_unit":"usd_per_year","ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1312,"benefit_unit":"usd","application_deadline_month":9,"application_deadline_day":1,"locally_variable":true,"notes":"Discretionary at county level (county determines eligibility / funds it). Benefit = one-half of tax due OR max $1,312, whichever is less. Income limit indexed annually; $42,623 is the 2025 figure. Disability or extreme hardship also qualifies regardless of the age-65 path. Requires residing at the property at least 10 months of the year."}'::jsonb,'Utah Code Ann. Sec 59-2-1803 & 59-2-1804','https://files.tax.utah.gov/propertytax/media/tax-relief.pdf','2026-06-14',2026),
  ('UT','state','exemption','disability','Blind Exemption: a legally blind person (or their unmarried surviving spouse or minor orphans) receives an exemption of the first $11,500 of taxable value of real and tangible personal property. No income requirement. File annually by September 1 with a signed ophthalmologist statement.','{"ownership_required":true,"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":11500,"benefit_unit":"usd","income_max":null,"application_deadline_month":9,"application_deadline_day":1,"locally_variable":false,"notes":"Applies to a blind person, unmarried surviving spouse of a blind person, or a minor orphan of a blind person. No income requirement. Administered by the county. Sept 1 deadline is stated in the statute itself (''September 1 in each year'')."}'::jsonb,'Utah Code Ann. Sec 59-2-1106','https://le.utah.gov/xcode/Title59/Chapter2/59-2-S1106.html','2026-06-14',2026),
  ('UT','state','payment',NULL,'Property tax is due November 30 of each year following the date of levy and becomes delinquent at that point (if Nov 30 falls on a weekend/holiday, the next business day is substituted). There is a single annual due date, not installments. A taxpayer may make partial/prepayments (Sec 59-2-1331(4) permits payments of not less than $10); a commercial/industrial taxpayer may also enter an equal-payment agreement with the Commission (Sec 59-2-1308.5).','{"installments":[{"label":"Annual payment in full","due_month":11,"due_day":30}],"delinquent_after_desc":"Delinquent after November 30 following the date of levy (next business day if Nov 30 is a Saturday, Sunday, or holiday).","grace_days":0,"locally_variable":false,"notes":"Single statewide due date set by statute (not locally variable). No standard installments; partial payments permitted (min $10, Sec 59-2-1331(4)). Equal-payment agreements under Sec 59-2-1308.5 are limited to commercial/industrial taxpayers via agreement with the Commission, not a general homeowner option. Penalty/interest detail captured under delinquency_redemption."}'::jsonb,'Utah Code Ann. Sec 59-2-1331(1)','https://le.utah.gov/xcode/Title59/Chapter2/59-2-S1331.html','2026-06-14',2026),
  ('UT','state','delinquency_redemption',NULL,'Delinquent taxes incur a penalty of 2.5% of the delinquent amount (or $10, whichever is greater); the penalty drops to 1% (or $10, whichever is greater) if all delinquent taxes, tax notice charges, and penalty are paid by the following January 31. Interest accrues from January 1 after delinquency at a rate of 6% plus the federal funds target rate, with a 7% floor and 10% ceiling. Property may be redeemed at any time before the county tax sale, held in May or June after four years have lapsed from delinquency. Utah uses a tax-deed sale (struck off to the county after four years, then sold at public auction).','{"late_penalty_pct":2.5,"late_penalty_min_usd":10,"late_penalty_reduced_pct":1,"late_penalty_reduced_condition":"Reduced to 1% (or $10) if all delinquent taxes, tax notice charges, and penalty are paid by the January 31 immediately following the delinquency date.","late_interest_pct_per_year":null,"late_interest_formula":"6% + federal funds rate target (Federal Open Market Committee target on Jan 1 after delinquency); minimum 7%, maximum 10%.","late_interest_floor_pct":7,"late_interest_ceiling_pct":10,"redemption_period_months":48,"tax_sale_kind":"tax_deed","tax_sale_timing":"Tax sale held in May or June after four years lapse from delinquency (Sec 59-2-1346 / 59-2-1351).","locally_variable":false,"notes":"Interest rate is a per-annum formula (6% + Fed funds target, floored at 7%, capped at 10%), not a fixed number, so late_interest_pct_per_year is null. Redemption is allowed any time before the tax sale; the four-year delinquency-to-sale window is the effective redemption period. Tax-deed system: unredeemed parcels are sold at the county tax sale (Sec 59-2-1351.1 ''Deeds'') or struck off to the county (Sec 59-2-1351.3)."}'::jsonb,'Utah Code Ann. Sec 59-2-1331(2) (penalty/interest); Sec 59-2-1346 & 59-2-1351 (redemption/tax sale)','https://le.utah.gov/xcode/Title59/Chapter2/59-2-S1346.html','2026-06-14',2026),
  ('VA','state','exemption','disabled_veteran','Virginia grants a statewide, constitutionally-mandated 100% real property tax exemption on the principal residence (dwelling plus land up to one acre, or more if the locality provides) of any veteran with a U.S. Department of Veterans Affairs rating of 100 percent service-connected, permanent, and total disability. A surviving spouse keeps the exemption so long as the veteran''s death occurred on or after January 1, 2011 and the spouse does not remarry. This is a mandatory statewide benefit (not locally optional).','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":100,"benefit_unit":"pct","disability_rating_min_pct":100,"surviving_spouse_eligible":true,"surviving_spouse_death_on_or_after":"2011-01-01","surviving_spouse_no_remarriage":true,"land_acre_cap":1,"locally_variable":false}'::jsonb,'Va. Code Ann. § 58.1-3219.5','https://law.lis.virginia.gov/vacode/title58.1/chapter32/section58.1-3219.5/','2026-06-14',2026),
  ('VA','state','exemption','senior','Virginia authorizes (but does not mandate) localities to provide, by ordinance, an exemption from and/or deferral of real estate tax for an owner at least 65 years of age who owns and occupies the property as the sole dwelling. The same article also lets the locality extend relief to a person who is permanently and totally disabled. Each locality sets its own income and/or net-worth eligibility limits (58.1-3212) and may cap the benefited land at ten acres. Because the program and all dollar thresholds are locality-defined, the specific age-related dollar benefit varies locally.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","income_unit":"usd_per_year","land_acre_cap":10,"income_and_net_worth_limits_set_by_locality":true,"locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3210; § 58.1-3212','https://law.lis.virginia.gov/vacode/title58.1/chapter32/section58.1-3210/','2026-06-14',2026),
  ('VA','state','exemption','disability','Under the same locally-authorized elderly/disabled relief article, a locality may by ordinance extend the real estate tax exemption or deferral to a person found to be permanently and totally disabled, defined as being unable to engage in any substantial gainful activity by reason of a medically determinable physical or mental impairment expected to result in death or to last for the duration of the person''s life. As with the senior program, eligibility income/net-worth thresholds and benefit amounts are set by the locality.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"fixed_amount","income_unit":"usd_per_year","requires_permanent_total_disability":true,"locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3217 (definition); § 58.1-3210; § 58.1-3212','https://law.lis.virginia.gov/vacode/title58.1/chapter32/section58.1-3217/','2026-06-14',2026),
  ('VA','state','assessment',NULL,'Virginia counties must conduct a general reassessment of real estate every four years; a county board of supervisors may elect by majority vote to reassess every three years, and counties with 50,000 or fewer population (plus named counties Augusta and Bedford) may elect five- or six-year intervals. Cities and counties may alternatively adopt annual or biennial assessment. There is no statewide fractional assessment ratio — Virginia assesses at 100 percent fair market value (per § 58.1-3201, which is the statute that supplies the ratio; the cited cycle statutes 58.1-3252/3253 do not state the ratio). The exact cycle and method are set locally within this statutory framework. VERIFICATION NOTE: the four/three/five-six-year cycle is supported verbatim by the cited statute and evidence quote; the 100% fair-market-value ratio is true VA law but is supported by § 58.1-3201, which has been added to the citation since the original citation list (58.1-3252/3253) did not cover it.','{"assessment_ratio_pct":100,"market_value_standard":"fair_market_value","reassessment_cycle_years":4,"locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3252; § 58.1-3253; § 58.1-3201 (100% fair market value standard)','https://law.lis.virginia.gov/vacode/title58.1/chapter32/section58.1-3252/','2026-06-14',2026),
  ('VA','state','assessment_appeal',NULL,'A taxpayer aggrieved by a real estate assessment may apply to the local board of equalization for adjustment to fair market value and equalization; the board hears complaints and equalizes assessments, with a presumption that the assessor''s valuation is correct and the burden on the taxpayer. Beyond the board, a taxpayer may apply to the circuit court for correction of an erroneous assessment within three years from the last day of the tax year for which the assessment was made, or within one year from the date of the assessment, whichever is later. Board-of-equalization filing deadlines are set by the local ordinance, so the precise window varies by locality.','{"deadline_kind":"window","deadline_desc":"Apply to local board of equalization (deadline set by locality ordinance). Circuit court correction of an erroneous assessment: within 3 years from the last day of the tax year assessed, or 1 year from the date of assessment, whichever is later.","review_body":"Local board of equalization; appeal to the circuit court of the county or city","locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3380; § 58.1-3379; § 58.1-3984','https://law.lis.virginia.gov/vacode/title58.1/chapter32/section58.1-3984/','2026-06-14',2026),
  ('VA','state','payment',NULL,'Statewide default: the treasurer receives local levies without penalty up to and including December 5 of each year. A taxpayer who fails to pay by December 5 incurs a 5% penalty added to the tax. However, the governing body of any county, city, or town may by ordinance set different due dates, allow a single installment or two equal installments, and set its own penalties and interest — so the actual due date(s) and installment structure are determined locally. (Deployed armed-services members get an automatic extension on a primary residence ending 90 days after deployment completes.)','{"installments":[{"label":"Statewide default - paid without penalty through this date","due_month":12,"due_day":5}],"delinquent_after_desc":"Without penalty through December 5; localities may set other due dates and one or two installments by ordinance","statewide_late_penalty_pct":5,"locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3913; § 58.1-3915; § 58.1-3916','https://law.lis.virginia.gov/vacode/title58.1/chapter39/section58.1-3915/','2026-06-14',2026),
  ('VA','state','delinquency_redemption',NULL,'Delinquent Virginia real estate taxes accrue interest at 10% per annum (statewide default; localities that regulate by ordinance under § 58.1-3916 may set their own rate up to 10%) in addition to the late penalty (5% under § 58.1-3915). Real estate generally may be sold for delinquent taxes through a judicial (court-ordered, tax-deed) sale once taxes are delinquent on December 31 following the second anniversary of their due date (shorter triggers apply for blighted/condemned/low-value parcels). The owner (or heirs, successors, assigns) retains the right to redeem the property at any time prior to the date set for the judicial sale by paying all taxes, penalties, interest, and costs into court. Anyone who pays taxes on the property holds a lien for amounts paid plus 6% per year. VERIFICATION NOTE: the 6% lien interest is verbatim in the evidence quote (§ 58.1-3974); the 10% delinquent interest is verbatim in cited § 58.1-3918; the Dec-31-after-2nd-anniversary sale trigger is verbatim in cited § 58.1-3965; the 5% late penalty derives from § 58.1-3915 (added to the citation list, since the original 3918/3965/3974 citations did not cover the penalty figure).','{"late_penalty_pct":5,"late_interest_pct_per_year":10,"tax_sale_kind":"tax_deed","redemption_period_desc":"Owner may redeem any time before the date set for the judicial sale by paying all delinquent taxes, penalties, interest, and costs into court; sale generally available after taxes delinquent on Dec 31 following the 2nd anniversary of the due date","lien_holder_interest_pct_per_year":6,"locally_variable":true}'::jsonb,'Va. Code Ann. § 58.1-3918; § 58.1-3965; § 58.1-3974; § 58.1-3915 (5% late penalty)','https://law.lis.virginia.gov/vacode/title58.1/chapter39/section58.1-3965/','2026-06-14',2026),
  ('VT','state','exemption','disabled_veteran','Vermont exempts $10,000 of appraised value (towns may vote to raise to as much as $40,000) for a residence owned and occupied by a veteran (or spouse/widow/widower/child) who receives disability compensation for at least 50% disability, death/DIC compensation, or a disability pension. Must file with the Office of Veterans Affairs before May 1 each year. Excludes any part used for business or rental; only one exemption per property.','{"primary_residence_required":true,"ownership_required":true,"benefit_kind":"exempt_value_cap","benefit_value":10000,"benefit_unit":"usd","disability_min_pct":50,"application_deadline_month":5,"application_deadline_day":1,"locally_variable":true,"notes":"$10,000 is the statutory base exemption; a town may vote to increase it up to $40,000 (32 V.S.A. 3802(11)(C)). Eligibility tied to VA disability compensation of 50%+, death/DIC compensation, or disability pension. Annual filing with the Office of Veterans Affairs required before May 1. Not for business/rental portions; one exemption per property."}'::jsonb,'32 V.S.A. § 3802(11)(A)','https://legislature.vermont.gov/statutes/section/32/125/03802','2026-06-14',2026),
  ('VT','state','exemption','other','Local-option new-construction homes exemption: a town may vote annually at town meeting to exempt the first $75,000 (or a smaller amount) of appraised value of buildings used and occupied exclusively as homes, dwelling houses, or farm buildings that were constructed (or put in process of construction) within the 12 months before or after the meeting. Duration capped at three years, set by the vote. This is a discretionary local incentive, not a statewide owner-occupant exemption.','{"primary_residence_required":false,"benefit_kind":"exempt_value_cap","benefit_value":75000,"benefit_unit":"usd","locally_variable":true,"notes":"Local-option only \u2014 requires an affirmative town-meeting vote. Applies to newly constructed homes/dwellings/farm buildings (whether for sale or rent), max 3-year duration. Vermont has no statewide general homestead value exemption."}'::jsonb,'32 V.S.A. § 3836','https://legislature.vermont.gov/statutes/section/32/125/03836','2026-06-14',2026),
  ('VT','state','assessment_appeal',NULL,'Vermont''s appeal chain starts with the listers'' grievance hearings: listers meet on or before May 20 to hear persons aggrieved by their appraisals, and hearings must conclude by June 2. A taxpayer dissatisfied with the listers'' decision may appeal in writing to the Board of Civil Authority within 14 days after notice of the listers'' final decision. A further appeal from the Board of Civil Authority lies to the Director (Property Valuation and Review) or the Superior Court, filed within 30 days after entry of the board''s decision.','{"deadline_kind":"fixed_date","deadline_month":5,"deadline_day":20,"deadline_desc":"Listers hold grievance hearings on or before May 20 (concluding by June 2). Appeal to the Board of Civil Authority must be filed within 14 days after notice of the listers'' final decision. Appeal from the Board of Civil Authority to the Director or Superior Court must be filed within 30 days after entry of the board''s decision.","review_body":"Listers (grievance) -> Board of Civil Authority -> Director (Property Valuation and Review) or Superior Court","locally_variable":false,"notes":"Three-tier process. Grievance deadline anchored to the May 20 lister hearing / June 2 cutoff. The first appeal window is relative (14 days from lister decision notice); the second is 30 days from BCA decision entry (date of mailing of notice deemed date of entry). $70 entry fee for an appeal to the Director."}'::jsonb,'32 V.S.A. §§ 4221, 4404, 4461','https://legislature.vermont.gov/statutes/section/32/131/04461','2026-06-14',2026),
  ('VT','state','payment',NULL,'Property tax due dates and installment schedules are set locally by town vote, not by the state. A town may vote to collect taxes in installments (up to four), payable to the town treasurer or collector, with optional discounts for on-time payment. Where a municipality votes to collect interest on overdue taxes, those taxes are due and payable not later than December 1.','{"installments":[],"delinquent_after_desc":"Set locally. A town may vote up to four installments with town-set due dates. Where a municipality votes to collect interest on overdue taxes, the tax is due no later than December 1 (32 V.S.A. 5136(a)).","locally_variable":true,"notes":"Vermont leaves the number and dates of installments to each town''s vote (32 V.S.A. 4872 \u2014 not to exceed four installments). The only statewide-framed date is the December 1 outer due date that triggers interest under 5136(a) for municipalities that vote to collect overdue-tax interest."}'::jsonb,'32 V.S.A. §§ 4872, 5136(a)','https://legislature.vermont.gov/statutes/section/32/133/04872','2026-06-14',2026),
  ('VT','state','delinquency_redemption',NULL,'After real property is sold at a tax sale (public auction) to satisfy unpaid taxes, the owner, lienholder, or mortgagee may redeem within one year from the day of sale by paying the sale amount plus interest at one percent per month (or fraction). Overdue taxes generally bear interest at not more than 1% per month for the first three months and 1.5% per month thereafter where the town votes to impose it. If the property is not redeemed within the one-year period, the collector executes a deed conveying title to the purchaser.','{"late_interest_pct_per_year":12,"redemption_period_months":12,"tax_sale_kind":"hybrid","locally_variable":true,"notes":"Redemption period is a fixed one year from the day of tax sale (32 V.S.A. 5260(a)). Redemption interest is 1%/month (~12%/yr) per 5260(a). General overdue-tax interest (5136 / 4873) is capped at 1%/month for the first 3 months then 1.5%/month, but only applies if the town votes to impose it (hence locally_variable). tax_sale_kind = hybrid: property is sold at public sale (5252/5253/5254), redeemable for one year, then a deed issues to the purchaser if not redeemed (5261). NOTE: the parenthetical ''8% collection fee under 1674'' from the original draft could NOT be verified against the DB \u2014 \u00a7 1674 is not present in the VT statute corpus \u2014 so that figure is unverified; it is not part of any core param or the evidence quote."}'::jsonb,'32 V.S.A. §§ 5260, 5261, 5136','https://legislature.vermont.gov/statutes/section/32/135/05260','2026-06-14',2026),
  ('WA','state','assessment_appeal',NULL,'A property owner may petition the county Board of Equalization to challenge the assessor''s valuation. The petition must be filed on or before July 1 of the assessment year, OR within 30 days after the assessment/value-change notice was mailed (or electronically transmitted), whichever is later. A county legislative authority may set a longer deadline of up to 60 days. Direct appeal to the state Board of Tax Appeals is possible only by agreement of the assessor, owner, and a majority of the county board.','{"deadline_kind":"relative_to_roll","deadline_month":7,"deadline_day":1,"deadline_desc":"On or before July 1 of the assessment year, or within 30 days after the value/assessment notice was mailed or electronically transmitted, whichever is later; a county may extend to up to 60 days.","review_body":"County Board of Equalization (appeals onward to the state Board of Tax Appeals under RCW 84.08.130)","locally_variable":true}'::jsonb,'RCW 84.40.038','https://app.leg.wa.gov/RCW/default.aspx?cite=84.40.038','2026-06-14',2026),
  ('WA','state','assessment',NULL,'Washington assesses all property at 100% of its true and fair value in money (full market value); there is no fractional assessment ratio. Counties revalue on a cyclical basis set by the assessor.','{"assessment_ratio_pct":100,"market_value_standard":"true and fair value in money (100%)","locally_variable":false}'::jsonb,'RCW 84.40.030','https://app.leg.wa.gov/RCW/default.aspx?cite=84.40.030','2026-06-14',2026),
  ('WA','state','exemption','senior','Senior citizen / disabled / qualifying-veteran property tax exemption on a principal residence. Claimant must be 61+ on Dec 31 of the filing year, OR retired from gainful employment due to disability, OR a veteran with a 40%+ combined service-connected rating (a surviving spouse/domestic partner age 57+ may qualify). Owner-occupied principal residence required. Benefit is income-tiered against county median household income (the income thresholds are defined in RCW 84.36.383): at or below income threshold 3, exempt from all excess (voter-approved) levies and the additional state levy and the residence value is frozen; at or below income threshold 2 but above threshold 1, exempt from regular taxes on the greater of $50,000 or 35% of valuation (cap $70,000); at or below income threshold 1, exempt from regular taxes on the greater of $60,000 or 60% of valuation.','{"age_min":61,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":60000,"benefit_unit":"usd","locally_variable":true,"notes":"Three income tiers tied to a percentage of county median household income (RCW 84.36.383): threshold 1 = 50%, threshold 2 = 60%, threshold 3 = 70% of county median for collections 2024+. Lowest-income tier (<=threshold 1): exempt regular taxes on greater of $60,000 or 60% of valuation. Middle tier (<=threshold 2, >threshold 1): exempt regular taxes on greater of $50,000 or 35% of valuation, cap $70,000. Highest tier (<=threshold 3): exemption from excess/voter-approved levies plus a frozen-valuation benefit. Also covers retired-by-disability claimants and 40%+ rated veterans; surviving spouse/partner 57+ may continue. Benefit_value/benefit_kind reflect the lowest-income tier''s value floor; actual benefit varies by tier and county median income."}'::jsonb,'RCW 84.36.381 (income thresholds defined in RCW 84.36.383)','https://app.leg.wa.gov/RCW/default.aspx?cite=84.36.381','2026-06-14',2026),
  ('WA','state','payment',NULL,'All real and personal property taxes are due to the county treasurer on or before April 30 and are delinquent after that date. If the total tax is $50 or more and at least one-half is paid by April 30, the remaining half is due by October 31 and is delinquent after that date. Tax statements are distributed by March 15. (Counties administer collection within this statutory framework.)','{"installments":[{"label":"First half (or full payment)","due_month":4,"due_day":30},{"label":"Second half","due_month":10,"due_day":31}],"delinquent_after_desc":"Delinquent after April 30; if half paid by April 30, second half delinquent after October 31. Two-installment option requires total tax of $50 or more.","grace_days":0,"locally_variable":true}'::jsonb,'RCW 84.56.020','https://app.leg.wa.gov/RCW/default.aspx?cite=84.56.020','2026-06-14',2026),
  ('WA','state','delinquency_redemption',NULL,'Delinquent property taxes accrue interest at 9% per annum for residential real property with four or fewer units (including manufactured/mobile homes) and 12% per annum for other property (for taxes levied 2023 and after). Penalties (3% on June 1, an additional 8% on December 1) apply to nonresidential and larger-multifamily/personal property but NOT to residential property of four or fewer units. Washington uses a judicial tax-lien foreclosure model: after three years from the date of delinquency the treasurer issues a certificate of delinquency and forecloses. The owner may redeem at any time up to the close of business the day before the foreclosure sale by paying the amount due plus statutory interest; there is no general post-sale redemption period (minors and legally incompetent persons have up to three years after the sale).','{"late_penalty_pct":11,"late_interest_pct_per_year":9,"redemption_period_months":0,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"Interest: 9%/yr on residential <=4 units (incl. manufactured/mobile homes) for taxes levied 2023+; 12%/yr on other property. Penalty 11% total (3% assessed June 1 + additional 8% Dec 1) does NOT apply to residential property of four or fewer units. Foreclosure begins after 3 years from date of delinquency (RCW 84.64.050). Redemption (RCW 84.64.070) is allowed up to close of business the day before the sale; redemption_period_months=0 reflects no post-sale redemption for ordinary owners (3 years only for minors/legally incompetent persons)."}'::jsonb,'RCW 84.56.020(5) (interest/penalties); RCW 84.64.050 (foreclosure after 3 years); RCW 84.64.070 (redemption)','https://app.leg.wa.gov/RCW/default.aspx?cite=84.64.070','2026-06-14',2026),
  ('WI','state','assessment',NULL,'Wisconsin real property is assessed at full (fair market) value — the price ordinarily obtainable at private sale — per the Wisconsin Property Assessment Manual. There is no fractional assessment ratio; local assessors set values annually and the DOR equalizes across districts.','{"assessment_ratio_pct":100,"market_value_standard":"full_fair_market_value","locally_variable":true}'::jsonb,'Wis. Stat. § 70.32(1)','https://docs.legis.wisconsin.gov/document/statutes/70.32','2026-06-14',2026),
  ('WI','state','assessment_appeal','board_of_review','Assessment objections are heard by the local Board of Review, which meets during the 45-day period beginning the 4th Monday of April (no sooner than 7 days after the assessment roll opens for examination). A property owner must give written or oral notice of intent to file an objection at least 48 hours before the Board''s first scheduled meeting, then file a written objection with the Board. The Board of Review is the review body; the exact meeting dates are set locally.','{"deadline_kind":"window","deadline_month":4,"deadline_day":null,"deadline_desc":"Board of Review meets during the 45-day period beginning the 4th Monday of April; owner must give notice of intent to object at least 48 hours before the Board''s first scheduled meeting and file a written objection with the Board. Exact session dates set locally.","review_body":"local Board of Review","locally_variable":true}'::jsonb,'Wis. Stat. § 70.47(1), (7)','https://docs.legis.wisconsin.gov/document/statutes/70.47','2026-06-14',2026),
  ('WI','state','assessment_appeal','excessive_assessment_claim','After exhausting the Board of Review process, a taxpayer may file a written claim for an excessive assessment against the taxation district (or county with a county assessor system). The claim must be served on the clerk by January 31 of the year in which the tax based on the contested assessment is payable; the tax must be timely paid. This is the statewide statutory deadline for the excessive-assessment refund claim path.','{"deadline_kind":"fixed_date","deadline_month":1,"deadline_day":31,"deadline_desc":"Written claim for excessive assessment must be served on the taxation-district/county clerk by January 31 of the year the contested tax is payable; Board of Review objection procedures under s. 70.47 must first be complied with and the tax timely paid.","review_body":"taxation district / county clerk (then circuit court on disallowance)","locally_variable":false}'::jsonb,'Wis. Stat. § 74.37(2)(b)5., (4)','https://docs.legis.wisconsin.gov/document/statutes/74.37','2026-06-14',2026),
  ('WI','state','exemption','homestead','Wisconsin has no value-reducing residential homestead exemption. Its homeowner relief is a refundable income-tax HOMESTEAD CREDIT (Schedule H) tied to property taxes (or rent) paid on a Wisconsin homestead. No credit is allowed if household income exceeds $24,680. Property taxes accrued are capped at $1,460 for the credit formula, and the credit rate is 80%, so the maximum credit is 80% of $1,460 = $1,168. Claimant must own or rent and occupy the homestead.','{"income_max":24680,"income_unit":"usd_per_year","ownership_required":false,"primary_residence_required":true,"benefit_kind":"fixed_amount","benefit_value":1168,"benefit_unit":"usd","locally_variable":false,"notes":"Refundable income-tax credit, not an assessed-value exemption. Property taxes accrued capped at $1,460 in the formula (\u00a7 71.54(2)(b)); income limit $24,680 (\u00a7 71.54(1)(cm)). 80% credit rate confirmed in \u00a7 71.54(1)(cm)/(am)-(bm) phase-out formula, so max credit = 80% x $1,460 = $1,168 (occurs only at the lowest income tier). Statute text NOT present in DB property_tax catalog; figures re-fetched and verbatim-confirmed from official docs.legis.wisconsin.gov source. The $1,168 is a sound derivation, not a directly quoted figure. Also available to renters via rent-constituting-property-taxes."}'::jsonb,'Wis. Stat. § 71.54(1)(cm), (2)(b)','https://docs.legis.wisconsin.gov/document/statutes/71.54','2026-06-14',2026),
  ('WI','state','exemption','disabled_veteran','Wisconsin''s Veterans and Surviving Spouses Property Tax Credit is a refundable income-tax credit equal to 100% of the property taxes paid on the claimant''s principal Wisconsin dwelling. Eligible claimant is a veteran (verified by the WI Dept. of Veterans Affairs) with a service-connected disability rating of 100 percent (or a 100% rating based on individual unemployability), or an eligible unremarried surviving spouse. No income limit applies.','{"age_min":null,"income_max":null,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":100,"benefit_unit":"pct","locally_variable":false,"notes":"Refundable income-tax credit (claimed on the WI income tax return), not an assessed-value exemption. Veteran must have a service-connected disability rating of 100 percent under 38 USC 1114 or 1134, or a 100% rating based on individual unemployability, verified by WDVA; surviving spouses also eligible. Credit equals the amount of the claimant''s property taxes on the principal dwelling; no income cap. Statute text NOT present in DB property_tax catalog; the 100% disability requirement, the 100%-of-property-taxes credit amount, and the absence of an income limit were re-fetched and verbatim-confirmed from the official docs.legis.wisconsin.gov source."}'::jsonb,'Wis. Stat. § 71.07(6e)','https://docs.legis.wisconsin.gov/document/statutes/71.07','2026-06-14',2026),
  ('WI','state','payment',NULL,'Real property taxes are payable in full on or before January 31, OR in two equal installments with the first due by January 31 and the second by July 31 (taxation districts may by ordinance authorize 3+ installments). If the first installment is not received within 5 working days after January 31, the entire remaining tax is delinquent as of February 1; a missed second installment makes the remainder delinquent as of August 1. Specific installment schedules beyond the statutory default are set locally by ordinance.','{"installments":[{"label":"Full payment OR first installment","due_month":1,"due_day":31},{"label":"Second installment (2-installment option)","due_month":7,"due_day":31}],"delinquent_after_desc":"First installment not received within 5 working days after Jan 31 -> entire remaining tax delinquent Feb 1; second installment not received within 5 working days after Jul 31 -> remainder delinquent Aug 1.","grace_days":5,"locally_variable":true}'::jsonb,'Wis. Stat. § 74.11(2), (7), (8)','https://docs.legis.wisconsin.gov/document/statutes/74.11','2026-06-14',2026),
  ('WI','state','delinquency_redemption',NULL,'Delinquent property taxes accrue interest of 1% per month (or fraction of a month) — 12% per year — from February 1; counties/authorized cities may add a penalty of up to 0.5% per month on top. Delinquency leads to issuance of a tax CERTIFICATE (tax lien). The owner may redeem at any time before a tax deed is recorded by paying the unpaid taxes plus accrued interest and penalty. A county may foreclose the certificate only after 2 years from the date of the certificate, giving an effective minimum redemption window of about 2 years before title can be taken.','{"late_penalty_pct":0.5,"late_interest_pct_per_year":12,"redemption_period_months":24,"tax_sale_kind":"hybrid","locally_variable":true}'::jsonb,'Wis. Stat. §§ 74.47(1)-(2), 75.01(1)(b), 75.19','https://docs.legis.wisconsin.gov/document/statutes/75.01','2026-06-14',2026),
  ('WV','state','assessment',NULL,'All property (except public-service businesses) is assessed annually as of July 1 at 60% of its true and actual value (market value). The assessment date is July 1 of the year preceding the tax year.','{"assessment_ratio_pct":60,"market_value_standard":"true and actual value (price property would sell for if voluntarily offered for sale; not forced-sale price)","reassessment_cycle_years":1,"locally_variable":false}'::jsonb,'W. Va. Code § 11-3-1(a)','https://code.wvlegislature.gov/11-3-1/','2026-06-14',2026),
  ('WV','state','assessment_appeal','board_of_equalization','A taxpayer protests the assessed value to the county commission sitting as a Board of Equalization and Review, or to the Office of Tax Appeals, by filing a written protest not later than February 20 of the tax year. The board meets by February 1 and may adjourn sine die after February 15, no later than the last day of February. Board orders may be appealed to the Office of Tax Appeals.','{"deadline_kind":"fixed_date","deadline_month":2,"deadline_day":20,"deadline_desc":"Written protest of assessed value due not later than February 20 of the tax year, filed with the clerk of the county commission (Board of Equalization and Review) or the Office of Tax Appeals. The Board meets not later than February 1 and adjourns sine die no later than the last day of February.","review_body":"County commission sitting as a Board of Equalization and Review; appeal to the Office of Tax Appeals","locally_variable":false}'::jsonb,'W. Va. Code § 11-3-23a(c)(2); see also § 11-3-24(a) and § 11-3-24(j)','https://code.wvlegislature.gov/11-3-23a/','2026-06-14',2026),
  ('WV','state','assessment_appeal','assessor_petition','Optional earlier step: a taxpayer who believes real property was valued too high may file a petition for review with the assessor within eight business days after receiving the notice of increased assessment (or after its publication). This assessor-review path is not required and is separate from the February 20 protest to the Board / Office of Tax Appeals.','{"deadline_kind":"relative_to_roll","deadline_desc":"Optional petition for assessor review of an increased real-property valuation must be filed within eight business days after the taxpayer receives the notice of increased assessment (or after the notice was published as a Class II-0 legal advertisement). Not required; precedes/parallels the February 20 protest path.","review_body":"County assessor (informal review), then county commission as Board of Equalization and Review or Office of Tax Appeals","locally_variable":false}'::jsonb,'W. Va. Code § 11-3-15c(d)','https://code.wvlegislature.gov/11-3-15c/','2026-06-14',2026),
  ('WV','state','exemption','senior','Homestead exemption: the first $20,000 of assessed value of an owner-occupied residence is exempt from ad valorem property tax when the owner is age 65 or older (or is permanently and totally disabled). Owner must have been (or will be) a WV resident for the two consecutive calendar years preceding the tax year and occupy the homestead exclusively for residential purposes. One exemption per homestead; ineligible if receiving a similar exemption in another state.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":20000,"benefit_unit":"usd","locally_variable":false,"notes":"Applies to the first $20,000 of ASSESSED value (assessment ratio is 60% of market value). Same $20,000 exemption covers owners 65+ OR permanently and totally disabled. Requires 2 consecutive calendar years of WV residency preceding the tax year; age qualifier is attaining 65 on or before June 30 following the July 1 assessment day."}'::jsonb,'W. Va. Code § 11-6B-3(a)','https://code.wvlegislature.gov/11-6B-3/','2026-06-14',2026),
  ('WV','state','exemption','disability','The same $20,000 assessed-value homestead exemption is available to an owner certified as permanently and totally disabled (regardless of age), defined as a person unable to engage in any substantial gainful activity by reason of a medically determinable physical or mental condition. Same residency, owner-occupancy, and primary-residence conditions as the senior homestead exemption apply.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":20000,"benefit_unit":"usd","locally_variable":false,"notes":"Disability prong of the single homestead exemption in \u00a7 11-6B-3; no minimum age. ''Permanently and totally disabled'' is defined in \u00a7 11-6B-2 as a person unable to engage in any substantial gainful activity by reason of any medically determinable physical or mental condition. Owner must be a WV resident for the two consecutive calendar years preceding the tax year."}'::jsonb,'W. Va. Code § 11-6B-3(a); definition at § 11-6B-2','https://code.wvlegislature.gov/11-6B-3/','2026-06-14',2026),
  ('WV','state','payment',NULL,'Current real and personal property taxes may be paid in two installments. First installment is payable September 1 and becomes delinquent October 1; second installment is payable the following March 1 and becomes delinquent April 1. A 2.5% discount applies to taxes paid on or before they are payable. Delinquent taxes accrue interest at 9% per annum from the delinquency date. (Collection is by the county sheriff.)','{"installments":[{"label":"First installment","due_month":9,"due_day":1},{"label":"Second installment","due_month":3,"due_day":1}],"delinquent_after_desc":"First installment delinquent October 1; second installment delinquent April 1. 2.5% discount for on-time payment; 9% per annum interest on delinquent amounts.","locally_variable":false}'::jsonb,'W. Va. Code § 11A-1-3(a)','https://code.wvlegislature.gov/11A-1-3/','2026-06-14',2026),
  ('WV','state','delinquency_redemption',NULL,'West Virginia sells tax LIENS on delinquent real estate (Auditor-administered system since the 2022 reform). After a tax lien is sold at the Auditor''s auction, the owner (or other interested/lien party) may redeem at any time before a tax deed is issued, by paying the taxes/interest/charges due as of the sale plus interest at 1% per month (12% per year) on the purchase amount and subsequent payments, plus statutory costs/fees. There is no fixed-month redemption window; redemption is cut off only when the deed issues after the purchaser completes the statutory notice-to-redeem process.','{"late_interest_pct_per_year":12,"tax_sale_kind":"tax_lien","redemption_period_months":null,"locally_variable":false,"notes":"Redemption interest is 1% per month on the purchase amount (= 12%/yr) under \u00a7 11A-3-56(a)(1)-(2). Earlier-stage interest (delinquent taxes accrue 9%/yr under \u00a7 11A-1-3; lands certified to the Auditor accrue 12%/yr under \u00a7 11A-3-38(b)). Redemption is available ''at any time before a tax deed is issued'' rather than for a fixed number of months. Process: delinquent real estate not redeemed by October 31 is certified to the State Auditor (\u00a7 11A-3-8); the Auditor certifies a sale list (Mar 1-Aug 1) and holds a public auction of tax liens within 90 days (\u00a7 11A-3-44, \u00a7 11A-3-45); the purchaser must complete a notice-to-redeem process and the deed issues no sooner than 30 days after notice (\u00a7 11A-3-59). Financial-hardship installment redemption of a primary residence is permitted (\u00a7 11A-3-56(b))."}'::jsonb,'W. Va. Code § 11A-3-56(a); see also § 11A-3-8, § 11A-3-44, § 11A-3-45, § 11A-3-59','https://code.wvlegislature.gov/11A-3-56/','2026-06-14',2026),
  ('WY','state','assessment',NULL,'Wyoming taxable value is a fixed statutory percentage of fair market value by class: residential and all other real/personal property are assessed at 9.5%, industrial-use property at 11.5%, and gross product of minerals/mine products at 100%.','{"assessment_ratio_pct":9.5,"market_value_standard":"fair market value","locally_variable":false,"notes":"9.5% applies to ''all other property, real and personal'' (includes residential). Industrial-use property is 11.5%; mineral gross product is 100%. Ratios are set statewide by statute, not locally."}'::jsonb,'Wyo. Stat. § 39-13-103(b)(iii)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','assessment_appeal',NULL,'A property owner contesting an assessment must file a written statement of reasons with the county assessor no later than 30 days after the date the assessment schedule was sent. The contest is heard by the county board of equalization (which must issue written findings by October 1); further appeals go to the state board of equalization and then district court.','{"deadline_kind":"relative_to_roll","deadline_month":null,"deadline_day":null,"deadline_desc":"Not later than 30 days after the date the assessment schedule was properly sent (postmark/electronic-transmission date controls).","review_body":"County board of equalization (appeals onward to state board of equalization, then district court)","locally_variable":false}'::jsonb,'Wyo. Stat. § 39-13-109(b)(i)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','exemption','veteran','Honorably discharged wartime/qualifying veterans (and qualifying surviving spouses or parents) who have been bona fide Wyoming residents for at least three years receive an annual property tax exemption of $6,000 of assessed value, applied to the veteran''s principal residence. Disabled veterans with a compensable service-connected disability also qualify. Claim must be filed with the county assessor on or before the fourth Monday in May.','{"ownership_required":true,"primary_residence_required":true,"benefit_kind":"exempt_value_cap","benefit_value":6000,"benefit_unit":"usd","locally_variable":false,"notes":"$6,000 is exempted assessed value (not market value); at the 9.5% residential ratio this corresponds to roughly $63,000 of fair market value (verifier''s own derivation, not a statutory figure). Requires 3-year WY residency. Real-property exemption applies only to the veteran''s principal residence. Annual claim deadline: fourth Monday in May. Includes disabled veterans with a compensable service-connected disability."}'::jsonb,'Wyo. Stat. § 39-13-105(a), (b), (c)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','exemption','senior','A long-term-homeowner exemption: if the owner or their spouse is 65 or older and the owner or spouse has paid Wyoming residential property tax for 25+ years, the primary residence receives an exemption of 50% of fair market value, applied to the first $3,000,000 of FMV. Claim must be submitted to the county assessor by March 1 each year. Note: the statute as enacted is repealed effective 7/1/2027.','{"age_min":65,"ownership_required":true,"primary_residence_required":true,"benefit_kind":"pct_reduction","benefit_value":50,"benefit_unit":"pct","locally_variable":false,"notes":"Requires owner or spouse 65+ AND 25+ years of paid WY residential property tax on any residential property. 50% of FMV, capped to first $3,000,000 of FMV. Annual claim deadline March 1. Surviving spouse continues to qualify. Paragraph (xlv) is scheduled to be repealed effective 7/1/2027 \u2014 statute text carries this repeal note; verify current status before relying on it."}'::jsonb,'Wyo. Stat. § 39-11-105(a)(xlv)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','exemption','homestead','Single-family residential anti-spike exemption: the assessed value of a single-family residential structure exceeding the prior year''s assessed value plus 4% is exempt (effectively capping taxable-value growth at 4%/year). Does not apply if the increase is from structural changes/new construction or if the owner acquired the property in the prior calendar year (with stated transfer exceptions). A parallel exemption (xliv) applies the same 4% cap to the associated improved land.','{"primary_residence_required":false,"benefit_kind":"assessment_freeze","benefit_value":4,"benefit_unit":"pct","locally_variable":false,"notes":"Caps year-over-year assessed-value growth on a single-family residential structure at 4%. Excess over (prior-year assessed value less prior exemption, plus 4%) is exempt. Not a homestead in the equity-protection sense \u2014 it is a residential valuation cap. Companion paragraph (xliv) applies the same 4% cap to improved land associated with the structure. Exemption lost in the year of acquisition or for value from structural changes/new construction."}'::jsonb,'Wyo. Stat. § 39-11-105(a)(xliii), (xliv)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','payment',NULL,'Property taxes are payable at the county treasurer''s office. 50% is due/payable on and after November 10, and the remaining 50% on and after May 10 of the succeeding year; the full tax may be paid by December 31 with no interest or penalty. Taxes remaining unpaid on May 11 are declared delinquent.','{"installments":[{"label":"First half (50%)","due_month":11,"due_day":10},{"label":"Second half (50%)","due_month":5,"due_day":10}],"delinquent_after_desc":"Taxes remaining unpaid on May 11 are declared delinquent; if the entire tax is paid on or before December 31 no interest or penalty is chargeable.","grace_days":null,"locally_variable":false,"notes":"Payment-date text is in W.S. 39-13-107 at subparagraph (D); delinquency-on-May-11 at (ii)(B)(I). The combined statute_citation also leads with \u00a7 39-13-108(b)(i), but the payment-date content lives in 39-13-107 \u2014 citation is slightly noisy though the evidence and params are fully supported by 39-13-107."}'::jsonb,'Wyo. Stat. § 39-13-107(b)(i)(D), (b)(ii)(B)(I)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026),
  ('WY','state','delinquency_redemption',NULL,'Delinquent property tax bears interest at 18% per annum until paid or collected. Wyoming is a tax-lien (certificate of purchase) state: at a tax sale the purchaser receives a certificate of purchase. The owner may redeem until a tax deed issues; a tax deed to a private purchaser may be applied for not less than 4 nor more than 6 years from the date of sale, and the county takes a tax deed for its unredeemed certificates after 4 years — giving a minimum redemption period of 4 years.','{"late_penalty_pct":null,"late_interest_pct_per_year":18,"redemption_period_months":48,"tax_sale_kind":"tax_lien","locally_variable":false,"notes":"18% per annum interest on delinquent taxes (\u00a7 39-13-108(b)(ii)). Tax-lien state: purchaser gets a certificate of purchase. Redemption runs until a tax deed issues. County issues a tax deed to itself for unredeemed certificates after 4 years (\u00a7 39-13-108(e)(iv)(A)); a purchaser may apply for a tax deed not less than 4 nor more than 6 years from the original sale date (\u00a7 39-13-108(e)(v)(A)) \u2014 so the guaranteed minimum redemption window is 4 years. The specific redemption-payment interest rate owed to the certificate holder was confirmed ABSENT from \u00a7 39-13-108 in the statute text reviewed \u2014 no redemption rate is asserted in params; only the 18% delinquent-tax interest is verified here."}'::jsonb,'Wyo. Stat. § 39-13-108(b)(ii); § 39-13-108(e)(iv)(A), (e)(v)(A)','https://wyoleg.gov/statutes/compress/title39.pdf','2026-06-14',2026);
